var e=[{id:1,status:`live`,carbLevel:`high`,meta:{macros:{protein:35,calories:425,fat:14,carbs:42,netCarbs:40,estimated:!1},allergens:[`dairy`,`gluten`],warnings:[`contains-dairy`,`spicy-adult-version`],dietTags:[`halal`],proteinTags:[`chicken`],splitAxes:[`spice`],effortTags:[`one-pan`],costTier:`budget`,costPerServing:`$4.50`,substitutionNotes:[`swap chicken for turkey or Kirkland chicken bites`,`use GF gnocchi for gluten-free`,`skip chili oil for mild version`]},slug:`spicy-fajita-chicken-gnocchi`,proteinAnchor:`chicken`,mealType:`pasta`,flavorDirection:`creamy-comfort`,splitFriendly:`full`,title:`Spicy Fajita Chicken Gnocchi`,category:`Core Signatures`,pillar:`Protein Meals`,tags:[`crispy`,`creamy`,`chicken`,`gnocchi`,`signature`,`flagship`,`split-cook`],time:`30 min`,servings:4,protein:35,calories:425,image:`/images/gnocchi/hero-finished-dish.png`,role:`The Texture Hero`,makeThisWhen:`You want a high-protein dinner that doesn't turn into two separate meals for adults and kids — and you still want real texture (crispy, not mushy).`,hook:`This replaces ordering takeout on weeknights. Crispy gnocchi, creamy spicy sauce, and a kid plate that's ready in the same 30 minutes — no separate meal, no compromise.`,description:`~35g protein for ~425 calories. Pan-fried gnocchi with golden crispy edges, a spicy cottage cheese cream sauce, and pre-cooked shredded chicken. Adults get chili oil and Dan-O's. Kids get Rao's Alfredo or a dry plate. 30 minutes, one workflow.`,whyMostFail:[`Gnocchi gets boiled — turns soft and forgettable`,`Chicken is just reheated — no texture, no browning`,`Sauce is too heavy — kills the dish and the macros`],whyThisWorks:[`Pan-crisped gnocchi = crispy shell + soft center = texture contrast that makes 425 calories feel indulgent`,`Lightly browned chicken = actual flavor, not steamed protein`,`Cottage cheese sauce = indistinguishable from cream sauce but 14g protein per serving instead of empty fat`,`Split happens post-chicken, pre-sauce — 3 extra minutes for a kid plate, not a second meal`],executionRules:[`Don't sauce everything before splitting — sauce goes in AFTER the split point.`,`Don't overcook after sauce — breaks texture. Simmer 2-3 min max.`,`Don't force veggies into kid portion — serve on side, they eat more when they choose.`,`Don't boil gnocchi — pan-fry only. Boiled = mush, and the whole recipe falls apart.`,`Don't skip the lime — flavor goes flat without acid. This is what makes it taste complete.`],troubleshooting:[{problem:`Gnocchi is soggy / soft`,fix:`You either boiled it or crowded the pan. Single layer, medium-high heat, don't touch for 3-4 min per side. If using frozen gnocchi, thaw first.`},{problem:`Sauce is grainy / chunky`,fix:`Blend longer — full 60 seconds on high. Cottage cheese must be completely smooth before it hits the pan.`},{problem:`Sauce is too thick / paste-like`,fix:`Add more milk, 1 tbsp at a time. You want it to coat a spoon, not clump.`},{problem:`Dish tastes flat`,fix:`You skipped the lime. Squeeze half a lime over the finished dish — acid is what ties everything together.`},{problem:`Too heavy / rich`,fix:`You used too much sauce. The sauce should coat the gnocchi, not pool at the bottom of the pan. Less is more.`}],splitCook:{splitRatio:`70% Adult / 30% Kid`,splitPoint:`STOP. Chicken is crisped. Divide gnocchi, chicken, and veg into 2 pans NOW — everything after this point is different for adults and kids.`,sharedIngredients:[`--- BASE ---`,`1 pack shelf-stable gnocchi (~16 oz)`,`2-2.5 cups cooked shredded chicken`,`--- VEG ---`,`1 bell pepper, sliced`,`1/2 onion, sliced`,`--- SHARED SAUCE BASE (NEUTRAL) ---`,`3/4 cup cottage cheese`,`1/2 cup Fairlife fat-free milk`],sharedSteps:[{text:`CRISP THE GNOCCHI: Medium-high heat, 2 tsp oil. Add gnocchi in a single layer. Cook 8-10 min, flipping occasionally. Goal: crispy outside, not soft. Set aside.`,images:[`/images/gnocchi/step1-crisp-gnocchi.png`]},{text:`COOK VEG: Same pan, high heat. Add peppers + onions. Cook 4-5 min until lightly charred. Set aside.`,images:[`/images/gnocchi/step2-cook-veg.png`]},{text:`CRISP CHICKEN: Add shredded chicken to pan. Let it sit — develop slight browning. Don't stir constantly.`}],adult:{label:`Adult — Spicy Fajita`,protein:35,calories:425,extraIngredients:[`--- ADULT ADD-ONS ---`,`1-1.5 tsp Dan-O's (Outlaw preferred)`,`1 tsp smoked paprika`,`1 tsp garlic powder`,`1 tsp onion powder`,`1 tsp chili oil`,`Optional: chili flakes`,`--- FINISH ---`,`Juice of 1 lime`,`Optional: green onions`],steps:[{text:`BUILD FLAVOR SAUCE: Blend cottage cheese + milk until smooth. Add to adult pan. Mix in Dan-O's, garlic powder, onion powder, smoked paprika, chili oil. Simmer 2-3 min. Should look like a light creamy sauce, not thick paste.`,images:[`/images/gnocchi/step4-sauce-pour.png`]},{text:`COMBINE: Add gnocchi + veggies to adult pan. Toss lightly — should coat, not drown.`},{text:`FINISH: Lime squeeze + optional green onions. This completes the dish — don't skip.`}]},kid:{label:`Kid Path — Simple + Fast`,protein:28,calories:380,proteinSwap:`Swap shredded chicken for Kirkland chicken bites or mild meatballs if preferred.`,options:[{label:`Option A — Mild Creamy`,extraIngredients:[`Small amount of blended sauce base (no chili oil, no spice)`,`Shredded mild cheese (mozz or cheddar)`],steps:[{text:`MILD SAUCE: Add a small amount of the blended cottage cheese + milk to kid pan (NO spices, NO chili oil). Stir with chicken.`},{text:`COMBINE: Add gnocchi. Add shredded cheese on top. Toss gently — keep it creamy and familiar.`}]},{label:`Option B — Rao's Alfredo`,extraIngredients:[`2-3 tbsp Rao's Alfredo sauce`,`Optional: shredded mild cheese on top`],steps:[{text:`SAUCE: Warm 2-3 tbsp Rao's Alfredo in the kid pan. Skip the cottage cheese sauce entirely for this option.`},{text:`COMBINE: Add gnocchi + chicken (or kid protein swap). Toss in Rao's until coated. Add cheese if they want it.`}]},{label:`Option C — Dry Plate (lowest friction)`,extraIngredients:[`Optional: ketchup or mild dipping sauce on side`],steps:[{text:`PLATE: Gnocchi + chicken only. No sauce. Veg on side — not mixed in.`},{text:`SERVE: Optional ketchup or mild sauce on the side for dipping.`}]}]}},ingredients:[`--- PROTEIN & BASE ---`,`1 pack shelf-stable gnocchi (~16 oz)`,`2-2.5 cups cooked shredded chicken`,`--- SAUCE (HIGH-PROTEIN CREAM BASE) ---`,`3/4 cup cottage cheese`,`1/2 cup Fairlife fat-free milk`,`1 tsp chili oil`,`1-1.5 tsp Dan-O's seasoning (Outlaw preferred)`,`1 tsp smoked paprika`,`1 tsp garlic powder`,`1 tsp onion powder`,`Optional: chili flakes`,`--- VEG (NON-NEGOTIABLE) ---`,`1 bell pepper, sliced`,`1/2 onion, sliced`,`--- FINISH ---`,`Juice of 1 lime`,`Optional: green onions`],steps:[{text:`CRISP THE GNOCCHI: Medium-high heat, 2 tsp oil. Add gnocchi in a single layer. Cook 8-10 min, flipping occasionally. Goal: crispy outside, not soft. Set aside.`,images:[`/images/gnocchi/step1-crisp-gnocchi.png`]},{text:`COOK VEG: Same pan, high heat. Add peppers + onions. Cook 4-5 min until lightly charred. Set aside.`,images:[`/images/gnocchi/step2-cook-veg.png`]},{text:`CRISP CHICKEN: Add shredded chicken to pan. Let it sit — develop slight browning. Don't stir constantly.`},{text:`BUILD THE SAUCE: Blend cottage cheese + milk until smooth. Add to pan with chicken. Mix in Dan-O's, garlic powder, onion powder, smoked paprika, chili oil. Simmer 2-3 min ONLY. Should look like a light creamy sauce, not thick paste.`,images:[`/images/gnocchi/step4-sauce-pour.png`]},{text:`COMBINE: Add gnocchi + veggies back. Toss gently to coat — 'coated,' not 'swimming.'`},{text:`FINISH: Lime squeeze + green onions. This completes the dish — don't skip.`}],brands:[{name:`Fairlife`,item:`Fat-free milk`,why:`Higher protein per serving than regular milk, lactose-free`,image:`/images/brands/fairlife-milk.png`,url:`https://fairlife.com/ultra-filtered-milk/fat-free-skim-milk/`},{name:`Dan-O's`,item:`Outlaw seasoning`,why:`All-purpose spice blend with heat — replaces 4-5 individual spices`,image:`/images/brands/danos-outlaw.png`,url:`https://danosseasoning.com/product/sweet-tangy-bbq-seasoning-made-with-tamarind-medium-bottle/`},{name:`Del Real`,item:`Shredded chicken`,why:`Pre-cooked, saves 20+ min, consistent shred texture`,image:`/images/brands/del-real-chicken.webp`,url:`https://delrealfoods.com/products/pulled-chicken`},{name:`Rao's`,item:`Alfredo sauce`,why:`Kid Option B — store-bought shortcut that actually tastes good. Skip the cottage cheese sauce for kids who want familiar flavor.`,image:`/images/brands/raos-alfredo.png`,url:`https://raos.goldbelly.com/alfredo-sauce-15-oz?ref=collection`}],mealPrep:{storage:`Store gnocchi + sauce together (the crisp won't survive anyway). Keep chicken separate if possible.`,reheat:`Microwave 90 sec or pan reheat with a splash of milk to loosen the sauce. The gnocchi won't re-crisp — that's the tradeoff. Fresh is best for this one.`,lasts:`2-3 days in fridge. Best eaten same day for texture.`}},{id:2,status:`live`,carbLevel:`high`,meta:{macros:{protein:45,calories:500,fat:16,carbs:48,netCarbs:45,estimated:!0},allergens:[`dairy`,`gluten`],warnings:[`contains-dairy`,`spicy-adult-version`],dietTags:[`halal`],proteinTags:[`beef`,`steak`],splitAxes:[`spice`],effortTags:[`meal-prep`],costTier:`moderate`,costPerServing:`$6.50`,substitutionNotes:[`swap tri-tip for sirloin or flank steak`,`use GF penne for gluten-free`,`skip chili oil for mild version`]},slug:`chili-cream-tri-tip-penne`,proteinAnchor:`beef`,mealType:`pasta`,flavorDirection:`smoky-southwest`,splitFriendly:`full`,title:`Chili Cream Tri-Tip Penne`,category:`Core Signatures`,pillar:`Protein Meals`,tags:[`steak`,`pasta`,`creamy`,`split-cook`,`meal-prep`],time:`35 min`,servings:4,protein:45,calories:500,image:`/images/tritip/hero-plated.png`,role:`The Steak Meal Prep`,makeThisWhen:`You want steak for dinner but don't want to blow 800 calories on cream sauce — and you need the kids fed from the same cook.`,hook:`This replaces heavy steak pasta with a version that reheats clean, hits 45g protein, and splits for kids without you touching a second pan until the last 3 minutes.`,description:`~45g protein for ~500 calories. Seared tri-tip sliced thin over penne in a cottage cheese cream sauce. Adults get chili oil and Dan-O's heat. Kids get meatballs or sausage in a mild creamy coat. Meal preps for 3-4 days.`,whyMostFail:[`Steak gets overcooked — chewy and grey instead of pink and tender`,`Cream sauce adds 400+ calories — turns a protein meal into a calorie bomb`,`Can't reheat — pasta turns to mush by day 2`],whyThisWorks:[`Tri-tip is lean but beefy — cheaper than ribeye, more flavor than chicken breast`,`Cottage cheese + beef broth sauce = rich mouthfeel at half the calories of cream`,`Split happens post-sauce, so both versions get the same creamy base — only protein and heat changes`,`Stores 3-4 days if pasta and protein are kept separate`],executionRules:[`Don't overcook tri-tip — this kills the entire dish. Pull at medium-rare, rest 5-10 min.`,`Don't slice with the grain — ruins texture. Always against the grain, thin.`,`Don't mix kid + adult protein before the split — sauce goes on AFTER splitting.`,`Don't store pasta in sauce for meal prep — store separately, reheat with a splash of milk or broth.`,`Don't overload on sauce — should coat, not drown.`],troubleshooting:[{problem:`Tri-tip is chewy / tough`,fix:`Two possible causes: overcooked (pull at 130°F internal, not 160) or sliced with the grain. Always slice thin against the grain at a slight angle.`},{problem:`Sauce broke / looks curdled`,fix:`You boiled it. Cottage cheese sauce needs a gentle simmer, never a rolling boil. If it breaks, blend it again with a splash of milk.`},{problem:`Pasta is mushy after reheating`,fix:`You stored pasta in the sauce. Store separately next time. Reheat pasta with a splash of broth, then add sauce.`},{problem:`Dish tastes bland`,fix:`Add more Dan-O's and a squeeze of lime. The spice and acid are what make this feel like a restaurant dish, not diet food.`}],splitCook:{splitRatio:`70% Adult / 30% Kid`,splitPoint:`STOP. Sauce base is done. Divide sauce + pasta into two pans NOW — adult gets chili oil and tri-tip, kid gets meatballs and mild cheese.`,sharedIngredients:[`--- PASTA ---`,`8 oz penne (dry)`,`--- VEG ---`,`2 cups spinach`,`2 cloves garlic, minced`,`--- SAUCE BASE ---`,`1 cup cottage cheese`,`3/4 cup Fairlife fat-free milk`,`1/2 cup beef broth`],sharedSteps:[{text:`COOK PASTA: Salted water, cook to al dente. Reserve 1/2 cup pasta water. Set aside.`,images:[``]},{text:`COOK ADULT PROTEIN: Season tri-tip aggressively with Dan-O's. Sear high heat (or grill), 4-5 min per side. Rest 5-10 min. Slice THIN against the grain. Do NOT overcook — this kills the dish.`,images:[`/images/tritip/step2-sear.png`,`/images/tritip/step2-sliced.png`]},{text:`COOK KID PROTEIN: Heat meatballs or sausage separately. Keep mild — no spice. Set aside.`,images:[``]},{text:`BUILD SHARED SAUCE: Blend cottage cheese + milk + beef broth until smooth. In a pan, sauté garlic 30 sec, add spinach and wilt, pour in blended sauce. Simmer 2-3 min.`,images:[`/images/tritip/step4-sauce-blend.png`,`/images/tritip/step4-sauce-pour.png`,`/images/tritip/hero-plated.png`]}],adult:{label:`Adult — Spicy Chili Cream`,protein:45,calories:500,extraIngredients:[`--- ADULT PROTEIN ---`,`1.25 lb tri-tip`,`Dan-O's Outlaw seasoning`,`--- ADULT FLAVOR BUILD ---`,`1-1.5 tsp chili oil`,`1 tsp smoked paprika`,`1 tsp garlic powder`,`Dan-O's (to taste)`,`Optional: chili flakes, lime`],steps:[{text:`FLAVOR BUILD: Add chili oil, smoked paprika, garlic powder, and Dan-O's to adult pan. Stir into sauce.`},{text:`COMBINE: Add pasta + sliced tri-tip. Toss gently — goal is coated, not heavy.`},{text:`FINISH: Optional chili flakes and lime squeeze. Tri-tip goes ON TOP so it doesn't steam.`}]},kid:{label:`Kid Path — Mild & Familiar`,protein:25,calories:400,proteinSwap:`Earth's Best mini meatballs or all-beef sausage (sliced). Keep seasoning minimal.`,options:[{label:`Option A — Creamy Mild`,extraIngredients:[`Mini meatballs or sausage slices`,`Small cheese sprinkle (mozz or cheddar)`],steps:[{text:`COMBINE: Add pasta + meatballs/sausage to kid pan with sauce. Keep sauce light.`},{text:`FINISH: Sprinkle cheese on top. Serve — creamy and familiar.`}]},{label:`Option B — Deconstructed Plate`,extraIngredients:[`Optional: ketchup or mild dipping sauce on side`],steps:[{text:`PLATE: Pasta + protein separately. Sauce on side for dipping.`},{text:`SERVE: Spinach optional — on the side if at all.`}]}]}},ingredients:[`--- PROTEIN ---`,`1.25 lb tri-tip`,`Dan-O's Outlaw seasoning`,`--- PASTA ---`,`8 oz penne (dry)`,`--- SAUCE ---`,`1 cup cottage cheese`,`3/4 cup Fairlife fat-free milk`,`1/2 cup beef broth`,`--- VEG ---`,`2 cups spinach`,`2 cloves garlic, minced`,`--- ADULT FLAVOR BUILD ---`,`1-1.5 tsp chili oil`,`1 tsp smoked paprika`,`1 tsp garlic powder`,`Dan-O's (to taste)`,`Optional: chili flakes, lime`],steps:[{text:`COOK PASTA: Salted water, cook to al dente. Reserve 1/2 cup pasta water. Set aside.`,images:[``]},{text:`SEAR TRI-TIP: Season aggressively with Dan-O's. Sear high heat, 4-5 min per side. Rest 5-10 min. Slice THIN against the grain.`,images:[`/images/tritip/step2-sear.png`,`/images/tritip/step2-sliced.png`]},{text:`BUILD SAUCE: Blend cottage cheese + milk + beef broth. Sauté garlic, wilt spinach, pour in sauce. Simmer 2-3 min.`,images:[`/images/tritip/step4-sauce-blend.png`,`/images/tritip/step4-sauce-pour.png`,`/images/tritip/hero-plated.png`]},{text:`FLAVOR BUILD: Add chili oil, smoked paprika, garlic powder, Dan-O's to sauce. Stir.`},{text:`COMBINE: Add pasta + splash of pasta water. Toss until coated.`},{text:`PLATE: Pasta in bowl, sliced tri-tip ON TOP (don't bury it — it steams and loses sear). Optional chili flakes + lime.`}],brands:[{name:`Fairlife`,item:`Fat-free milk`,why:`Higher protein per serving, lactose-free, blends smooth into sauce`,image:`/images/brands/fairlife-milk.png`,url:`https://fairlife.com/ultra-filtered-milk/fat-free-skim-milk/`},{name:`Dan-O's`,item:`Outlaw seasoning`,why:`All-purpose spice with heat — perfect on steak and in the sauce`,image:`/images/brands/danos-outlaw.png`,url:`https://danosseasoning.com/product/sweet-tangy-bbq-seasoning-made-with-tamarind-medium-bottle/`},{name:`Earth's Best`,item:`Mini meatballs`,why:`Pre-cooked, mild, kid-approved protein swap`,image:`/images/brands/earths-best-meatballs.webp`,url:`https://www.earthsbest.com/products/mini-beef-meatballs-toddler`}],mealPrep:{storage:`Store pasta and protein separately. Sauce can stay on pasta.`,reheat:`Reheat with a splash of milk or broth to loosen sauce. Add protein after.`,lasts:`3-4 days in fridge`}},{id:3,status:`placeholder`,slug:`swedish-steak-noodles`,proteinAnchor:`beef`,mealType:`pasta`,flavorDirection:`creamy-comfort`,splitFriendly:`easy-swap`,title:`Swedish-Style High Protein Steak & Noodles`,category:`Core Signatures`,pillar:`Protein Meals`,tags:[`comfort-food`,`steak`,`noodles`,`bone-broth`],time:`30 min`,servings:3,protein:50,calories:490,image:`https://images.unsplash.com/photo-1529694157872-4e0c0f3b238b?w=600&h=400&fit=crop`,description:`Your refined stroganoff: bone broth + splash of milk + Dijon mustard sauce over egg noodles with seared beef. Comfort food, optimized.`,whyItWorks:`Bone broth + milk + Dijon = rich without heavy cream. Egg noodles absorb sauce better than regular pasta. Searing beef separately keeps it tender, not rubbery.`,ingredients:[`450g sirloin or flank steak, sliced thin`,`250g egg noodles`,`1 cup bone broth`,`1/3 cup milk (2% is fine)`,`1 tbsp Dijon mustard`,`1 tbsp Worcestershire sauce`,`250g mushrooms, sliced`,`1 onion, sliced thin`,`3 cloves garlic, minced`,`2 tbsp olive oil`,`1 tbsp butter`,`Salt, pepper, paprika`,`Fresh dill or parsley`],steps:[`Season beef strips with salt, pepper, and paprika. Sear in batches over HIGH heat in 1 tbsp oil — 60 seconds per side max. Remove immediately. You're going for sear, not cook-through.`,`Same pan, add butter. Cook mushrooms without stirring for 3-4 minutes until deeply golden. Add onion, cook 3 more minutes.`,`Add garlic, 30 seconds. Deglaze with bone broth, scraping up all the fond.`,`Stir in milk, Dijon, and Worcestershire. Simmer 5 minutes until sauce reduces slightly.`,`Cook egg noodles. Drain and add directly to the sauce.`,`Return beef strips, toss gently. The beef finishes cooking in the sauce — don't let it boil or the meat tightens.`,`Garnish with dill. This is comfort food that earns its calories.`]},{id:4,status:`live`,carbLevel:`high`,meta:{macros:{protein:45,calories:500,fat:14,carbs:45,netCarbs:42,estimated:!0},allergens:[`soy`],warnings:[`contains-soy`,`spicy-adult-version`],dietTags:[`dairy-free`,`halal`,`gluten-free-option`],proteinTags:[`beef`,`steak`],splitAxes:[`spice`],effortTags:[`fast`,`meal-prep`,`one-pan`],costTier:`moderate`,costPerServing:`$5.50`,substitutionNotes:[`use tamari for gluten-free soy sauce`,`swap beef for chicken or tofu`,`carb lever: adults ½ cup jasmine (~22g net) + 1 oz extra beef, kids full cup — rice is dinner, don't kill it`]},slug:`spicy-beef-broccoli-bowls`,proteinAnchor:`beef`,mealType:`rice-bowl`,flavorDirection:`spicy-asian`,splitFriendly:`full`,title:`Spicy Beef & Broccoli Rice Bowls`,category:`Core Signatures`,pillar:`Protein Meals`,tags:[`meal-prep`,`stir-fry`,`rice-bowl`,`split-cook`,`high-volume`],time:`25 min`,servings:4,protein:45,calories:500,image:`/images/beefbroccoli/hero.png`,role:`The Fast Weekday Workhorse`,makeThisWhen:`It's Tuesday, you have 25 minutes, and you need something that feeds the family, hits protein goals, and meal preps through Thursday.`,hook:`This replaces takeout beef & broccoli with a 25-minute version that reheats clean, doesn't get soggy, and splits for kids without a single extra step.`,description:`~45g protein for ~500 calories. Bone broth rice + seared beef strips + charred broccoli in a soy-sesame glaze. Adults get chili oil and sriracha. Kids get mini meatballs or grass-fed beef sausage in a mild soy coat. 25 minutes, meal preps through the week.`,whyMostFail:[`Beef gets overcrowded in the pan — steams instead of sears, turns grey`,`Broccoli gets boiled or steamed — army green mush with no flavor`,`Too much sauce — turns rice into a soggy mess`,`Can't split for kids — the whole batch is either spicy or bland`],whyThisWorks:[`Bone broth rice = depth without effort — just swap water for broth, same cook time`,`Cornstarch velvet on beef = restaurant texture from any cheap cut`,`Broccoli charred in cast iron = Maillard reaction, not steam`,`Split happens after base is done — same rice, same broccoli, different protein and sauce level`],executionRules:[`Don't overcrowd the pan when searing beef — steaming instead of searing ruins it. Do batches.`,`Don't use too much sauce — soggy rice kills the bowl. Keep it glossy, not soupy.`,`Don't overcook broccoli — charred edges and bright green, not army green mush.`,`Don't skip slicing thin against the grain — chewy beef = failed dish.`,`Don't mix adult sauce into the full batch before splitting.`],troubleshooting:[{problem:`Beef is chewy / tough`,fix:`Either sliced too thick, cut with the grain, or skipped the cornstarch velvet. Slice thin against the grain, toss with soy + cornstarch, let sit 10-15 min before searing.`},{problem:`Broccoli is mushy / army green`,fix:`Overcooked or too much moisture. Pat dry, high heat, single layer. You want charred edges in 3-4 min, not steamed in 10.`},{problem:`Rice is soggy / wet`,fix:`Too much sauce on the rice, or too much broth when cooking. Stick to 1:2 ratio. Sauce should glaze the beef, not pool in the bowl.`},{problem:`Beef didn't sear / looks grey`,fix:`Pan wasn't hot enough or too crowded. Wait for wisps of smoke before adding beef. Do 2-3 batches, not all at once.`},{problem:`Tastes like generic stir-fry`,fix:`Add more sesame oil and finish with chili oil. The bone broth rice should carry the base flavor — if it's bland, you used water instead of broth.`}],splitCook:{splitRatio:`70% Adult / 30% Kid`,splitPoint:`STOP. Rice and broccoli are done. Bowl up the base now — adult bowls get seared beef with spicy sauce, kid bowls get meatballs or sausage with mild soy.`,sharedIngredients:[`--- RICE ---`,`1 cup rice`,`2 cups Roli Roti Butcher's Bone Broth`,`--- VEG ---`,`3-4 cups broccoli (fresh or frozen)`,`3 cloves garlic, minced`,`--- SAUCE BASE (SHARED) ---`,`2 tbsp soy sauce (or tamari + splash dark soy)`,`1/2 cup beef broth`,`1 tsp sesame oil`],sharedSteps:[{text:`COOK RICE: Cook 1:2 ratio with bone broth instead of water. Fluff and set aside. This is your flavor foundation — don't skip.`,images:[`/images/beefbroccoli/step1-rice.png`]},{text:`PREP BEEF: Slice thin against the grain. Toss with 1 tsp soy sauce + 1 tsp cornstarch for velveting. If you mess this up → chewy, game over.`,images:[`/images/beefbroccoli/step2-prep-beef.png`]},{text:`COOK BROCCOLI: High heat stir-fry or air fry. Goal: slightly charred edges, bright green, not mushy. Set aside.`,images:[`/images/beefbroccoli/step3-broccoli.png`]}],adult:{label:`Adult — Spicy Soy-Sesame`,protein:45,calories:500,extraIngredients:[`--- ADULT PROTEIN ---`,`1.25 lb beef (tri-tip / flank / sirloin), sliced thin`,`1 tsp cornstarch (velveting)`,`--- ADULT FLAVOR BUILD ---`,`Chili oil or sriracha`,`1 tsp ginger, grated`,`Sesame seeds`,`Green onion, sliced`],steps:[{text:`SEAR BEEF: Screaming hot pan. Don't overcrowd — do batches. Quick sear 1-2 min per batch.`,images:[`/images/beefbroccoli/step4-sear.png`]},{text:`BUILD SAUCE: Add soy sauce + beef broth + sesame oil + garlic + ginger to pan. Add chili oil or sriracha for heat. Simmer briefly.`,images:[`/images/beefbroccoli/step4-sauce.png`]},{text:`COMBINE: Return broccoli, toss quickly. Keep it glossy, not soupy. Serve over bone broth rice. Top with sesame seeds and green onion.`}]},kid:{label:`Kid Path — Mild & Familiar`,protein:25,calories:400,proteinSwap:`Earth's Best mini meatballs or grass-fed beef sausage (sliced). Keep seasoning minimal.`,options:[{label:`Option A — Mild Soy Glaze`,extraIngredients:[`Mini meatballs or beef sausage slices`,`Small splash soy sauce + broth (NO chili)`],steps:[{text:`COOK PROTEIN: Heat meatballs or sausage slices separately. Light salt + minimal soy only.`},{text:`MILD SAUCE: Small splash soy + broth in kid pan. No chili, no sriracha. Keep it light.`},{text:`COMBINE: Rice + protein + broccoli (on side or mixed lightly). Keep sauce minimal.`}]},{label:`Option B — Dry Bowl`,extraIngredients:[`Optional: ketchup or mild dipping sauce on side`],steps:[{text:`BOWL: Rice + meatballs/sausage + broccoli on side. No sauce.`},{text:`SERVE: Optional dipping sauce on the side. Keep it simple.`}]}]}},ingredients:[`--- RICE ---`,`1 cup rice`,`2 cups Roli Roti Butcher's Bone Broth`,`--- PROTEIN ---`,`1.25 lb beef (tri-tip / flank / sirloin), sliced thin`,`1 tsp soy sauce + 1 tsp cornstarch (velveting)`,`--- VEG ---`,`3-4 cups broccoli`,`3 cloves garlic, minced`,`1 tsp ginger, grated`,`--- SAUCE ---`,`2 tbsp soy sauce`,`1/2 cup beef broth`,`1 tsp sesame oil`,`Chili oil or sriracha`,`--- FINISH ---`,`Sesame seeds`,`Green onion, sliced`],steps:[{text:`COOK RICE: Cook 1:2 ratio with bone broth. Fluff and set aside.`,images:[`/images/beefbroccoli/step1-rice.png`]},{text:`PREP BEEF: Slice thin against the grain. Toss with soy + cornstarch. Let sit 10-15 min.`,images:[`/images/beefbroccoli/step2-prep-beef.png`]},{text:`COOK BROCCOLI: High heat stir-fry or air fry. Charred edges, bright green. Set aside.`,images:[`/images/beefbroccoli/step3-broccoli.png`]},{text:`SEAR BEEF: Screaming hot pan, batches, don't crowd. 1-2 min per batch.`,images:[`/images/beefbroccoli/step4-sear.png`]},{text:`BUILD SAUCE: Soy + broth + sesame oil + garlic + ginger + chili oil in pan. Simmer briefly.`,images:[`/images/beefbroccoli/step4-sauce.png`]},{text:`COMBINE: Return beef + broccoli. Toss until glossy. Serve over bone broth rice. Sesame seeds + green onion on top.`}],brands:[{name:`Roli Roti`,item:`Butcher's Bone Broth`,why:`Cooks rice with built-in flavor — replaces plain water for zero extra effort`,image:`/images/brands/roli-roti-broth.jpg`,url:`https://roliroti.com/products/organic-chicken-broth/`},{name:`Earth's Best`,item:`Mini meatballs`,why:`Pre-cooked, mild, kid-approved protein swap`,image:`/images/brands/earths-best-meatballs.webp`,url:`https://www.earthsbest.com/products/mini-beef-meatballs-toddler`}],mealPrep:{storage:`Store rice separate from beef. Broccoli can go with beef.`,reheat:`Reheat with splash of broth to prevent drying. Avoid overcooking on reheat.`,lasts:`3-4 days in fridge`}},{id:5,status:`placeholder`,slug:`doner-beef-lavash-wraps`,proteinAnchor:`beef`,mealType:`wrap`,flavorDirection:`smoky-southwest`,splitFriendly:`full`,title:`Sheet Pan Doner-Style Beef Lavash Wraps`,category:`Core Signatures`,pillar:`Protein Meals`,tags:[`family-friendly`,`viral`,`wraps`,`meal-prep`],time:`45 min`,servings:6,protein:42,calories:440,image:`https://images.unsplash.com/photo-1561651188-d207bbec4ec3?w=600&h=400&fit=crop`,description:`Viral-style doner kebab but optimized: lean ground beef, sheet pan method, lavash wraps. High protein, family-friendly, zero fuss.`,whyItWorks:`Sheet pan = hands-off cooking for a crowd. Lavash is lighter than pita. The spice blend mimics doner without a rotisserie. Kids eat it, adults respect it.`,ingredients:[`700g lean ground beef (90/10)`,`1 tbsp cumin`,`1 tbsp paprika`,`1 tsp garlic powder`,`1 tsp onion powder`,`1/2 tsp cayenne`,`1/2 tsp cinnamon`,`Salt and pepper`,`Lavash flatbreads`,`Sliced tomatoes, red onion, lettuce`,`1/2 cup Greek yogurt + 1 clove garlic (sauce)`,`Hot sauce`],steps:[`Preheat oven to 400°F (200°C). Line a sheet pan with parchment.`,`Mix ground beef with ALL spices by hand. Don't overwork — just combine.`,`Press meat into a flat, even layer on the sheet pan. About 1/2 inch thick. Score into strips with a knife.`,`Bake 20-25 minutes until edges are crispy and browned. The edges are the best part.`,`While baking, mix Greek yogurt with minced garlic, salt, and a squeeze of lemon.`,`Break/slice the baked beef into strips. Load into lavash with tomato, onion, lettuce, yogurt sauce, and hot sauce.`,`Wrap tight. This feeds the whole family and meal preps for days. The crispy edge pieces go first — accept it.`]},{id:6,status:`placeholder`,slug:`philly-cheesesteak-sliders`,proteinAnchor:`beef`,mealType:`wrap`,flavorDirection:`creamy-comfort`,splitFriendly:`easy-swap`,title:`Philly Cheesesteak Sliders (Lean Version)`,category:`Fast Meals`,pillar:`Protein Meals`,tags:[`quick`,`beef`,`sliders`,`family-friendly`],time:`20 min`,servings:4,protein:38,calories:380,image:`https://images.unsplash.com/photo-1513185158878-8d8c2a2a3da3?w=600&h=400&fit=crop`,description:`Ground beef + peppers + light provolone on slider buns. Fast, scalable, and hits the cheesesteak craving without the calorie blowout.`,whyItWorks:`Ground beef cooks in minutes vs shaved steak. Light provolone melts perfectly with 60% fewer calories. Slider format = portion control without thinking about it.`,ingredients:[`500g lean ground beef (90/10)`,`1 green bell pepper, diced`,`1 onion, diced`,`4 slices light provolone`,`8 slider buns`,`2 tbsp Worcestershire sauce`,`1 tsp garlic powder`,`Salt and pepper`,`Pickled jalapeños (optional)`,`Yellow mustard`],steps:[`Cook ground beef over high heat, breaking into small crumbles. Don't stir too much — you want browned crispy bits.`,`When beef is 80% done, add peppers and onion. Cook 3-4 minutes until softened.`,`Hit with Worcestershire, garlic powder, salt, pepper. Stir to combine.`,`Lay provolone slices over the top. Cover pan 1 minute until melted.`,`Load into slider buns. Add jalapeños and mustard.`,`These take 20 minutes and make 8 sliders. That's Tuesday dinner solved.`]},{id:7,status:`placeholder`,slug:`mini-naan-protein-pizzas`,proteinAnchor:`chicken`,mealType:`other`,flavorDirection:`creamy-comfort`,splitFriendly:`full`,title:`Mini Naan High-Protein Pizzas`,category:`Fast Meals`,pillar:`Protein Meals`,tags:[`quick`,`pizza`,`cottage-cheese`,`kids`],time:`15 min`,servings:2,protein:40,calories:420,image:`https://images.unsplash.com/photo-1565299624946-b28f40a0ae38?w=600&h=400&fit=crop`,description:`Mini naan + blended cottage cheese sauce + toppings. Your 'protein junk food' lane. Kids don't know there's cottage cheese. You don't tell them.`,whyItWorks:`Naan is the perfect personal pizza base — crispy edges, soft center. Blended cottage cheese replaces pizza sauce AND adds 14g protein per serving. This is stealth nutrition.`,ingredients:[`4 mini naan breads`,`1 cup cottage cheese, blended with 1 tbsp tomato paste + Italian seasoning`,`1 cup shredded mozzarella (part-skim)`,`150g cooked chicken breast, diced`,`Sliced bell peppers`,`Red onion, sliced thin`,`Red chili flakes`,`Fresh basil`,`Olive oil drizzle`],steps:[`Preheat oven to 425°F (220°C) or use broiler for speed.`,`Blend cottage cheese + tomato paste + Italian seasoning until smooth. This is your high-protein pizza sauce.`,`Spread sauce on naan. Top with chicken, peppers, onion, and mozzarella.`,`Bake 8-10 minutes until cheese is bubbly and naan edges are crispy.`,`Hit with chili flakes, fresh basil, and a tiny drizzle of olive oil.`,`Two naan = 40g protein. That's a pizza night that doesn't derail anything.`]},{id:8,status:`placeholder`,slug:`chicken-thigh-2-marinade-prep`,proteinAnchor:`chicken`,mealType:`other`,flavorDirection:`smoky-southwest`,splitFriendly:`full`,title:`Chicken Thigh Meal Prep (2 Marinade System)`,category:`Fast Meals`,pillar:`Protein Meals`,tags:[`meal-prep`,`chicken`,`system`,`family-friendly`],time:`35 min`,servings:8,protein:44,calories:380,image:`https://images.unsplash.com/photo-1598515214211-89d3c73ae83b?w=600&h=400&fit=crop`,description:`One sheet pan, two marinades: adult spicy + kid mild. Same cook time, same method, two different meals. This is VERY valuable content.`,whyItWorks:`Bone-in thighs are cheaper and juicier than breast. Two marinades on one pan = family meal without cooking twice. The yogurt base tenderizes AND adds protein.`,ingredients:[`8 bone-in, skin-on chicken thighs`,`--- ADULT SPICY MARINADE ---`,`1/2 cup Greek yogurt`,`2 tbsp harissa paste`,`1 tbsp smoked paprika`,`1 tsp cumin`,`4 cloves garlic, minced`,`Juice of 1 lemon`,`Salt and pepper`,`--- KID MILD MARINADE ---`,`1/2 cup Greek yogurt`,`2 tbsp honey`,`1 tbsp Dijon mustard`,`1 tsp garlic powder`,`1 tsp Italian seasoning`,`Salt and pepper`],steps:[`Mix each marinade in separate bowls. Coat 4 thighs in spicy, 4 in mild. Marinate 30 min minimum (overnight is better).`,`Preheat oven to 425°F (220°C). Line sheet pan with foil.`,`Place thighs skin-side UP on the pan — spicy on one side, mild on the other. Mark the dividing line if needed.`,`Pat the skin dry with paper towels BEFORE placing on pan. Non-negotiable for crispy skin.`,`Roast 35-40 minutes until skin is crackling and internal temp hits 165°F.`,`Let rest 5 minutes. The yogurt marinade keeps them juicy even reheated 3 days later.`,`Pair with rice, salad, or lavash. You've got 4 days of protein locked down from 35 minutes of work.`]},{id:9,status:`placeholder`,slug:`pan-seared-bavette-chimichurri`,proteinAnchor:`steak`,mealType:`other`,flavorDirection:`smoky-southwest`,splitFriendly:`adult-only`,title:`Pan-Seared Bavette with Chimichurri`,category:`Steak & Protein`,pillar:`Cooking Techniques`,tags:[`steak`,`technique`,`chimichurri`,`date-night`],time:`25 min`,servings:2,protein:52,calories:420,image:`https://images.unsplash.com/photo-1558030006-450675393462?w=600&h=400&fit=crop`,description:`Bavette (flap steak) is the most underrated cut. Proper sear + proper slicing + fresh chimichurri. This is technique-driven protein.`,whyItWorks:`Bavette has more flavor than filet at 1/3 the price. The grain runs one direction — slice against it and it's butter. Chimichurri adds acid and freshness that cuts through the richness.`,ingredients:[`500g bavette (flap steak)`,`2 tbsp olive oil`,`2 tbsp butter`,`4 cloves garlic, smashed`,`Fresh rosemary sprigs`,`Flaky salt and cracked black pepper`,`--- CHIMICHURRI ---`,`1 cup flat-leaf parsley, finely chopped`,`4 cloves garlic, minced`,`2 tbsp red wine vinegar`,`1/3 cup olive oil`,`1 tsp red chili flakes`,`1/2 tsp oregano`,`Salt to taste`],steps:[`Make chimichurri: mix parsley, garlic, vinegar, olive oil, chili flakes, oregano, and salt. Set aside — it gets better as it sits.`,`Pat bavette completely dry. Season HEAVILY with flaky salt and pepper. Let it sit at room temp 20 minutes.`,`Get cast iron screaming hot — you should see wisps of smoke. Add olive oil.`,`Lay steak away from you. Don't touch for 4 minutes. You're building a crust.`,`Flip. Add butter, garlic, and rosemary. Baste by tilting pan and spooning butter over the steak for 3 minutes.`,`Pull at 125°F for medium-rare. Rest 8-10 minutes — this is when carryover cooking finishes the job.`,`Slice THIN against the grain at a 45° angle. Top with chimichurri. The slicing angle is what makes this cut work — get it wrong and it's chewy.`]},{id:10,status:`placeholder`,slug:`picanha-reverse-sear`,proteinAnchor:`steak`,mealType:`other`,flavorDirection:`smoky-southwest`,splitFriendly:`adult-only`,title:`Picanha Fat Cap Reverse Sear`,category:`Steak & Protein`,pillar:`Cooking Techniques`,tags:[`steak`,`technique`,`reverse-sear`,`educational`],time:`1 hr`,servings:4,protein:55,calories:480,image:`https://images.unsplash.com/photo-1544025162-d76694265947?w=600&h=400&fit=crop`,description:`The Brazilian steakhouse cut, done at home. Reverse sear method = perfect edge-to-edge medium-rare + rendered crispy fat cap. This is educational content.`,whyItWorks:`Reverse sear gives you zero gray band — pink wall to wall. Starting low renders the fat cap properly. The final sear is just for crust. Science, not luck.`,ingredients:[`1 kg picanha (sirloin cap), fat cap on`,`Coarse salt (generous)`,`Cracked black pepper`,`2 tbsp high-smoke-point oil (avocado)`,`Flaky salt for finishing`],steps:[`Score the fat cap in a crosshatch pattern, 1/4 inch deep. Don't cut into the meat.`,`Season with coarse salt and pepper. Place on a wire rack over a sheet pan, fat cap UP.`,`Into a 250°F (120°C) oven. Low and slow. You're targeting 115°F internal — this takes 40-50 minutes.`,`Pull at 115°F. Rest on cutting board while you heat cast iron to smoking hot.`,`Sear fat cap side DOWN first — 2 minutes until it's crackling and rendered. Then sear all other sides, 45 seconds each.`,`Rest another 5 minutes. The carryover brings you to perfect 130°F medium-rare.`,`Slice against the grain in 1/2 inch pieces. Each slice should have a strip of rendered fat cap on top. Finish with flaky salt.`]},{id:11,status:`placeholder`,slug:`smoky-southwest-flank-steak`,proteinAnchor:`steak`,mealType:`other`,flavorDirection:`smoky-southwest`,splitFriendly:`easy-swap`,title:`Smoky Southwest Flank Steak`,category:`Steak & Protein`,pillar:`Protein Meals`,tags:[`steak`,`spicy`,`southwest`,`meal-prep`],time:`30 min`,servings:4,protein:48,calories:390,image:`https://images.unsplash.com/photo-1432139555190-58524dae6a55?w=600&h=400&fit=crop`,description:`Your spice-forward style applied to flank steak. Smoky-sweet-heat rub, high-heat sear, sliced for bowls or wraps. This is your weeknight steak system.`,whyItWorks:`Flank is lean, affordable, and absorbs rubs well. The smoked paprika + cumin + brown sugar combo creates bark without a smoker. Versatile enough for bowls, wraps, or salads.`,ingredients:[`600g flank steak`,`1 tbsp smoked paprika`,`1 tsp cumin`,`1 tsp chili powder`,`1/2 tsp garlic powder`,`1/2 tsp brown sugar`,`1/2 tsp cayenne`,`Salt and pepper`,`2 tbsp olive oil`,`Lime wedges`],steps:[`Mix all spices into a rub. Coat flank steak on both sides. Press it in.`,`Let steak sit at room temp 15-20 minutes while the rub sets.`,`Get a grill or cast iron screaming hot. Oil the surface.`,`Sear 4-5 minutes per side for medium-rare (130°F internal).`,`Rest 10 minutes. This is not optional — cut too early and all the juice runs out.`,`Slice thin against the grain. Squeeze lime over the top.`,`Use in rice bowls, wraps, salads, or just eat the plate. Meal preps well sliced and stored.`]},{id:12,status:`placeholder`,slug:`cottage-cheese-fajita-pasta`,proteinAnchor:`chicken`,mealType:`pasta`,flavorDirection:`creamy-comfort`,splitFriendly:`easy-swap`,title:`Creamy Cottage Cheese Fajita Pasta`,category:`Pasta Systems`,pillar:`Sauce Systems`,tags:[`pasta`,`cottage-cheese`,`fajita`,`signature-sauce`],time:`25 min`,servings:4,protein:46,calories:480,image:`https://images.unsplash.com/photo-1621996346565-e3dbc646d9a9?w=600&h=400&fit=crop`,description:`Your signature sauce system in its purest form. Blended cottage cheese + fajita seasoning + pasta. This is the recipe that proves cottage cheese sauce works.`,whyItWorks:`Cottage cheese blended smooth is indistinguishable from cream sauce. Fajita seasoning gives it a bold direction. This is your sauce system's flagship recipe.`,ingredients:[`350g penne or rotini`,`400g chicken breast, sliced`,`1.5 cups cottage cheese`,`1/2 cup chicken broth`,`2 tbsp fajita seasoning`,`1 bell pepper, sliced`,`1/2 onion, sliced`,`2 cloves garlic, minced`,`1 tbsp olive oil`,`Lime juice`,`Cilantro`,`Chili flakes`],steps:[`Blend cottage cheese + chicken broth + half the fajita seasoning until silky smooth. Taste it — this should be good enough to eat with a spoon.`,`Season chicken with remaining fajita seasoning. Sear over high heat until golden. Slice and set aside.`,`Cook pasta to al dente. Reserve 1 cup pasta water.`,`In the same pan, cook peppers and onion 3-4 minutes. Add garlic, 30 seconds.`,`Pour in the cottage cheese sauce. Bring to a gentle simmer — don't boil or it can break.`,`Add pasta and chicken. Toss, adding pasta water until the sauce coats everything.`,`Finish with lime juice, cilantro, and chili flakes. This is the recipe you send people when they ask 'what's the cottage cheese thing?'`]},{id:13,status:`placeholder`,slug:`spicy-chicken-rotini`,proteinAnchor:`chicken`,mealType:`pasta`,flavorDirection:`creamy-comfort`,splitFriendly:`easy-swap`,title:`Spicy Chicken Rotini (Low-Cal Cream Sauce)`,category:`Pasta Systems`,pillar:`Sauce Systems`,tags:[`pasta`,`chicken`,`spicy`,`low-cal`],time:`25 min`,servings:3,protein:48,calories:460,image:`https://images.unsplash.com/photo-1555949258-eb67b1ef0ceb?w=600&h=400&fit=crop`,description:`Lean but rich. The sauce is cottage cheese + a splash of milk + garlic + chili. Rotini catches it in every spiral. Feels indulgent, checks the macros.`,whyItWorks:`Rotini's ridges and spirals trap more sauce per bite than any other shape. The milk loosens the cottage cheese base without adding cream-level calories. Chili flakes make it addictive.`,ingredients:[`300g rotini`,`400g chicken breast, diced`,`1 cup cottage cheese`,`1/4 cup milk`,`4 cloves garlic, minced`,`1 tsp red chili flakes (more if you want heat)`,`1 tbsp olive oil`,`2 cups spinach`,`2 tbsp parmesan`,`Salt, pepper, Italian seasoning`,`Lemon juice`],steps:[`Blend cottage cheese + milk until completely smooth.`,`Season chicken with Italian seasoning, salt, pepper. Sear in olive oil over high heat until golden. Remove.`,`Cook rotini to al dente. Reserve pasta water.`,`In the chicken pan, toast garlic and chili flakes in olive oil for 30 seconds. This blooms the heat.`,`Add cottage cheese sauce. Stir until warmed through.`,`Toss in pasta, chicken, and spinach. Add pasta water until sauce consistency is perfect — creamy, not gloopy.`,`Finish with parmesan and lemon juice. The lemon brightens everything.`]},{id:14,status:`placeholder`,slug:`gnocchi-chicken-skillet`,proteinAnchor:`chicken`,mealType:`pasta`,flavorDirection:`creamy-comfort`,splitFriendly:`easy-swap`,title:`Gnocchi Chicken Skillet (Crispy Method)`,category:`Pasta Systems`,pillar:`Cooking Techniques`,tags:[`gnocchi`,`crispy`,`one-pan`,`texture`],time:`25 min`,servings:3,protein:44,calories:490,image:`https://images.unsplash.com/photo-1598866594230-a7c12756260f?w=600&h=400&fit=crop`,description:`The crispy gnocchi method, stripped to essentials. Pan-fried until golden on both sides + chicken + simple garlic sauce. Texture-focused cooking.`,whyItWorks:`Store-bought gnocchi goes from boring to elite with one technique: don't touch it in the pan. The starch crisps into a shell while the inside stays pillowy. That contrast is everything.`,ingredients:[`500g shelf-stable gnocchi`,`350g chicken breast, diced`,`3 tbsp olive oil`,`4 cloves garlic, sliced`,`1 cup cherry tomatoes, halved`,`2 cups baby spinach`,`1/2 cup chicken broth`,`2 tbsp parmesan`,`Red chili flakes`,`Salt and pepper`,`Fresh basil`],steps:[`Heat 2 tbsp olive oil in a large pan over medium-high. Add gnocchi in a SINGLE LAYER.`,`Do not touch for 3-4 minutes. Seriously. You're building a golden crust on the bottom.`,`Flip gnocchi, crisp the other side 2-3 minutes. Remove to a plate.`,`Same pan, add remaining oil. Sear chicken until golden, 4-5 minutes. Season with salt and pepper.`,`Add garlic and cherry tomatoes. Cook until tomatoes start to burst, 2 minutes.`,`Add chicken broth, let it reduce by half. Add spinach, wilt.`,`Return crispy gnocchi. Toss gently — if you smash them, you lose the crisp. Top with parmesan, chili flakes, and basil.`]},{id:15,status:`placeholder`,slug:`cottage-cheese-sauce-base`,proteinAnchor:`any`,mealType:`sauce`,flavorDirection:`creamy-comfort`,splitFriendly:`not-applicable`,title:`High-Protein Cream Sauce Base (Cottage Cheese System)`,category:`Sauces & Systems`,pillar:`Sauce Systems`,tags:[`sauce`,`system`,`cottage-cheese`,`foundational`],time:`5 min`,servings:4,protein:14,calories:80,image:`https://images.unsplash.com/photo-1563379926898-05f4575a45d8?w=600&h=400&fit=crop`,description:`The base that runs through half your recipes. Blended cottage cheese + broth + seasonings. Master this and you unlock high-protein versions of any cream sauce dish.`,whyItWorks:`Cottage cheese blended smooth has the same mouthfeel as heavy cream sauce but with 14g protein and 80 calories per serving instead of 400+. It's a system, not a hack.`,ingredients:[`2 cups cottage cheese (full fat for richness, low fat for cutting)`,`1/2 cup broth (chicken, beef, or vegetable — match your dish)`,`Your flavor direction (see variations below):`,`  FAJITA: 2 tbsp fajita seasoning + lime juice`,`  ITALIAN: 2 tbsp tomato paste + Italian seasoning + garlic`,`  ALFREDO: 3 tbsp parmesan + garlic + black pepper + nutmeg`,`  SOUTHWEST: 1 tbsp chipotle in adobo + cumin + lime`,`Salt to taste`],steps:[`Add cottage cheese and broth to a blender. Blend on HIGH for 60 seconds until completely smooth. No chunks.`,`Add your flavor direction ingredients. Blend 15 more seconds.`,`Taste and adjust salt. It should taste good straight from the blender — if it doesn't, it won't taste good on pasta.`,`To use: heat gently in a pan (don't boil). Toss with pasta + protein + pasta water until it coats everything.`,`This is your SYSTEM. Learn the base, then swap the flavor direction for any cuisine. One technique, infinite meals.`]},{id:16,status:`placeholder`,slug:`smoky-southwest-chili-oil`,proteinAnchor:`any`,mealType:`sauce`,flavorDirection:`smoky-southwest`,splitFriendly:`not-applicable`,title:`Smoky Southwest Chili Oil Drizzle`,category:`Sauces & Systems`,pillar:`Sauce Systems`,tags:[`sauce`,`chili-oil`,`condiment`,`flavor-bomb`],time:`10 min`,servings:12,protein:0,calories:45,image:`https://images.unsplash.com/photo-1472476443507-c7a5948772fc?w=600&h=400&fit=crop`,description:`Your flavor enhancer. Smoky, spicy oil that goes on everything — eggs, bowls, pizza, pasta, toast. Make a batch, keep it in the fridge, use daily.`,whyItWorks:`Fat carries flavor. This oil concentrates smoky-spicy-garlicky flavor so a small drizzle transforms bland protein into something you actually want to eat. Zero protein tax, maximum taste ROI.`,ingredients:[`1 cup neutral oil (avocado or vegetable)`,`3 tbsp red chili flakes (Korean gochugaru is ideal)`,`1 tbsp smoked paprika`,`1 tsp cumin`,`4 cloves garlic, minced fine`,`1 tbsp sesame seeds`,`1 tsp sugar`,`1/2 tsp salt`,`1 tsp soy sauce`],steps:[`Combine chili flakes, smoked paprika, cumin, garlic, sesame seeds, sugar, and salt in a heatproof bowl.`,`Heat oil in a small pot to 300°F (150°C) — use a thermometer or test with one chili flake (it should sizzle gently, not burn).`,`Pour hot oil over the dry ingredients. It should sizzle and bloom. Stir immediately.`,`Add soy sauce and stir. Let cool completely.`,`Transfer to a jar. Keeps in the fridge for 2-3 weeks.`,`Use on literally everything. This is the thing that makes 'boring protein + rice' actually taste good.`]},{id:17,status:`placeholder`,slug:`quick-chimichurri`,proteinAnchor:`any`,mealType:`sauce`,flavorDirection:`smoky-southwest`,splitFriendly:`not-applicable`,title:`Quick Chimichurri (No-Fuss Version)`,category:`Sauces & Systems`,pillar:`Sauce Systems`,tags:[`sauce`,`chimichurri`,`fresh`,`steak-companion`],time:`5 min`,servings:6,protein:0,calories:60,image:`https://images.unsplash.com/photo-1534938665420-4c43ac99b95c?w=600&h=400&fit=crop`,description:`Pantry-friendly chimichurri you can make in 5 minutes. No mortar and pestle, no special herbs. Flat-leaf parsley, garlic, oil, vinegar, chili. Done.`,whyItWorks:`Acid + herb + heat = the universal steak enhancer. Chimichurri cuts through fatty cuts and adds freshness to lean ones. It makes good steak great and great steak unforgettable.`,ingredients:[`1 cup flat-leaf parsley, finely chopped (stems are fine)`,`4 cloves garlic, minced`,`1/3 cup olive oil`,`2 tbsp red wine vinegar`,`1 tsp red chili flakes`,`1/2 tsp dried oregano`,`Salt and pepper`],steps:[`Chop parsley fine. Not paste — you want texture. Include tender stems.`,`Mix everything in a bowl. That's it.`,`Let it sit 10 minutes if you can — the flavors meld. But it's good immediately.`,`Serve with any steak, grilled chicken, or roasted vegetables.`,`Keeps in the fridge 5 days. The garlic gets stronger over time — feature, not a bug.`]},{id:18,status:`placeholder`,slug:`general-tso-sauce`,proteinAnchor:`any`,mealType:`sauce`,flavorDirection:`spicy-asian`,splitFriendly:`not-applicable`,title:`General Tso High-Protein Sauce`,category:`Sauces & Systems`,pillar:`Sauce Systems`,tags:[`sauce`,`asian`,`sweet-spicy`,`stir-fry`],time:`10 min`,servings:4,protein:2,calories:70,image:`https://images.unsplash.com/photo-1525755662778-989d0524087e?w=600&h=400&fit=crop`,description:`Balanced General Tso's sauce — sweet, spicy, tangy, sticky. Use on chicken, tofu, or any protein. Half the sugar of takeout, all the flavor.`,whyItWorks:`Takeout General Tso's is a sugar bomb. This version uses less sugar, more vinegar and chili, and soy sauce for depth. The cornstarch slurry gives it that glossy takeout texture.`,ingredients:[`3 tbsp soy sauce`,`2 tbsp rice vinegar`,`1 tbsp hoisin sauce`,`1 tbsp honey or brown sugar`,`1 tbsp sriracha or sambal`,`1 tsp sesame oil`,`2 cloves garlic, minced`,`1 tsp ginger, grated`,`1 tbsp cornstarch + 2 tbsp water (slurry)`],steps:[`Whisk soy sauce, rice vinegar, hoisin, honey, sriracha, and sesame oil in a bowl.`,`In a small pot, briefly sauté garlic and ginger in a drop of oil, 30 seconds.`,`Pour in the sauce mixture. Bring to a simmer.`,`Add cornstarch slurry while stirring. Sauce will thicken in 60 seconds to a glossy coat.`,`Pour over fried or seared chicken, shrimp, or tofu.`,`The vinegar-to-sugar ratio is the key. If it's too sweet, add more vinegar. If too tangy, a touch more honey. Dial it to your taste.`]},{id:19,status:`placeholder`,slug:`air-fryer-charred-broccoli`,proteinAnchor:`any`,mealType:`side`,flavorDirection:`smoky-southwest`,splitFriendly:`not-applicable`,title:`Air Fryer Charred Broccoli (No-Soggy Method)`,category:`Sides That Matter`,pillar:`Cooking Techniques`,tags:[`side`,`broccoli`,`air-fryer`,`technique`],time:`12 min`,servings:2,protein:4,calories:80,image:`https://images.unsplash.com/photo-1584270354949-c26b0d5b4a0c?w=600&h=400&fit=crop`,description:`Broccoli that's charred on the edges, tender in the middle, never soggy. The technique is the content: high heat, dry florets, single layer. That's the whole trick.`,whyItWorks:`Most people steam their broccoli in the air fryer by crowding and using wet florets. Dry florets + space + high heat = Maillard reaction on vegetables. Charred edges have flavor that steamed broccoli never will.`,ingredients:[`1 large head broccoli, cut into florets`,`1.5 tbsp olive oil`,`1 tsp garlic powder`,`Salt and pepper`,`Squeeze of lemon`,`Red chili flakes (optional)`,`Parmesan shavings (optional)`],steps:[`Cut broccoli into even-sized florets. PAT COMPLETELY DRY. Moisture is the enemy of char.`,`Toss with olive oil, garlic powder, salt, and pepper.`,`Air fryer at 400°F (200°C). Single layer — if you have to stack, do two batches.`,`Cook 10-12 minutes, shaking basket once at 6 minutes.`,`You want blackened tips and crispy edges. If it's uniformly green, it's not done.`,`Finish with lemon juice and optional parmesan or chili flakes.`]},{id:20,status:`placeholder`,slug:`sweet-potato-croutons`,proteinAnchor:`any`,mealType:`side`,flavorDirection:`smoky-southwest`,splitFriendly:`not-applicable`,title:`Sweet Potato Croutons`,category:`Sides That Matter`,pillar:`Cooking Techniques`,tags:[`side`,`sweet-potato`,`texture`,`hack`],time:`25 min`,servings:4,protein:2,calories:120,image:`https://images.unsplash.com/photo-1596097635121-14b63a7abeec?w=600&h=400&fit=crop`,description:`Sweet potato cubed small and roasted until the edges are crunchy. Use as a texture topper on bowls, salads, or next to any protein. This is a texture contrast hack.`,whyItWorks:`Small cubes = more surface area = more crispy edges. Sweet potatoes caramelize naturally, so the edges get almost candy-crisp while the inside stays creamy. This solves the 'my bowl is all soft textures' problem.`,ingredients:[`2 medium sweet potatoes, peeled and cubed into 1/2 inch pieces`,`2 tbsp olive oil`,`1 tsp smoked paprika`,`1/2 tsp garlic powder`,`1/2 tsp cumin`,`Salt and pepper`,`Flaky salt for finishing`],steps:[`Preheat oven to 425°F (220°C). Line sheet pan with parchment.`,`Cut sweet potatoes into SMALL cubes — 1/2 inch max. The smaller they are, the more edges crisp.`,`Toss with olive oil and all seasonings.`,`Spread in a single layer. Every piece needs contact with the pan — crowding = steaming.`,`Roast 20-25 minutes, flipping once at 15 minutes. Edges should be deeply caramelized.`,`Hit with flaky salt immediately out of the oven.`,`Use as croutons on salads, toppers on bowls, or a side to any protein. The crunch factor changes the whole plate.`]},{id:21,status:`live`,carbLevel:`none`,meta:{macros:{protein:42,calories:380,fat:16,carbs:8,netCarbs:5,estimated:!0},allergens:[`dairy`],warnings:[`contains-dairy`],dietTags:[`gluten-free`,`halal`,`low-carb`],proteinTags:[`chicken`],splitAxes:[`spice`],effortTags:[`fast`,`air-fryer`],costTier:`budget`,costPerServing:`$3.50`,substitutionNotes:[`swap thighs for chicken breast`,`skip Cheesoning for dairy-free broccoli`,`use any mild seasoning for kid side`]},slug:`air-fryer-chicken-thighs-cheesy-broccoli`,proteinAnchor:`chicken`,mealType:`other`,flavorDirection:`smoky-southwest`,splitFriendly:`full`,title:`Air Fryer Chicken Thighs + Cheesy Broccoli`,category:`Core Signatures`,pillar:`Protein Meals`,tags:[`air-fryer`,`chicken`,`broccoli`,`split-cook`,`easy`,`hands-off`],time:`25 min`,servings:4,protein:42,calories:380,image:`/images/airfryer-chicken/hero-adult-plate.jpg`,role:`The Hands-Off Winner`,makeThisWhen:`You want dinner done in 25 minutes with zero pan-watching — air fryer does the work while you handle everything else.`,hook:`This is the recipe that proves 'chicken and broccoli' doesn't have to be sad. Dan-O's Cheesoning on hot broccoli changes everything. Same cook, different plates — kids get comfort, adults get flavor.`,description:`~42g protein for ~380 calories. Air fryer chicken thighs seasoned two ways (mild for kids, bold for adults) + broccoli finished with Dan-O's Cheesoning. Dinner rolls for kids. 25 minutes, hands-off.`,whyMostFail:[`Chicken and broccoli = the most boring meal in fitness`,`Air fryer broccoli usually comes out steamed and soggy`,`Kids won't eat it because it all looks the same`],whyThisWorks:[`Split seasoning: Dan-O's Original (kids) vs Outlaw Blackened Bloody Mary (adults) — same cook time`,`Cheesoning on hot broccoli = transforms boring veg into something people actually eat`,`Air fryer = hands-off, consistent, no babysitting`,`Different plates from the same cook — kids get a roll for comfort, adults get extra broccoli for volume`],executionRules:[`Pat chicken DRY before seasoning — moisture kills crispness in the air fryer.`,`Don't overcrowd broccoli — single layer or it steams instead of crisps.`,`Add Cheesoning IMMEDIATELY when broccoli comes out — it needs the heat to stick.`,`Don't skip the flip at halfway — both sides need direct heat.`],troubleshooting:[{problem:`Chicken isn't crispy on the outside`,fix:`You didn't pat it dry. Also check you used oil spray — it needs a thin fat layer for browning.`},{problem:`Broccoli is soggy / steamed`,fix:`Overcrowded the basket. Do two batches if needed. Single layer is non-negotiable.`},{problem:`Cheesoning didn't stick`,fix:`You waited too long. Sprinkle within 30 seconds of pulling from the air fryer while it's still hot.`},{problem:`Chicken overcooked / dry`,fix:`Thighs are forgiving but check at 16 min. Pull at 165°F internal — carryover does the rest.`}],splitCook:{splitRatio:`50% Adult / 50% Kid`,splitPoint:`STOP. Chicken and broccoli are done. Plate differently — adults get bold seasoning + extra veg, kids get mild + dinner roll.`,sharedIngredients:[`--- PROTEIN ---`,`6-8 chicken thighs (boneless, skinless)`,`Oil spray`,`--- VEG ---`,`Frozen broccoli florets`,`Oil spray`,`Dan-O's Cheesoning (for finishing)`],sharedSteps:[{text:`PREP CHICKEN: Pat chicken thighs completely dry. Light oil spray on both sides.`,images:[`/images/airfryer-chicken/step1-raw-airfryer.jpg`]},{text:`SEASON SPLIT: Season half with Dan-O's Original (kid/mild side), half with Outlaw Blackened Bloody Mary (adult/bold side). Both go in the air fryer together.`},{text:`PREP BROCCOLI: Toss frozen broccoli with light oil spray + salt. Don't overcrowd. Cheesoning goes on AFTER cooking.`,images:[`/images/airfryer-chicken/step2-broccoli-prep.jpg`]},{text:`COOK CHICKEN: 375°F, 16-20 min, flip halfway. Target: 165°F internal.`},{text:`COOK BROCCOLI: 400°F, 10-14 min, shake halfway. Goal: crispy charred edges.`},{text:`CHEESONING FINISH: Immediately sprinkle Dan-O's Cheesoning on hot broccoli. Toss while hot — this is the differentiator.`}],adult:{label:`Adult — Bold + High Protein`,protein:42,calories:380,extraIngredients:[`--- ADULT SEASONING ---`,`Dan-O's Outlaw Blackened Bloody Mary`,`Extra Cheesoning`,`Optional: Money Mustard sauce`],steps:[{text:`PLATE: 2 chicken thighs (Outlaw seasoned) + 4 oz cheesy broccoli. Optional Money Mustard on the side.`}]},kid:{label:`Kid Plate — Comfort + Familiar`,protein:22,calories:320,proteinSwap:`If kids don't like thighs, cube the chicken into bite-sized pieces or use Kirkland chicken bites.`,options:[{label:`Option A — Full Plate`,extraIngredients:[`Dan-O's Original + salt (mild)`,`1 dinner roll per kid`],steps:[{text:`PLATE: 1 chicken thigh (Original seasoned) + 2 oz broccoli + dinner roll. Cube chicken if needed for small kids.`,images:[`/images/airfryer-chicken/kid-plate.jpg`]}]},{label:`Option B — Deconstructed`,extraIngredients:[`Ketchup or mild dipping sauce on side`],steps:[{text:`PLATE: Cubed chicken + broccoli on side (not mixed) + roll. Dipping sauce optional.`}]}]}},ingredients:[`--- PROTEIN ---`,`6-8 chicken thighs (boneless, skinless)`,`Dan-O's Outlaw Blackened Bloody Mary seasoning`,`Oil spray`,`--- VEG ---`,`Frozen broccoli florets`,`Oil spray`,`Salt`,`Dan-O's Cheesoning`,`--- OPTIONAL ---`,`Money Mustard sauce`],steps:[{text:`PREP: Pat chicken dry. Oil spray. Season with Outlaw Blackened Bloody Mary.`,images:[`/images/airfryer-chicken/step1-raw-airfryer.jpg`]},{text:`COOK CHICKEN: Air fryer 375°F, 16-20 min, flip halfway. Pull at 165°F.`},{text:`PREP BROCCOLI: Toss frozen broccoli with oil spray + salt. Single layer.`,images:[`/images/airfryer-chicken/step2-broccoli-prep.jpg`]},{text:`COOK BROCCOLI: Air fryer 400°F, 10-14 min, shake halfway. Charred edges.`},{text:`CHEESONING: Sprinkle Dan-O's Cheesoning on hot broccoli immediately. Toss.`},{text:`PLATE: Chicken + cheesy broccoli. Money Mustard on the side if you want.`,images:[`/images/airfryer-chicken/hero-adult-plate.jpg`]}],brands:[{name:`Dan-O's`,item:`Original Seasoning`,why:`Mild all-purpose for kid-friendly chicken + salt base`,image:`/images/brands/danos-original.png`,url:`https://danosseasoning.com/product/original-seasoning-large/`},{name:`Dan-O's`,item:`Outlaw Blackened Bloody Mary Bloody Mary`,why:`Bold smoky heat for adult chicken — same cook time, completely different flavor`,image:`/images/brands/danos-blackened-bloody-mary.png`,url:`https://danosseasoning.com/product/blackened-bloody-mary-medium-bottle/`},{name:`Dan-O's`,item:`Cheesoning`,why:`The broccoli hack — sprinkle on hot veg and it transforms into something people actually request`,image:`/images/brands/danos-cheesoning.png`,url:`https://danosseasoning.com/product/cheesoning-seasoning-medium/`}],mealPrep:{storage:`Store chicken and broccoli separately. Chicken reheats well, broccoli loses some crunch.`,reheat:`Air fryer 350°F for 3-4 min to re-crisp. Microwave works for chicken but kills broccoli texture.`,lasts:`3-4 days in fridge.`}},{id:22,status:`live`,carbLevel:`low`,meta:{macros:{protein:45,calories:500,fat:22,carbs:18,netCarbs:8,estimated:!0},allergens:[`dairy`,`gluten`],warnings:[`contains-dairy`,`contains-gluten`],dietTags:[`halal`,`keto-option`],proteinTags:[`chicken`],splitAxes:[`carb`],effortTags:[`fast`,`survival-mode`,`one-pan`,`one-hand`],costTier:`budget`,costPerServing:`$4.00`,substitutionNotes:[`use GF tortillas for gluten-free`,`swap ground chicken for ground turkey`,`skip cheese for dairy-free`]},slug:`chicken-smash-caesar-tacos`,proteinAnchor:`chicken`,mealType:`other`,flavorDirection:`caesar-crunch`,splitFriendly:`full`,title:`Chicken Smash Caesar Tacos`,category:`Core Signatures`,pillar:`Protein Meals`,tags:[`tacos`,`chicken`,`caesar`,`smash`,`split-cook`,`keto-option`,`fast`],time:`15 min`,servings:4,protein:45,calories:500,image:`/images/smash-tacos/hero.png`,role:`The Dual-Carb System`,makeThisWhen:`You want fast food satisfaction at home — crispy smash tacos with a Caesar twist. Keto tortillas for adults, regular for kids. Same cook, different carb profiles.`,hook:`This is your first dual-carb system recipe. One base, two tortilla types, two different plates. Adults get keto + Quest crunch. Kids get familiar tacos + chips on the side. No food fights.`,description:`~45g protein for ~500 cal. Ground chicken smashed directly onto tortillas with melted cheddar inside. Caesar finish with romaine + Bolthouse dressing. Quest chip crunch for adults. 15 minutes.`,whyMostFail:[`99/1 ground chicken dries out instantly without a hack`,`Smash tacos fall apart if spread too thick or flipped too early`,`Taco seasoning overpowers everything — ruins the Caesar profile`],whyThisWorks:[`Cheese mixed into raw chicken = melts inside, keeps it moist + binds to tortilla`,`40g per keto tortilla, 50g per regular = dialed ratios that actually cook right`,`Light Spiceology Taco seasoning as background spice — Caesar dressing carries the flavor`,`Quest chips = crunch + protein without junk carbs`],executionRules:[`Spread chicken THIN on tortilla — thick = raw center, bad texture.`,`Chicken side down first — always. If you flip too early, it breaks apart.`,`Keep seasoning subtle — this is a Caesar taco, not a taco-taco.`,`Cover briefly to steam through — ensures inside cooks without drying out.`],troubleshooting:[{problem:`Chicken is dry / rubbery`,fix:`You overcooked it or skipped the cheese. Cheddar mixed into the chicken is what keeps 99/1 moist.`},{problem:`Taco falls apart when flipping`,fix:`You flipped too early. Wait 4-5 min until chicken is fully browned and bound to tortilla.`},{problem:`Tastes like a regular taco, not Caesar`,fix:`Too much Spiceology Taco seasoning. Keep it to ~1/2 tsp per serving. Let the Caesar dressing carry the flavor.`},{problem:`Chicken layer too thick / raw in center`,fix:`Spread thinner. 40g per keto tortilla, 50g per regular. Cover pan briefly to steam through.`}],splitCook:{splitRatio:`50% Adult / 50% Kid`,splitPoint:`STOP. All tacos are cooked. Plate differently — adults get Caesar + Quest crunch, kids get simple tacos + sides.`,sharedIngredients:[`--- PROTEIN BASE ---`,`24 oz 99/1 ground chicken (or 93/7 for better taste, minimal calorie penalty)`,`4 oz Kraft Mild Cheddar, shredded (mixed into chicken)`,`Redmond Real Salt`,`Spiceology Taco Seasoning (~2 tsp total, keep it light)`,`--- FINISH ---`,`Fresh cilantro`,`Lime wedges`],sharedSteps:[{text:`MIX: Combine ground chicken, shredded cheddar, salt, and light Spiceology Taco seasoning. Don't overmix — keep it loose.`,images:[`/images/smash-tacos/step1-ingredients.png`,`/images/smash-tacos/step2-mixing.png`]},{text:`SMASH: Spread 40g chicken mix onto each keto tortilla, 50g onto each street taco tortilla. Thin and even — this is critical.`,images:[`/images/smash-tacos/step3-smash-raw.png`]},{text:`COOK: Chicken side down on griddle or flat pan, medium heat, 4-5 min until browned. Flip, cook tortilla side 1-2 min. Cover briefly to steam through.`,images:[`/images/smash-tacos/step4-griddle-cooking.png`]}],adult:{label:`Adult — Caesar Crunch (Keto)`,protein:45,calories:500,extraIngredients:[`--- ADULT BUILD ---`,`4 Mission Zero Net Carbs tortillas`,`Romaine lettuce, chopped`,`Bolthouse Farms Caesar dressing (~2 tbsp)`,`Quest Loaded Taco Chips, crushed (~15g)`,`Fresh cilantro + lime squeeze`],steps:[{text:`BUILD: Top each taco with romaine, Bolthouse Caesar, crushed Quest chips, cilantro, and a squeeze of lime.`,images:[`/images/smash-tacos/step5-caesar-salad.png`,`/images/smash-tacos/step6-plated-adult.png`]}]},kid:{label:`Kid — Classic Tacos + Sides`,protein:23,calories:400,extraIngredients:[`--- KID BUILD ---`,`2 Mission Street Tacos flour tortillas`,`Romaine (optional, on side)`,`Regular Caesar dressing (milder)`,`Regular chips (side)`],variants:[{name:`Simple`,description:`Plain taco, salad on side, chips on side`,steps:[{text:`PLATE: Keep tacos simple — light dressing or none. Salad on side. Regular chips on side.`}]}]}},ingredients:[`--- PROTEIN BASE ---`,`24 oz 99/1 ground chicken (or 93/7 for better taste)`,`4 oz Kraft Mild Cheddar, shredded`,`Redmond Real Salt`,`Spiceology Taco Seasoning`,`--- TORTILLAS ---`,`Mission Zero Net Carbs (adults)`,`Mission Street Tacos flour (kids)`,`--- TOPPINGS ---`,`Romaine lettuce`,`Bolthouse Farms Caesar dressing`,`Quest Loaded Taco Chips`,`Fresh cilantro`,`Lime`],steps:[{text:`MIX: Combine ground chicken, shredded cheddar, salt, and light Spiceology Taco seasoning. Keep it loose.`,images:[`/images/smash-tacos/step1-ingredients.png`,`/images/smash-tacos/step2-mixing.png`]},{text:`SMASH: Spread 40g on keto tortillas, 50g on street taco tortillas. Thin and even.`,images:[`/images/smash-tacos/step3-smash-raw.png`]},{text:`COOK: Chicken side down on griddle, medium heat, 4-5 min. Flip, 1-2 min. Cover briefly to steam through.`,images:[`/images/smash-tacos/step4-griddle-cooking.png`]},{text:`BUILD: Top with romaine, Caesar dressing, crushed Quest chips, cilantro, and lime (adults). Kids get simpler tacos + sides.`,images:[`/images/smash-tacos/step5-caesar-salad.png`,`/images/smash-tacos/step6-plated-adult.png`]}],brands:[{name:`Spiceology`,item:`Taco Seasoning`,why:`Clean taco seasoning with no fillers — periodic table jar looks sick on the counter too`,image:`/images/brands/spiceology-taco.jpg`,url:`https://spiceology.com/products/taco-seasoning`},{name:`Mission`,item:`Zero Net Carbs Tortillas`,why:`Keto-friendly, holds up to smash cooking, 3 tortillas = 110 cal`,image:`/images/brands/mission-zero-carbs.png`,url:`https://www.missionfoods.com/products/zero-net-carbs-tortillas-original/`},{name:`Mission`,item:`Street Tacos Flour Tortillas`,why:`Perfect street taco size for kids — soft, familiar, no resistance`,image:`/images/brands/mission-street-tacos.png`,url:`https://www.missionfoods.com/products/street-tacos-flour-tortillas/`},{name:`Quest`,item:`Loaded Taco Protein Chips`,why:`Protein + crunch without junk carbs — crushed on top is the move`,image:`/images/brands/quest-loaded-taco.png`,url:`https://www.questnutrition.com/products/loaded-taco-protein-chips`},{name:`Bolthouse Farms`,item:`Creamy Caesar Dressing`,why:`Lower calorie Caesar that actually tastes good — yogurt-based, refrigerated`,image:`/images/brands/bolthouse-caesar.png`,url:`https://www.bolthouse.com/product/creamy-caesar/`},{name:`Kraft`,item:`Mild Cheddar Shredded`,why:`Melts into the chicken mix — binds and adds moisture. Regular mild, not fat free`,image:`/images/brands/kraft-ff-cheddar.jpg`,url:`https://kraftnaturalcheese.com/product/shredded-cheese/cheddar-fat-free/`}],mealPrep:{storage:`Store cooked tacos flat in container. Toppings separate.`,reheat:`Air fryer 350°F 2-3 min to re-crisp. Don't microwave — kills the crunch.`,lasts:`2-3 days. Best fresh.`},notes:`You used 99/1 for best macros, but 93/7 ground chicken will taste better — juicier, richer — without sacrificing too many calories. Worth trying both.`},{id:24,status:`live`,carbLevel:`high`,meta:{macros:{protein:45,calories:520,fat:20,carbs:50,netCarbs:48,estimated:!0},allergens:[`dairy`],warnings:[`contains-dairy`],dietTags:[`gluten-free`,`halal`],proteinTags:[`beef`,`steak`],splitAxes:[`portion`],effortTags:[`meal-prep`],costTier:`moderate`,costPerServing:`$6.00`,substitutionNotes:[`swap ghee for oil for dairy-free`,`carb lever: adults ½ cup jasmine (~22g net) + extra steak, kids full cup — split the rice, don't kill it`,`swap steak for chicken or ground beef`]},slug:`golden-garlic-rice-bowl-steak`,proteinAnchor:`beef`,mealType:`bowl`,flavorDirection:`golden-savory`,splitFriendly:`full`,title:`Golden Garlic Rice Bowl with Steak`,category:`Core Signatures`,pillar:`Protein Meals`,tags:[`rice`,`steak`,`bowl`,`turmeric`,`garlic`,`split-cook`,`meal-prep-base`],time:`25 min`,servings:4,protein:45,calories:520,image:`/images/garlic-rice-bowl/hero.webp`,role:`The Repeatable System Meal`,makeThisWhen:`You want a high-flavor bowl that scales for the whole family — make the rice once, cook steak fresh each time, rotate sauces across meals.`,hook:`This is not a one-off recipe. It's a system meal. ~45g protein, ~520 cal. Golden turmeric rice cooked in bone broth, fresh-seared steak, and a controlled sauce drizzle. Make the rice once, eat it 2-3 times. Cook steak fresh in 10 minutes. Same base, different sauces, zero boredom.`,description:`~45g protein for ~520 cal. Turmeric garlic rice cooked in bone broth with butter. Gary's QuickSteak seared fresh (~1.5 servings per adult bowl). Liquid Chipotle drizzle. Rice batch lasts 2-3 meals.`,whyMostFail:[`Rice is bland — just water and white rice, no flavor built in`,`Steak is overcooked and chewy because people batch it ahead`,`Too much oil/butter makes it calorie-dense without realizing`],whyThisWorks:[`Bone broth + turmeric + frozen garlic cubes + frozen baby onions = rice has built-in flavor, zero prep`,`Steak cooked fresh each time in 5-6 min — never batch the protein`,`Ghee is measured (2 tbsp) — better flavor than butter/oil combo without calorie creep`,`Rice base reuses across 2-3 meals with different proteins/sauces`],executionRules:[`Bloom the turmeric in fat for 30-60 seconds — raw turmeric tastes metallic.`,`Cook steak from frozen on HIGH heat — low heat = steamed, not seared.`,`Don't overcook the steak — 5-6 min max. It turns dry and chewy fast.`,`Measure the butter and oil — 21g each. Eyeballing doubles your calories.`],troubleshooting:[{problem:`Rice is bland / tastes plain`,fix:`You used water instead of bone broth, or skipped the garlic/shallot/turmeric base. The flavor base IS the recipe.`},{problem:`Rice is mushy`,fix:`Too much liquid or you didn't rinse the rice. Rinse until water runs clear. Use 2:1 broth to rice ratio.`},{problem:`Steak is chewy / tough`,fix:`You overcooked it or used low heat. High heat, 5-6 min, break apart as it cooks. Don't babysit — let it sear.`},{problem:`Bowl feels heavy / calorie bomb`,fix:`Too much ghee. Stick to 2 tbsp, measured. Ghee is calorie-dense — a little goes a long way.`},{problem:`Turmeric tastes raw / bitter`,fix:`You didn't bloom it. Stir turmeric in the hot fat for 30-60 seconds before adding rice.`}],splitCook:{splitRatio:`50% Adult / 50% Kid`,splitPoint:`STOP. Rice is done, steak is seared. Plate differently — adults get full portions + sauce, kids get smaller portions + minimal sauce.`,sharedIngredients:[`--- RICE BASE ---`,`300g rice (~1.5 cups raw)`,`3 cups chicken bone broth`,`1/2 pack Deep Quick Cubes Garlic (~30g)`,`1/2 pack Vadilal Red Baby Onions (~60g)`,`5g turmeric (~1.5 tsp)`,`10g salt (~1.5 tsp)`,`2 tbsp Kirkland Organic Ghee`,`--- PROTEIN ---`,`1 package Gary's QuickSteak Sirloin (cook fresh each time)`],sharedSteps:[{text:`FLAVOR BASE: Heat ghee in pot. Add frozen garlic cubes + frozen baby onions. Cook until soft and fragrant — not browned.`,images:[`/images/garlic-rice-bowl/step1-ingredients.webp`]},{text:`BLOOM TURMERIC: Add turmeric + salt. Stir 30-60 seconds in the hot fat. This removes the raw spice taste.`,images:[`/images/garlic-rice-bowl/step2-turmeric-bloom.webp`]},{text:`COOK RICE: Add rinsed rice, pour in bone broth. Bring to boil, reduce to low, cover. Cook ~15 min until done.`,images:[`/images/garlic-rice-bowl/step4-rice-steak-done.webp`]},{text:`SEAR STEAK: High heat pan. Add frozen sliced steak directly. Break apart, cook 5-6 min. Salt to taste. Don't overcook.`,images:[`/images/garlic-rice-bowl/step3-steak-sear.webp`]}],adult:{label:`Adult — Full Bowl + Sauce`,protein:45,calories:520,extraIngredients:[`--- ADULT FINISH ---`,`~1 serving rice per bowl`,`~1.5 servings steak`,`1 serving Liquid Chipotle Sauce`,`Optional: cilantro, lemon squeeze, crispy onions`],steps:[{text:`BUILD: Rice base, steak on top, light chipotle drizzle. Optional: cilantro + lemon squeeze for restaurant level.`}]},kid:{label:`Kid — Smaller Bowl, Mild`,protein:15,calories:350,extraIngredients:[`--- KID FINISH ---`,`~1/2 cup rice`,`~1/2 portion steak`,`Minimal or no sauce`],variants:[{name:`Simple Bowl`,description:`Rice + steak, no sauce`,steps:[{text:`PLATE: Half portion rice, half portion steak. No sauce or very light. The rice already has flavor from the broth and butter.`}]}]}},ingredients:[`--- RICE BASE ---`,`300g rice (~1.5 cups raw)`,`3 cups chicken bone broth`,`1/2 pack Deep Quick Cubes Garlic (~30g)`,`1/2 pack Vadilal Red Baby Onions (~60g)`,`5g turmeric (~1.5 tsp)`,`10g salt (~1.5 tsp)`,`2 tbsp Kirkland Organic Ghee`,`--- PROTEIN ---`,`1 package Gary's QuickSteak Sirloin`,`--- SAUCE ---`,`Liquid Chipotle Sauce`,`--- OPTIONAL FINISH ---`,`Fresh cilantro`,`Lemon wedge`,`Crispy fried onions`],steps:[{text:`FLAVOR BASE: Heat ghee in pot. Add frozen garlic cubes + frozen baby onions. Cook until soft and fragrant.`,images:[`/images/garlic-rice-bowl/step1-ingredients.webp`]},{text:`BLOOM TURMERIC: Add turmeric + salt. Stir 30-60 seconds in hot fat.`,images:[`/images/garlic-rice-bowl/step2-turmeric-bloom.webp`]},{text:`COOK RICE: Add rinsed rice + bone broth. Boil, reduce to low, cover 15 min.`,images:[`/images/garlic-rice-bowl/step4-rice-steak-done.webp`]},{text:`SEAR STEAK: High heat, frozen steak direct to pan. Break apart, 5-6 min. Salt to taste.`,images:[`/images/garlic-rice-bowl/step3-steak-sear.webp`]},{text:`BUILD: Rice in bowl, steak on top, light chipotle drizzle. Cilantro + lemon if finishing.`,images:[`/images/garlic-rice-bowl/step5-split-plate.webp`]}],brands:[{name:`Gary's QuickSteak`,item:`100% Sirloin Thinly Sliced Beef`,why:`Cooks from frozen in 5 min — real sirloin, not processed. Thin slices sear fast and stay tender.`,image:`/images/brands/garys-quicksteak.png`,url:`https://garysquicksteak.com/sirloin/`},{name:`Kirkland`,item:`Organic Ghee`,why:`Better flavor than butter + oil combo. High smoke point for the sauté, rich nutty taste in the rice.`,image:`/images/brands/kirkland-ghee.jpg`,url:`https://www.costco.com`},{name:`Deep`,item:`Quick Cubes Garlic`,why:`Frozen garlic cubes — no peeling, no mincing, same flavor. Pop them straight into the pot.`,image:`/images/brands/deep-garlic-cubes.webp`,url:`https://instamandi.com/products/deep-garlic-cubes-7-oz`},{name:`Vadilal`,item:`Red Baby Onions`,why:`Frozen baby onions — sweeter than shallots, zero prep. Thaw and cook, or straight from frozen.`,image:`/images/brands/vadilal-baby-onions.jpg`,url:`https://www.kesargrocery.com/vadilal-red-baby-onions-312-gm-sku45877/`},{name:`Roli Roti`,item:`Chicken Bone Broth`,why:`The rice absorbs real broth flavor — water makes bland rice, broth makes golden rice`,image:`/images/brands/roli-roti-broth.jpg`}],mealPrep:{storage:`Rice stores 3-4 days in fridge. Cook steak fresh each time — don't batch the protein.`,reheat:`Microwave rice with a splash of water to re-steam. Sear steak fresh.`,lasts:`Rice base: 3-4 days. Steak: cook per meal.`},notes:`This is a system meal, not a one-off. Make the rice once, eat it 2-3 times. Rotate sauces (chipotle → Money Mustard → yogurt-based) and proteins (steak → chicken → mince). The rice is the asset — everything else rotates around it.`},{id:23,status:`live`,carbLevel:`low`,meta:{macros:{protein:50,calories:600,fat:24,carbs:30,netCarbs:12,estimated:!0},allergens:[`gluten`,`soy`],warnings:[`contains-gluten`,`spicy-adult-version`],dietTags:[`dairy-free-option`,`halal`,`keto-option`],proteinTags:[`chicken`],splitAxes:[`carb`],effortTags:[`fast`,`survival-mode`,`air-fryer`,`one-hand`],costTier:`budget`,costPerServing:`$3.75`,substitutionNotes:[`use GF buns for gluten-free`,`swap fillets for chicken tenders`,`regular buns for non-keto version`]},slug:`spicy-chicken-sandwich`,proteinAnchor:`chicken`,mealType:`other`,flavorDirection:`spicy-crispy`,splitFriendly:`full`,title:`Spicy Chicken Sandwich`,category:`Core Signatures`,pillar:`Protein Meals`,tags:[`chicken`,`sandwich`,`fast-food`,`air-fryer`,`split-cook`,`keto-option`,`fast`],time:`15 min`,servings:4,protein:50,calories:600,image:`/images/chicken-sandwich/hero.png`,role:`The Fast Food Killer`,makeThisWhen:`You want Chick-fil-A or Popeyes satisfaction at home — crispy chicken sandwiches with controlled calories. Keto buns for adults, sliders for kids.`,hook:`Better than fast food — with control. Same Kirkland chicken fillets, two bun types, your choice of sauce. Adults get macro-friendly keto buns at 50 cal each. Kids get familiar sliders. No drive-through needed.`,description:`~50g protein for ~600 cal (2 sandwiches). Kirkland chicken fillets air fried crispy, Bettergoods keto buns for adults, slider buns for kids. Add Liquid Chipotle or Money Mustard. 15 minutes.`,whyMostFail:[`Fast food chicken sandwiches are 600+ cal for ONE sandwich`,`Homemade versions use raw chicken and take 45 min`,`People skip the bun swap and lose the macro advantage`],whyThisWorks:[`Kirkland frozen fillets = already breaded, consistent, air fryer perfect in 12 min`,`Bettergoods keto buns = 50 cal each vs 200+ for regular buns — that's 300 cal saved on 2 sandwiches`,`Sauce is controlled at ~1/2 serving per sandwich — flavor without calorie bomb`,`Kids get sliders from the same fillet — split one in half, regular buns, done`],executionRules:[`Air fry at 400°F — don't microwave. Crispiness is the entire point.`,`Toast the buns in a pan — 30 seconds, butter side down. Non-negotiable texture.`,`Sauce goes on the bun, not the chicken — prevents soggy bottom.`,`Half serving sauce max per sandwich — full serving overpowers everything.`],troubleshooting:[{problem:`Chicken isn't crispy`,fix:`You microwaved it or overcrowded the air fryer. Single layer, 400°F, 10-12 min.`},{problem:`Sandwich is dry`,fix:`You skipped the sauce. Even a half serving makes a huge difference. Also toast the bun — dry bun + dry chicken = bad.`},{problem:`Bun falls apart`,fix:`The keto buns are softer. Toast them lightly and don't over-sauce.`},{problem:`Kids won't eat it`,fix:`Split the fillet, use regular slider buns, serve plain or with ketchup. Don't force the spicy sauce.`}],splitCook:{splitRatio:`50% Adult / 50% Kid`,splitPoint:`STOP. Chicken is cooked. Plate differently — adults get keto buns + sauce, kids get sliders.`,sharedIngredients:[`--- PROTEIN ---`,`4 Kirkland Signature Lightly Breaded Chicken Breast Fillets`],sharedSteps:[{text:`COOK: Air fry chicken fillets at 400°F for 10-12 min until crispy and heated through.`},{text:`TOAST BUNS: Lightly toast all buns in a pan, 30 seconds butter side down.`}],adult:{label:`Adult — Spicy Keto Sandwich`,protein:50,calories:600,extraIngredients:[`--- ADULT BUILD ---`,`4 Bettergoods Keto Friendly Hamburger Buns (50 cal each)`,`Liquid Chipotle Sauce OR Money Mustard (~1/2 serving per sandwich)`,`Pickles (optional)`,`Shredded lettuce (optional)`],steps:[{text:`BUILD: Sauce on bottom bun. Chicken fillet. Pickles + lettuce if using. Top bun. Serve 2 per plate.`}]},kid:{label:`Kid — Chicken Sliders`,protein:25,calories:350,extraIngredients:[`--- KID BUILD ---`,`Slider buns (regular)`,`Ketchup (optional)`],variants:[{name:`Simple Sliders`,description:`Split fillet into 2, slider buns, plain or ketchup`,steps:[{text:`PLATE: Cut fillet in half. Place on slider buns. Serve plain or with ketchup. Fruit or chips on side.`}]}]}},ingredients:[`--- PROTEIN ---`,`4 Kirkland Signature Lightly Breaded Chicken Breast Fillets`,`--- BUNS ---`,`Bettergoods Keto Friendly Hamburger Buns (adults)`,`Slider buns (kids)`,`--- SAUCE ---`,`Liquid Chipotle Sauce or Money Mustard`,`--- TOPPINGS (optional) ---`,`Pickles`,`Shredded lettuce`],steps:[{text:`COOK: Air fry chicken fillets at 400°F for 10-12 min until crispy.`,images:[`/images/chicken-sandwich/prep.png`]},{text:`TOAST: Lightly toast buns in a pan, 30 seconds butter side down.`,images:[`/images/chicken-sandwich/prep.png`]},{text:`BUILD ADULT: Sauce on bottom bun. Chicken. Pickles + lettuce. Top bun. Serve 2 per plate.`},{text:`BUILD KID: Cut fillet in half. Slider buns. Plain or ketchup. Fruit on side.`}],brands:[{name:`Kirkland`,item:`Lightly Breaded Chicken Breast Fillets`,why:`Sandwich-shaped, consistent size, crispy in the air fryer — the fillet version, not the chunks`,image:`/images/brands/kirkland-chicken-fillets.jpg`,url:`https://www.costco.com/p/-/kirkland-signature-lightly-breaded-chicken-breast-fillets-3-lbs/4000300941`},{name:`Bettergoods`,item:`Keto Friendly Hamburger Buns`,why:`50 cal per bun — saves 300 cal vs regular buns on a 2-sandwich plate. Walmart brand, easy to find.`,image:`/images/brands/bettergoods-keto-buns.jpg`,url:`https://www.walmart.com/ip/bettergoods-Keto-Friendly-Hamburger-Buns-14-oz-8-Count/5352547355`}],mealPrep:{storage:`Cook fillets, store separate from buns. Assemble fresh.`,reheat:`Air fryer 350°F 3-4 min to re-crisp. Don't microwave.`,lasts:`Cooked fillets keep 3-4 days in fridge.`}},{id:25,status:`live`,carbLevel:`low`,meta:{macros:{protein:45,calories:620,fat:30,carbs:35,netCarbs:32,estimated:!0},allergens:[],warnings:[`contains-pork-kid-version`],dietTags:[`dairy-free`,`gluten-free-option`],proteinTags:[`beef`,`steak`],splitAxes:[`protein`],effortTags:[`fast`,`air-fryer`],costTier:`premium`,costPerServing:`$10.50`,substitutionNotes:[`swap bavette for flank or skirt steak`,`swap pork patties for chicken nuggets for pork-free`,`skip fries for lower carb`]},slug:`bavette-steak-fries-chimichurri`,proteinAnchor:`beef`,mealType:`other`,flavorDirection:`bold-herb`,splitFriendly:`full`,title:`Steak & Fries with Chimichurri`,category:`Core Signatures`,pillar:`Protein Meals`,tags:[`steak`,`bavette`,`fries`,`chimichurri`,`split-cook`,`air-fryer`,`fast`],time:`20 min`,servings:4,protein:45,calories:620,image:`/images/steak-fries/hero.webp`,role:`The Steak Night`,makeThisWhen:`You want a proper steak dinner that feels like a restaurant but takes 20 minutes. Kids get pork patties + fries from the same cook — no second meal.`,hook:`Bavette steak is the most underrated cut. Fast cook, insane flavor, and it slices beautifully against the grain. Pair it with a no-judge chimichurri (Spiceology seasoning + olive oil + vinegar) and air fryer fries. Kids swap to pork breakfast patties — zero resistance.`,description:`~45g protein for ~620 cal. Bavette steak with SPG seasoning, seared 2-3 min per side. No-judge chimichurri from Spiceology seasoning. Checkers/Rally's fries air fried. Kids get pork patties + fries + carrots.`,whyMostFail:[`People pick the wrong cut — too thick, too lean, too expensive`,`Steak gets overcooked because they don't rest it`,`Chimichurri from scratch takes 15 min of chopping — people skip it`],whyThisWorks:[`Bavette = thin, flavorful, fast-cooking. 2-3 min per side, done.`,`No-judge chimichurri: Spiceology seasoning + olive oil + vinegar. Mixed in 60 seconds.`,`Air fryer fries cook while you sear — zero overlap, zero waiting`,`Kids get pork patties from the same pan time — not a separate meal, just a separate protein`],executionRules:[`Rest the steak 5 minutes after cooking — this is NON-NEGOTIABLE. Skip it = dry steak.`,`Slice THIN against the grain — wrong direction = chewy mess.`,`Chimichurri needs 5-10 min to sit after mixing — don't skip or it tastes flat.`,`Fries go in first (12-15 min) — steak cooks during the last 5 min of fries.`],troubleshooting:[{problem:`Steak is chewy / tough`,fix:`You either overcooked it, didn't rest it, or sliced with the grain. 2-3 min per side, rest 5 min, slice thin AGAINST the grain.`},{problem:`Chimichurri tastes flat / raw`,fix:`You didn't let it sit. Mix it, wait 5-10 min. The vinegar needs time to bloom the dried herbs.`},{problem:`Fries are soggy`,fix:`Air fryer too crowded. Single layer, 400°F, no oil needed. Shake halfway.`},{problem:`Kids won't eat steak`,fix:`That's why you have pork patties. Don't force it. Same fries, add carrots, done.`}],splitCook:{splitRatio:`50% Adult / 50% Kid`,splitPoint:`STOP. Fries are done, steak is resting, patties are cooked. Plate differently — adults get steak + chimichurri, kids get patties + carrots.`,sharedIngredients:[`--- FRIES (shared) ---`,`Checkers/Rally's frozen fries (~1 serving per person)`],sharedSteps:[{text:`FRIES FIRST: Air fry at 400°F for 12-15 min. No oil, no spray. Shake halfway.`,images:[`/images/steak-fries/step2-fries.webp`]},{text:`SEAR STEAK: Season bavette with SPG. High heat stainless pan + cooking spray. 2-3 min per side.`,images:[`/images/steak-fries/step3-sear.webp`]},{text:`REST: Pull steak, rest 5 minutes. Cook pork patties in the same pan, 5 min per side.`},{text:`CHIMICHURRI: Mix olive oil + Spiceology chimichurri seasoning + red wine vinegar + chili flakes. Let sit 5 min.`},{text:`SLICE: Cut steak thin against the grain.`}],adult:{label:`Adult — Steak + Chimichurri`,protein:45,calories:620,extraIngredients:[`--- ADULT ---`,`6 oz bavette steak per person`,`SPG seasoning (salt, pepper, garlic)`,`Cooking spray`,`--- CHIMICHURRI ---`,`2 tbsp olive oil`,`1.5 tbsp Spiceology Chimichurri seasoning`,`1 tbsp red wine vinegar`,`Dash chili flakes`],steps:[{text:`PLATE: Sliced bavette + fries. Spoon chimichurri over the steak — not on the fries.`}]},kid:{label:`Kid — Pork Patties + Fries + Carrots`,protein:20,calories:400,extraIngredients:[`--- KID ---`,`1.5 pork breakfast patties per kid`,`Raw carrots (baby or sticks)`],variants:[{name:`Simple`,description:`Patties cut up, fries, carrots on side`,steps:[{text:`PLATE: Cut patties into small pieces. Fries on side. Raw carrots. No sauce needed.`}]}]}},ingredients:[`--- PROTEIN ---`,`6 oz bavette steak per adult`,`SPG seasoning (salt, pepper, garlic)`,`Cooking spray`,`--- KID PROTEIN ---`,`1.5 pork breakfast patties per kid`,`--- FRIES ---`,`Checkers/Rally's frozen fries`,`--- CHIMICHURRI ---`,{text:`No-Judge Chimichurri sauce`,link:`/cookbook/no-judge-chimichurri`},`--- KID SIDES ---`,`Raw carrots`],steps:[{text:`FRIES: Air fry at 400°F, 12-15 min. No oil. Shake halfway.`,images:[`/images/steak-fries/step2-fries.webp`]},{text:`SEAR: Season bavette with SPG. High heat pan + spray. 2-3 min per side.`,images:[`/images/steak-fries/step3-sear.webp`]},{text:`REST: 5 minutes. Don't skip — this is what makes it juicy.`},{text:`CHIMICHURRI: Mix oil + seasoning + vinegar + chili flakes. Let sit 5 min.`},{text:`SLICE: Thin, against the grain. Always.`},{text:`PLATE: Adults get steak + fries + chimichurri. Kids get pork patties + fries + carrots.`,images:[`/images/steak-fries/step5-split-plate.webp`,`/images/steak-fries/step4-kid-plate.webp`]}],brands:[{name:`Spiceology`,item:`Chimichurri Blend`,why:`60-second chimichurri — no chopping herbs. Just add oil + vinegar.`,image:`/images/brands/spiceology-chimichurri.jpg`,url:`https://spiceology.com/products/chimichurri-blend`},{name:`Napa Valley Naturals`,item:`Organic Red Wine Vinegar`,why:`Clean acid that blooms the dried herbs — the vinegar makes it chimichurri, not just herb oil`,image:`/images/brands/napa-valley-vinegar.jpg`,url:`https://www.stonewallkitchen.com/organic-red-wine-vinegar-M311231.html`},{name:`O California`,item:`Organic Extra Virgin Olive Oil`,why:`Good olive oil matters here — it's half the sauce. California organic, clean flavor.`,image:`/images/brands/o-olive-oil.jpg`,url:`https://ooliveoil.com/products/o-california-organic-extra-virgin-olive-oil`},{name:`Checkers/Rally's`,item:`Famous Seasoned Fries`,why:`Best frozen fries for air frying — seasoned, crispy, no oil needed`,image:`/images/brands/checkers-fries.jpg`,url:`https://www.target.com/p/checkers-frozen-crispy-frozen-seasoned-fries-28oz/-/A-26398457`},{name:`Great Value`,item:`Original Pork Sausage Patties`,why:`Kid protein swap — familiar, no resistance. Cook in 5 min while steak rests.`,image:`/images/brands/great-value-pork-patties.jpg`,url:`https://www.walmart.com/ip/Great-Value-Fully-Cooked-Original-Pork-Sausage-Patties-Family-Size-35-6-oz-Frozen/24360492`}],mealPrep:{storage:`Steak is best fresh. Chimichurri keeps 3-4 days in fridge.`,reheat:`Don't reheat steak in microwave — slice cold for steak salad, or quick pan sear.`,lasts:`Chimichurri: 3-4 days. Steak: eat same day.`}},{id:26,status:`live`,carbLevel:`none`,meta:{macros:{protein:40,calories:350,fat:10,carbs:6,netCarbs:5,estimated:!0},allergens:[`dairy`],warnings:[`contains-dairy`,`spicy-adult-version`,`requires-overnight-marinade`],dietTags:[`gluten-free`,`halal`,`low-carb`],proteinTags:[`chicken`],splitAxes:[`spice`],effortTags:[`meal-prep`,`one-hand`],costTier:`budget`,costPerServing:`$3.00`,substitutionNotes:[`use coconut yogurt for dairy-free marinade`,`swap drumsticks for thighs`,`use mild paprika instead of Shan for less heat`]},slug:`tandoori-chicken-drumsticks`,proteinAnchor:`chicken`,mealType:`other`,flavorDirection:`indian-spiced`,splitFriendly:`full`,title:`Tandoori Chicken Drumsticks`,category:`Core Signatures`,pillar:`Protein Meals`,tags:[`chicken`,`drumsticks`,`tandoori`,`indian`,`grill`,`split-cook`,`meal-prep`],time:`30 min + overnight marinade`,servings:4,protein:40,calories:350,image:`/images/tandoori/hero.webp`,role:`The Weekend Grill`,makeThisWhen:`You want tandoori that actually tastes like tandoori — deep spice from Shan masala, yogurt tenderized, and visible char from the grill or broiler. Two marinades: full power for adults, mild Lawry's for kids.`,hook:`Two marinades, one cook. Adults get Shan Tandoori Masala — real deal Pakistani spice blend. Kids get Lawry's seasoned yogurt — mild, familiar, zero resistance. Both go on the grill at the same time. Overnight marinade is non-negotiable.`,description:`~40g protein for ~350 cal. Skinless drumsticks marinated overnight — adults in Shan Tandoori Masala + yogurt + lemon, kids in Lawry's + yogurt. Grill or bake+broil until red-orange with dark char marks. Serve 2-3 drumsticks with cucumber + kala namak and onion salad with Kashmiri chili + lemon.`,whyMostFail:[`Skip the slits — spice sits on the surface, doesn't penetrate`,`Don't marinate long enough — overnight is the minimum for real flavor`,`Broil-only burns the yogurt coating before the inside cooks`],whyThisWorks:[`Deep slits to the bone = spice penetrates fully, not just surface coating`,`Overnight yogurt marinade = tenderized, juicy, falls off the bone`,`Two separate marinades = adults get heat, kids get mild. Same grill time.`,`Bake first, broil to finish = cooked interior + controlled char, not burnt`],executionRules:[`Cut 2-3 deep slits per drumstick TO THE BONE — don't half-ass this.`,`Overnight marinade minimum. 6 hours if you're in a rush.`,`Don't add salt — Shan masala already has it. Extra salt = inedible.`,`If broiling: bake 425°F 15-20 min first, THEN broil 5-7 min per side. Never broil-only.`],troubleshooting:[{problem:`Outside burnt, inside raw`,fix:`You broiled from the start. Bake first at 425°F for 15-20 min, flip halfway, THEN broil to char.`},{problem:`No flavor / bland`,fix:`Slits weren't deep enough, or you didn't marinate overnight. Both are non-negotiable.`},{problem:`Chicken is dry`,fix:`Overcooked. Internal temp 165°F, pull immediately. The yogurt should keep it moist if you don't overcook.`},{problem:`Too spicy for adults`,fix:`Use 1/2 packet of Shan instead of 2/3. The heat is front-loaded — it mellows with yogurt.`},{problem:`Kids won't eat it`,fix:`That's why they get the Lawry's marinade. If still resistant, serve with a carb (naan, rice) for familiarity.`}],splitCook:{splitRatio:`60% Adult / 40% Kid`,splitPoint:`SPLIT HAPPENS AT MARINATION — not at cooking. Separate the drumsticks before marinating. Both go on the grill/oven at the same time.`,sharedIngredients:[`--- BASE ---`,`8-10 skinless chicken drumsticks`],sharedSteps:[{text:`PREP: Pat drumsticks dry. Cut 2-3 deep slits per piece — to the bone. Split into adult pile (5-6) and kid pile (3-4).`},{text:`MARINATE ADULT: Mix full yogurt container + 2/3 packet Shan Tandoori Masala + lemon juice + optional red color. Massage deep into slits.`},{text:`MARINATE KID: Mix half yogurt container + 1-2 tsp Lawry's + tiny lemon squeeze. Keep it light.`},{text:`REST: Overnight in fridge. Minimum 6 hours.`},{text:`COOK: Grill medium-high 10-15 min per side. OR bake 425°F 15-20 min then broil 5-7 min per side. Aim for visible char marks without burning the yogurt crust.`}],adult:{label:`Adult — Full Tandoori`,protein:40,calories:350,extraIngredients:[`--- ADULT MARINADE ---`,`1 container fat-free Greek yogurt (~150-170g)`,`2/3 packet Shan Tandoori Masala`,`Juice of 1 lemon`,`Pinch red color (optional)`,`--- SIDES ---`,`Cucumber + kala namak (black salt)`,`Onion + Kashmiri chili + lemon`],steps:[{text:`PLATE: 2-3 drumsticks per adult on a white plate. Finish with onion salad (Kashmiri chili + lemon) and sliced cucumber sprinkled with kala namak.`}]},kid:{label:`Kid — Mild Drumsticks`,protein:25,calories:250,extraIngredients:[`--- KID MARINADE ---`,`1/2 container fat-free Greek yogurt (~75-85g)`,`1-2 tsp Lawry's seasoning`,`Optional: small lemon squeeze`,`--- KID SIDES ---`,`Cucumber slices`,`Optional: naan or rice`],variants:[{name:`Simple`,description:`Mild drumstick + cucumber + optional carb`,steps:[{text:`PLATE: 1 drumstick per kid. Cucumber on side. Add naan or rice if they need a carb.`}]}]}},ingredients:[`--- BASE ---`,`8-10 skinless chicken drumsticks`,`--- ADULT MARINADE ---`,`1 container fat-free Greek yogurt (~150-170g)`,`2/3 packet Shan Tandoori Masala`,`Juice of 1 lemon`,`Pinch red color (optional)`,`--- KID MARINADE ---`,`1/2 container fat-free Greek yogurt`,`1-2 tsp Lawry's seasoning`,`--- SIDES ---`,`Cucumber`,`Kala namak (black salt)`,`Onion`,`Kashmiri chili`,`Lemon`],steps:[{text:`PREP: Pat dry. Cut 2-3 deep slits per drumstick to the bone. Split into adult + kid piles.`,images:[`/images/tandoori/step1-prep.webp`]},{text:`MARINATE ADULT: Yogurt + 2/3 Shan packet + lemon. Massage into slits.`},{text:`MARINATE KID: Half yogurt + 1-2 tsp Lawry's. Keep it mild.`},{text:`REST: Overnight in fridge. Minimum 6 hours.`},{text:`COOK: Grill 10-15 min per side. Or bake 425°F 15-20 min, then broil 5-7 min per side.`},{text:`PLATE: Adults get 2-3 drumsticks + onion salad + cucumber. Kids get 1 drumstick + cucumber.`,images:[`/images/tandoori/step2-split-plate.webp`]}],brands:[{name:`Shan`,item:`Tandoori Masala`,why:`Real Pakistani spice blend — not the watered-down grocery store version. This is what makes it taste like tandoori.`,image:`/images/brands/shan-tandoori.png`,url:`https://www.shanfoods.com/product/recipe-mixes/bbq/tandoori/`},{name:`Lawry's`,item:`Seasoned Salt`,why:`Kid-safe seasoning that works on everything — mild enough, familiar enough, zero resistance`,image:`/images/brands/lawrys-seasoned-salt.jpg`,url:`https://www.mccormick.com/products/lawrys-seasoned-salt-8-oz`},{name:`Fage`,item:`Total 0% Greek Yogurt`,why:`Thick, high protein, tenderizes the chicken — the marinade base`,image:`/images/brands/fage-yogurt.jpg`}],mealPrep:{storage:`Marinated drumsticks keep 2 days in fridge before cooking. Cooked drumsticks reheat well.`,reheat:`Air fryer 375°F for 5 min to re-crisp. Or microwave if you don't care about the char.`,lasts:`Cooked: 3-4 days in fridge. Marinated raw: 2 days.`}},{id:27,status:`live`,carbLevel:`low`,meta:{macros:{protein:40,calories:450,fat:16,carbs:28,netCarbs:14,estimated:!0},allergens:[`dairy`,`gluten`],warnings:[`contains-dairy`,`contains-gluten`],dietTags:[`halal`,`keto-option`],proteinTags:[`chicken`],splitAxes:[`carb`,`texture`],effortTags:[`fast`,`one-pan`,`one-hand`],costTier:`budget`,costPerServing:`$4.25`,substitutionNotes:[`use GF tortillas for gluten-free`,`swap chicken for steak or ground beef`,`use regular cheese if not tracking macros`]},slug:`chipotle-chicken-quesadillas`,proteinAnchor:`chicken`,mealType:`other`,flavorDirection:`smoky-southwest`,splitFriendly:`full`,title:`Chipotle Chicken Quesadillas`,category:`Core Signatures`,pillar:`Protein Meals`,tags:[`chicken`,`quesadilla`,`tacos`,`chipotle`,`split-cook`,`fast`,`kid-friendly`],time:`20 min`,servings:4,protein:40,calories:450,image:`/images/quesadillas/hero.webp`,role:`The Crowd Pleaser`,makeThisWhen:`You want crispy quesadillas for adults and soft melty street tacos for kids — from the same chicken. Two sauces make it two different meals without cooking twice.`,hook:`Same chicken base, two builds. Adults get crispy carb-balance quesadillas with fajita veg and chipotle sauce. Kids get soft street taco tortillas with melted cheese and Primal Kitchen Special Sauce. Same cook window, zero complaints.`,description:`~40g protein for ~450 cal. Pre-cooked chicken with taco seasoning + bone broth. Adults: crispy quesadilla + fajitas + chipotle sauce. Kids: soft street tacos + melty cheese + mild sauce. 20 min.`,whyMostFail:[`Filling is watery — didn't reduce the broth properly`,`Burnt outside, cold cheese inside — heat was too high`,`Kids reject it because it's too spicy or too crunchy`],whyThisWorks:[`Bone broth keeps lean chicken juicy without adding fat`,`Carb-balance tortillas for adults = lower carb but still crispy`,`Street taco tortillas for kids = soft, small, easy to handle`,`Sauce split = adults get chipotle heat, kids get mild sweet sauce`,`Fat-free cheese + low-slow heat = melts properly if you rinse it first`],executionRules:[`Simmer broth until just reduced — filling should be coated, not swimming.`,`Medium heat for adult quesadillas. 4-5 min per side. Don't rush or cheese won't melt.`,`Medium-low for kid tacos. 2-3 min per side. Soft, not crispy.`,`Rinse fat-free cheese lightly before using — removes anti-caking powder and improves melt.`],troubleshooting:[{problem:`Filling is watery / soggy`,fix:`Didn't reduce the broth. Simmer until the liquid is mostly absorbed — filling should be coated, not wet.`},{problem:`Burnt tortilla, cold cheese`,fix:`Heat too high. Medium for adults, medium-low for kids. Low + slow = melty inside, golden outside.`},{problem:`Cheese won't melt`,fix:`Fat-free cheese needs help. Rinse it lightly, use low heat, and cover briefly with a lid.`},{problem:`Kids reject it`,fix:`Skip fajitas for kids. Use regular cheddar (not fat-free). Serve with Primal Kitchen sauce, not chipotle.`}],splitCook:{splitRatio:`50% Adult / 50% Kid`,splitPoint:`STOP. Chicken filling is done. Split into adult build (quesadilla + fajitas) and kid build (street tacos, no fajitas).`,sharedIngredients:[`--- PROTEIN ---`,`10 oz cooked chicken (pre-cooked only)`,`1-1.5 tbsp taco seasoning`,`1/4 cup chicken bone broth`,`Cooking spray (avocado oil)`],sharedSteps:[{text:`FAJITAS (adults only): Spray pan, cook sliced onion + peppers 2-3 min. Add taco seasoning + bone broth. Simmer until reduced.`},{text:`CHICKEN: Add pre-cooked chicken to fajita pan. Toss 1-2 min until coated and juicy.`}],adult:{label:`Adult — Crispy Quesadilla + Chipotle`,protein:40,calories:450,extraIngredients:[`--- ADULT BUILD ---`,`4 carb-balance tortillas (2 per person)`,`3 oz fat-free cheddar (rinsed)`,`3 oz fajita veg (onion + peppers)`,{text:`Smoky Chipotle Crema`,link:`/cookbook/smoky-chipotle-crema`}],steps:[{text:`BUILD: Tortilla → cheese → chicken + fajitas → cheese → tortilla. Medium heat, 4-5 min per side. Light press.`},{text:`SERVE: Slice, serve with chipotle sauce on the side.`}]},kid:{label:`Kid — Soft Street Tacos + Mild Sauce`,protein:20,calories:300,extraIngredients:[`--- KID BUILD ---`,`6 street taco tortillas (3 per kid)`,`2-3 oz regular cheddar`,`Primal Kitchen Special Sauce`],variants:[{name:`Soft Tacos`,description:`Soft tortilla, melted cheese, chicken, mild sauce`,steps:[{text:`BUILD: Tortilla → cheese → chicken (no fajitas) → fold. Medium-low heat, 2-3 min per side.`},{text:`SERVE: Soft tacos with Primal Kitchen sauce on side.`}]}]}},ingredients:[`--- PROTEIN ---`,`10 oz cooked chicken (pre-cooked)`,`1-1.5 tbsp taco seasoning`,`1/4 cup chicken bone broth`,`--- ADULT BUILD ---`,`4 carb-balance tortillas`,`3 oz fat-free cheddar`,`Onion + bell peppers (3 oz)`,{text:`Smoky Chipotle Crema`,link:`/cookbook/smoky-chipotle-crema`},`--- KID BUILD ---`,`6 street taco tortillas`,`2-3 oz regular cheddar`,`Primal Kitchen Special Sauce`],steps:[{text:`FAJITAS: Spray pan, cook onion + peppers 2-3 min. Add seasoning + broth. Reduce.`,images:[`/images/quesadillas/step0-ingredients.webp`]},{text:`CHICKEN: Add cooked chicken, toss 1-2 min until coated.`,images:[`/images/quesadillas/step1-chicken-fajitas.webp`]},{text:`ADULT BUILD: Tortilla → cheese → chicken + fajitas → cheese → tortilla. Medium heat, 4-5 min per side.`,images:[`/images/quesadillas/step2-cooking.webp`]},{text:`KID BUILD: Street tortilla → cheese → chicken → fold. Medium-low, 2-3 min per side.`},{text:`SERVE: Adults get sliced quesadilla + chipotle sauce. Kids get soft tacos + Primal Kitchen sauce.`,images:[`/images/quesadillas/hero.webp`]}],brands:[{name:`Mission`,item:`Carb Balance Flour Tortillas`,why:`4g net carbs, keto-friendly, still gets crispy — the adult tortilla`,image:`/images/brands/mission-zero-carbs.png`,url:`https://www.missionfoods.com/products/carb-balance-soft-taco-flour-tortillas/`},{name:`Mission`,item:`Street Tacos Flour Tortillas`,why:`Small, soft, kid-sized — perfect for little hands`,image:`/images/brands/mission-street-tacos.png`,url:`https://www.missionfoods.com/products/street-tacos-flour-tortillas/`},{name:`Kraft`,item:`Fat Free Cheddar Shredded`,why:`Melts with low heat + lid. Rinse lightly to remove anti-caking powder.`,image:`/images/brands/kraft-ff-cheddar.jpg`,url:`https://kraftnaturalcheese.com/product/shredded-cheese/cheddar-fat-free/`},{name:`Spiceology`,item:`Taco Seasoning`,why:`Clean taco seasoning — the 'Ta' jar from the periodic table line`,image:`/images/brands/spiceology-taco.jpg`,url:`https://spiceology.com/products/taco-seasoning`},{name:`Kirkland`,item:`Organic Chicken Bone Broth`,why:`Keeps lean chicken juicy without adding fat — simmer until reduced`,image:`/images/brands/roli-roti-broth.jpg`},{name:`Chosen Foods`,item:`Avocado Oil Spray`,why:`High smoke point, clean spray for the pan — no dripping`,image:`/images/brands/chosen-foods-spray.png`,url:`https://chosenfoods.com/products/avocado-oil-spray-2`},{name:`Primal Kitchen`,item:`Special Sauce`,why:`Mild, slightly sweet — the kid sauce that gets zero pushback`,image:`/images/brands/primal-kitchen-special.png`,url:`https://www.primalkitchen.com/products/special-sauce-dipping-sauce`}],mealPrep:{storage:`Assembled quesadillas keep 2-3 days in fridge. Reheat in air fryer.`,reheat:`Air fryer 350°F 3-4 min to re-crisp. Don't microwave — kills the crunch.`,lasts:`Filling: 3-4 days. Assembled: 2-3 days.`}},{id:28,status:`live`,carbLevel:`none`,meta:{macros:{protein:35,calories:400,fat:14,carbs:20,netCarbs:18,estimated:!0},allergens:[`soy`,`gluten`],warnings:[`contains-soy`,`contains-gluten`,`spicy-adult-version`],dietTags:[`dairy-free`,`halal`],proteinTags:[`chicken`],splitAxes:[`protein`],effortTags:[`air-fryer`],costTier:`budget`,costPerServing:`$4.50`,substitutionNotes:[`use tamari for gluten-free soy sauce`,`use GF breaded chicken for fully gluten-free`,`serve with rice or noodles for a full meal`]},slug:`indo-chinese-chili-chicken`,proteinAnchor:`chicken`,mealType:`other`,flavorDirection:`indo-chinese`,splitFriendly:`full`,title:`Indo-Chinese Chili Chicken`,category:`Core Signatures`,pillar:`Protein Meals`,tags:[`chicken`,`indo-chinese`,`chili`,`wok`,`air-fryer`,`split-cook`,`glossy`],time:`25 min`,servings:4,protein:35,calories:400,image:`/images/chili-chicken/hero.webp`,role:`The Restaurant Flex`,makeThisWhen:`You want Indo-Chinese takeout flavor at home — glossy, spicy, crispy chili chicken with charred veg. Kids get plain air-fried chunks + buns. Same Kirkland chicken, two outcomes.`,hook:`This is a glaze system, not a curry. Air fry the chicken crispy, char the veg on high heat, reduce the sauce BEFORE adding chicken, then toss for 60 seconds. That's it. The sauce is 6 ingredients mixed in a glass. Kids eat the same chicken straight from the air fryer — plain, with buns and raw peppers.`,description:`~35g protein for ~400 cal. Kirkland chicken chunks air fried crispy, tossed in a 6-ingredient Indo-Chinese chili sauce with charred peppers + onions. Jet Tila's Umami Punch for depth. Kids get plain air-fried chunks + buns.`,whyMostFail:[`Add sauce too early — chicken gets soggy and breading falls apart`,`Cook on low heat — sauce pools instead of glazing`,`Simmer after coating — turns into a curry, not a glaze`],whyThisWorks:[`Air fry chicken first = crispy base that holds up to sauce`,`Sauce reduces BEFORE chicken goes in = tight glaze, not soup`,`Chicken tossed for 60 seconds ONLY = coated but still crispy`,`Kill heat immediately = prevents sogginess`,`1 tbsp Jet Tila Umami Punch on chicken = depth without complexity`],executionRules:[`Sauce goes in the wok BEFORE the chicken. Let it boil 60-90 sec until glossy.`,`Chicken goes in LAST — toss 45-75 seconds only. No longer.`,`Kill heat immediately after coating. Do NOT simmer.`,`High heat the entire time. Low heat = failure.`],troubleshooting:[{problem:`Chicken is soggy / breading fell off`,fix:`You added chicken before the sauce reduced, or simmered after coating. Sauce reduces first, chicken in last, 60 sec max.`},{problem:`Sauce is watery / pooling`,fix:`Didn't reduce long enough. Boil hard for 60-90 sec before adding chicken. Optional: cornstarch slurry for extra thickness.`},{problem:`Not spicy enough`,fix:`Add 1-2 extra tbsp chili crisp or extra Ching's. The heat is front-loaded in the sauce.`},{problem:`Too sweet / too vinegary`,fix:`Too much rice vinegar. Cut by 1 tbsp and add more soy to balance.`},{problem:`Kids won't eat it`,fix:`They're not supposed to. Kids get plain air-fried chunks — no sauce. Serve with buns and raw pepper slices.`}],splitCook:{splitRatio:`60% Adult / 40% Kid`,splitPoint:`SPLIT HAPPENS AFTER AIR FRYING. Reserve kid portions of plain chicken before any sauce touches it.`,sharedIngredients:[`--- CHICKEN ---`,`32 oz Kirkland Lightly Breaded Chicken Breast Chunks`,`1 tbsp Jet Tila's Umami Punch (Spiceology) — sprinkle on chicken after air frying`,`Avocado oil spray`],sharedSteps:[{text:`AIR FRY: 400°F for 10-12 min. Shake halfway. Goal: crispy, golden.`,images:[`/images/chili-chicken/step1-airfry.webp`]},{text:`RESERVE KID CHICKEN: Set aside plain chunks for kids BEFORE any sauce.`,images:[`/images/chili-chicken/step0-ingredients.webp`]}],adult:{label:`Adult — Glossy Chili Chicken`,protein:35,calories:400,extraIngredients:[`--- VEG ---`,`16 oz bell peppers + onions (large chunks)`,`--- SAUCE (mix all in a glass) ---`,`1 tbsp Kikkoman Thai Style Chili Sauce`,`2 tbsp Ching's Red Chili Sauce`,`2 tbsp Nakano Rice Vinegar`,`2 tbsp Kikkoman Soy Sauce`,`1 tbsp Sesame Chili Oil`,`1 tbsp Dynasty Chili Crisp`,`--- OPTIONAL ---`,`1/2 tsp cornstarch + 1 tbsp water (slurry)`],steps:[{text:`COOK VEG: High heat wok, spray oil. Cook peppers + onions 3-5 min until charred.`,images:[`/images/chili-chicken/step2-veg-start.webp`,`/images/chili-chicken/step2-veg-char.webp`]},{text:`ADD SAUCE: Pour ALL sauce in at once. Boil hard 60-90 sec until glossy. Optional: add cornstarch slurry for extra thickness.`},{text:`ADD CHICKEN: Toss air-fried chicken in. Coat aggressively. 45-75 seconds ONLY.`,images:[`/images/chili-chicken/step3-sauce-glaze.webp`]},{text:`KILL HEAT: Immediately. Do not simmer. Serve hot.`,images:[`/images/chili-chicken/step4-finished.webp`]}]},kid:{label:`Kid — Plain Air-Fried Chunks + Buns`,protein:20,calories:250,extraIngredients:[`--- KID ---`,`Plain air-fried chicken chunks (reserved before sauce)`,`Toasted buns`,`Raw mini pepper slices`],variants:[{name:`Simple`,description:`Plain chunks + buns + peppers`,steps:[{text:`PLATE: Plain chicken chunks, toasted buns, raw pepper slices. No sauce.`}]}]}},ingredients:[`--- CHICKEN ---`,`32 oz Kirkland Lightly Breaded Chicken Breast Chunks`,`1 tbsp Jet Tila's Umami Punch (Spiceology)`,`--- VEG ---`,`16 oz bell peppers + onions (large chunks)`,`Avocado oil spray`,`--- SAUCE ---`,{text:`Indo-Chinese Chili Sauce (6-ingredient mix)`,link:`/cookbook/indo-chinese-chili-sauce`},`--- OPTIONAL ---`,`1/2 tsp cornstarch + 1 tbsp water (slurry)`,`--- KID ---`,`Toasted buns`,`Raw mini pepper slices`],steps:[{text:`AIR FRY: Chicken at 400°F, 10-12 min. Shake halfway.`,images:[`/images/chili-chicken/step1-airfry.webp`]},{text:`RESERVE: Set aside plain chunks for kids before sauce.`,images:[`/images/chili-chicken/step0-ingredients.webp`]},{text:`VEG: High heat wok, cook peppers + onions 3-5 min until charred.`,images:[`/images/chili-chicken/step2-veg-start.webp`,`/images/chili-chicken/step2-veg-char.webp`]},{text:`SAUCE: Pour ALL sauce at once. Boil hard 60-90 sec. Optional cornstarch slurry.`,images:[`/images/chili-chicken/step0-sauce.webp`]},{text:`TOSS: Add chicken, coat aggressively, 45-75 sec ONLY.`,images:[`/images/chili-chicken/step3-sauce-glaze.webp`]},{text:`KILL HEAT: Immediately. Serve hot. Kids get plain chunks + buns.`,images:[`/images/chili-chicken/step4-finished.webp`]}],brands:[{name:`Kirkland`,item:`Lightly Breaded Chicken Chunks`,why:`Air fries crispy, holds up to sauce tossing — the base`,image:`/images/brands/kirkland-chicken-chunks.jpg`,url:`https://www.costco.com/p/-/kirkland-signature-lightly-breaded-chicken-breast-chunks-4-lbs/4000202951`},{name:`Kikkoman`,item:`Thai Style Chili Sauce`,why:`Sweet heat base — the backbone of the sauce`},{name:`Ching's`,item:`Red Chili Sauce`,why:`Indo-Chinese specific heat — this is what makes it taste authentic, not generic`},{name:`Nakano`,item:`Rice Vinegar Seasoned`,why:`Acid + slight sweetness — balances the heat and adds tang`},{name:`Kikkoman`,item:`Soy Sauce`,why:`Salt + umami depth — all-purpose, no surprises`},{name:`Dynasty`,item:`Chili Crisp`,why:`Texture + slow burn — the crunchy chili bits add layers to the glaze`},{name:`Spiceology`,item:`Jet Tila's Umami Punch`,why:`1 tbsp sprinkled on chicken = umami depth without adding liquid`,image:`/images/brands/spiceology-taco.jpg`}],mealPrep:{storage:`Best fresh — the glaze is the whole point. Leftovers lose crispiness.`,reheat:`Air fryer 375°F 3-4 min. Don't microwave — kills the texture.`,lasts:`1-2 days max. Not a meal prep recipe — it's a same-night winner.`}},{id:29,status:`live`,carbLevel:`high`,meta:{macros:{protein:61,calories:430,fat:12,carbs:38,netCarbs:35,estimated:!0},allergens:[`soy`,`gluten`],warnings:[`contains-soy`,`contains-gluten`,`spicy-adult-version`],dietTags:[`dairy-free`,`halal`],proteinTags:[`chicken`],splitAxes:[`spice`],effortTags:[`fast`,`survival-mode`],costTier:`budget`,costPerServing:`$3.50`,substitutionNotes:[`swap Buldak for any high-protein ramen`,`use GF ramen noodles for gluten-free`,`swap sausage for sliced chicken breast`]},slug:`split-plate-buldak-ramen`,proteinAnchor:`chicken`,mealType:`other`,flavorDirection:`korean-spicy`,splitFriendly:`full`,title:`Split Plate Buldak Ramen`,category:`Core Signatures`,pillar:`Protein Meals`,tags:[`ramen`,`buldak`,`korean`,`spicy`,`split-cook`,`fast`,`high-protein`,`noodles`],time:`15 min`,servings:4,protein:61,calories:430,image:`/images/buldak-ramen/hero.webp`,role:`The 61g Protein Ramen`,makeThisWhen:`You want ramen night but need serious protein. Adults get spicy Buldak cooked in bone broth (not water) — semi-dry, coated, not soupy. Kids get Maruchan. Both get Bilinski's sausage. 15 minutes.`,hook:`61g protein for 430 cal. That's not a typo. Buldak High Protein Ramen cooked in bone broth instead of water, reduced until coated (not soupy), topped with air-fried Bilinski's cajun sausage. Kids get Maruchan + sausage — mild, familiar, zero resistance. Same kitchen, same 15 minutes.`,description:`61g protein for 430 cal. Buldak High Protein Ramen cooked in Kirkland bone broth (not water), reduced to a glossy coat. Bilinski's cajun chicken sausage air fried. Kids get Maruchan chicken ramen + sausage.`,whyMostFail:[`Cook ramen in water — zero extra protein, bland base`,`Leave it soupy — Buldak is designed to be semi-dry and coated`,`Overcook noodles — they turn mushy and can't hold the glaze`],whyThisWorks:[`Bone broth instead of water = 12g extra protein + umami depth for free`,`Reduce until coated = semi-dry, glossy noodles, not soup`,`Buldak High Protein = 30g protein from the ramen alone`,`Bilinski's sausage air fried = crispy edges, 19g protein per 1.5 links`,`Kids get Maruchan — zero effort, zero complaints`],executionRules:[`Adults: 1 cup bone broth, NOT water. This is where the extra protein comes from.`,`Cook noodles to ~90% done — some liquid should remain.`,`Reduce on medium-high, toss constantly 60-90 sec. Stop when coated, not wet.`,`Kill heat immediately. Don't simmer after coating.`,`Kids: just cook Maruchan normally with water + seasoning packet. Don't overthink it.`],troubleshooting:[{problem:`Adult noodles are soupy`,fix:`Didn't reduce long enough. Medium-high heat, toss constantly 60-90 sec. The broth should disappear.`},{problem:`Noodles are mushy`,fix:`Overcooked. Cook to 90%, then the reduction finishes them. Don't boil until soft.`},{problem:`Not spicy enough`,fix:`Add 1 tsp chili crisp or 1/2 tsp chili oil. The Buldak packet is already hot — boost carefully.`},{problem:`Sausage is dry`,fix:`400°F, 5 min only. Don't overcook — just crisp the edges.`}],splitCook:{splitRatio:`50% Adult / 50% Kid`,splitPoint:`These are two separate builds from the start. Adults get Buldak + broth. Kids get Maruchan + water. Sausage is shared.`,sharedIngredients:[`--- SAUSAGE (shared) ---`,`Bilinski's Organic Cajun Chicken Sausage (~1/2 sausage per person, sliced into coins)`],sharedSteps:[{text:`SAUSAGE: Slice into coins. Air fry 400°F for 5 min. Slightly crisp edges.`}],adult:{label:`Adult — Spicy Buldak in Bone Broth`,protein:61,calories:430,extraIngredients:[`--- ADULT (per person) ---`,`1 pack Buldak High Protein Ramen`,`1 cup Kirkland Chicken Bone Broth (NOT water)`,`Buldak sauce packet`,`--- OPTIONAL BOOST ---`,`1 tsp soy sauce`,`1/2-1 tsp chili crisp`,`1/2 tsp chili oil`],steps:[{text:`BOIL: 1 cup bone broth in pan. Add Buldak noodles. Cook until ~90% done — some liquid remains.`},{text:`SAUCE: Add Buldak packet + optional boosts. Mix well.`},{text:`REDUCE: Medium-high heat, toss constantly 60-90 sec. Stop when coated, not wet.`,images:[`/images/buldak-ramen/step1-cooking.webp`]},{text:`FINISH: Add sausage, toss 20-30 sec. Kill heat. Serve immediately.`}]},kid:{label:`Kid — Maruchan + Sausage`,protein:15,calories:300,extraIngredients:[`--- KID (per kid) ---`,`1 pack Maruchan Chicken Ramen`,`1.5-2 cups water`,`Seasoning packet`],variants:[{name:`Simple`,description:`Standard Maruchan + sausage on top`,steps:[{text:`COOK: Boil water, add noodles + seasoning. Cook until just tender. Don't overcook.`},{text:`PLATE: Bowl of ramen, sausage coins on top. Done.`}]}]}},ingredients:[`--- SAUSAGE ---`,`Bilinski's Organic Cajun Chicken Sausage`,`--- ADULT ---`,`Buldak High Protein Ramen (per person)`,`1 cup Kirkland Chicken Bone Broth (per person)`,`--- KID ---`,`Maruchan Chicken Ramen (per kid)`,`--- OPTIONAL ---`,`Soy sauce`,`Chili crisp`,`Chili oil`],steps:[{text:`SAUSAGE: Slice, air fry 400°F, 5 min.`,images:[`/images/buldak-ramen/step0-ingredients.webp`]},{text:`KIDS FIRST: Cook Maruchan in water + seasoning. Plate with sausage. Remove.`},{text:`ADULT: Boil 1 cup bone broth. Add Buldak noodles. Cook to 90%.`},{text:`SAUCE + REDUCE: Add Buldak packet. Medium-high, toss 60-90 sec until coated.`,images:[`/images/buldak-ramen/step1-cooking.webp`]},{text:`FINISH: Add sausage, toss 20 sec. Kill heat. Serve.`}],brands:[{name:`Buldak`,item:`High Protein Ramen`,why:`30g protein per pack + real spicy flavor. Cooked in broth = 42g protein before sausage.`,image:`/images/brands/buldak-ramen.jpg`,url:`https://www.amazon.com/Healspot-Protein-Noodles-Plant-Based-Friendly/dp/B0FVFHR4TC`},{name:`Bilinski's`,item:`Organic Cajun Chicken Sausage`,why:`19g protein per 1.5 links. Air fries with crispy edges in 5 min. Clean ingredients.`,image:`/images/brands/bilinskis-sausage.webp`,url:`https://www.bilinski.com/organicchickensausages/cajun-styleandouille`},{name:`Kirkland`,item:`Organic Chicken Bone Broth`,why:`12g protein per cup. Replaces water — free protein + umami depth.`,image:`/images/brands/kirkland-bone-broth.jpg`,url:`https://www.costcobusinessdelivery.com/kirkland-signature-organic-chicken-bone-broth-32-fl-oz,-6-ct.product.100403862.html`},{name:`Maruchan`,item:`Chicken Ramen`,why:`Kid ramen. Familiar, fast, zero resistance. Don't overthink this one.`,image:`/images/brands/maruchan-chicken.jpg`,url:`https://maruchan.com/products/ramen/chicken-flavor`}],mealPrep:{storage:`Best fresh. Ramen doesn't store well.`,reheat:`Don't. Make fresh — it's 15 minutes.`,lasts:`Eat same night.`}},{id:30,status:`live`,carbLevel:`high`,meta:{macros:{protein:31,calories:391,fat:12,carbs:40,netCarbs:38,estimated:!1},allergens:[`dairy`,`gluten`,`eggs`],warnings:[`contains-dairy`,`contains-gluten`,`contains-eggs`],dietTags:[`halal`],proteinTags:[`beef`,`steak`],splitAxes:[`spice`],effortTags:[`meal-prep`],costTier:`moderate`,costPerServing:`$5.50`,substitutionNotes:[`use GF noodles for gluten-free`,`swap steak for chicken or mushrooms`,`use lactose-free cottage cheese + milk for lactose-sensitive`]},slug:`creamy-steak-noodles`,proteinAnchor:`beef`,mealType:`pasta`,flavorDirection:`creamy-comfort`,splitFriendly:`full`,title:`Creamy Steak Noodles (No Cream)`,category:`Core Signatures`,pillar:`Protein Meals`,tags:[`steak`,`noodles`,`pasta`,`creamy`,`cottage-cheese`,`split-cook`,`comfort`,`high-protein`],time:`30 min`,servings:8,protein:31,calories:391,image:`/images/creamy-steak-noodles/hero.webp`,role:`The Protein Comfort Bowl`,makeThisWhen:`You want creamy steak pasta that feels indulgent but hits 31g protein at 391 cal — with no cream. Blended cottage cheese + Fairlife IS the sauce. Adults get chili flakes + parsley. Kids get it plain.`,hook:`The sauce trick: blend cottage cheese and Fairlife milk together cold, then fold into a butter-flour roux with beef broth. It becomes indistinguishable from cream sauce — but with 17g protein from the sauce alone. Steak seared fast, egg noodles, done. 8 servings, reheats well.`,description:`~31g protein for ~391 cal. Seared steak + egg noodles in a creamy sauce made from blended cottage cheese + Fairlife (no cream). Bettergoods beef bone broth for depth. Adults get chili flakes + parsley, kids get it plain.`,whyMostFail:[`Use heavy cream — kills the protein advantage and doubles calories`,`Curdle the cottage cheese by adding it to high heat`,`Sauce is grainy because they didn't blend the cottage cheese smooth enough`],whyThisWorks:[`Blended cottage cheese + Fairlife = indistinguishable from cream sauce, 17g protein from sauce alone`,`Pull off heat before adding the blend — no curdling risk`,`Roux (butter + flour) gives body — the cottage cheese blend gives creaminess`,`Beef broth instead of more milk = savory depth, not bland`,`Sear steak whole, then dice — better crust, more flavor`],executionRules:[`Blend cottage cheese + Fairlife COLD before cooking. 60 seconds on high, zero lumps.`,`Pull skillet OFF HEAT before stirring in the blend. Never add to boiling sauce.`,`Sear steak 1-2 min per side — then remove and dice. Don't dice before searing.`,`Store noodles and sauce separately for leftovers.`],troubleshooting:[{problem:`Sauce is grainy / lumpy`,fix:`Didn't blend long enough. Full 60 seconds on high. The cottage cheese must be completely smooth.`},{problem:`Sauce curdled / separated`,fix:`Added the blend to hot sauce. Pull OFF heat first, then stir in slowly.`},{problem:`Sauce is too thin`,fix:`Roux wasn't cooked long enough. 90 seconds of stirring until light golden and nutty.`},{problem:`Sauce is too thick`,fix:`Add beef broth 1 tbsp at a time until it reaches coating consistency.`},{problem:`Steak is tough`,fix:`Overcooked. 1-2 min per side, then dice. It finishes cooking in the sauce.`}],splitCook:{splitRatio:`50% Adult / 50% Kid`,splitPoint:`STOP. Noodles + sauce + steak are combined. Plate into bowls — adults get garnish, kids get it plain.`,sharedIngredients:[`--- PROTEIN ---`,`20 oz steak (flat iron or sirloin), seared whole then diced`,`--- NOODLES ---`,`12 oz wide egg noodles (dry)`,`--- SAUCE ---`,`1 cup Daisy Cottage Cheese (2%), blended with milk`,`1 cup Fairlife 2% milk`,`2 cups Bettergoods Beef Bone Broth`,`2 tbsp Kirkland Grass-Fed Butter`,`3 tbsp all-purpose flour`,`1 tsp Smash Kitchen Dijon Mustard`,`1 tsp Lea & Perrins Worcestershire`,`1/2 tsp garlic powder`,`1/2 tsp onion powder`,`1/3 tsp white pepper`,`1 tsp salt (adjust)`],sharedSteps:[{text:`BLEND: Cottage cheese + Fairlife milk, 60 seconds on high until completely smooth. Set aside cold.`,images:[`/images/creamy-steak-noodles/step0-ingredients.webp`]},{text:`NOODLES: Boil egg noodles to al dente. Drain, spray lightly to prevent sticking.`},{text:`SEAR: Season steak with half the salt + white pepper. High heat, 1-2 min per side. Remove, dice.`,images:[`/images/creamy-steak-noodles/step1-sear.webp`]},{text:`ROUX: Same pan, medium heat. Melt butter, whisk in flour. Stir 90 sec until golden and nutty.`},{text:`SAUCE: Slowly whisk in beef broth. Add Dijon, Worcestershire, garlic powder, onion powder, remaining salt + pepper. Simmer 5-6 min.`,images:[`/images/creamy-steak-noodles/step2-sauce.webp`]},{text:`BLEND IN: Pull OFF heat. Slowly stir in the cottage cheese blend. Smooth and creamy.`},{text:`COMBINE: Return steak to sauce on low heat. Add noodles. Toss gently 3-4 min.`,images:[`/images/creamy-steak-noodles/step3-combined.webp`]}],adult:{label:`Adult — Chili Flakes + Parsley`,protein:31,calories:391,extraIngredients:[`--- ADULT FINISH ---`,`Chili flakes`,`Fresh parsley, chopped`,`Black pepper`],steps:[{text:`PLATE: Bowl of noodles + steak. Top with chili flakes, parsley, black pepper.`}]},kid:{label:`Kid — Plain Creamy Noodles`,protein:25,calories:350,extraIngredients:[`--- KID FINISH ---`,`Optional: pat of butter on top`,`Optional: mild shredded cheese`],variants:[{name:`Simple`,description:`Plain creamy noodles + steak, no garnish`,steps:[{text:`PLATE: Same noodles + steak, no chili or parsley. Optional butter or cheese on top for extra comfort.`}]}]}},ingredients:[`--- PROTEIN ---`,`20 oz steak (flat iron or sirloin)`,`--- NOODLES ---`,`12 oz wide egg noodles (dry)`,`--- SAUCE ---`,`1 cup Daisy Cottage Cheese (2%)`,`1 cup Fairlife 2% milk`,`2 cups Bettergoods Beef Bone Broth`,`2 tbsp Kirkland Grass-Fed Butter`,`3 tbsp all-purpose flour`,`1 tsp Dijon mustard`,`1 tsp Worcestershire sauce`,`1/2 tsp garlic powder`,`1/2 tsp onion powder`,`1/3 tsp white pepper`,`1 tsp salt`,`--- GARNISH (adult) ---`,`Chili flakes`,`Fresh parsley`],steps:[{text:`BLEND: Cottage cheese + Fairlife, 60 sec on high. Set aside cold.`,images:[`/images/creamy-steak-noodles/step0-ingredients.webp`]},{text:`NOODLES: Boil to al dente. Drain.`},{text:`SEAR: Season steak. High heat, 1-2 min per side. Remove, dice.`,images:[`/images/creamy-steak-noodles/step1-sear.webp`]},{text:`ROUX: Melt butter, whisk in flour. 90 sec until golden.`},{text:`SAUCE: Whisk in broth + seasonings. Simmer 5-6 min.`,images:[`/images/creamy-steak-noodles/step2-sauce.webp`]},{text:`BLEND IN: Off heat. Stir in cottage cheese blend slowly.`},{text:`COMBINE: Add steak + noodles. Low heat, 3-4 min.`,images:[`/images/creamy-steak-noodles/step3-combined.webp`]},{text:`PLATE: Adults get chili flakes + parsley. Kids get it plain.`}],brands:[{name:`Daisy`,item:`Cottage Cheese 2%`,why:`Blends smooth, high protein — the secret sauce base. Indistinguishable from cream when blended.`,image:`/images/brands/daisy-sour-cream.jpg`},{name:`Fairlife`,item:`2% Reduced Fat Milk`,why:`Higher protein than regular milk. Blends with cottage cheese for a smooth, creamy base.`,image:`/images/brands/fairlife-milk.png`,url:`https://fairlife.com/ultra-filtered-milk/2-percent-reduced-fat-milk/`},{name:`Bettergoods`,item:`Organic Beef Bone Broth`,why:`22g protein per serving. Gives the sauce deep savory flavor — not just creamy, but beefy.`},{name:`Kirkland`,item:`Grass-Fed Butter`,why:`Rich, nutty roux base. Grass-fed = better flavor in the sauce.`,image:`/images/brands/kirkland-butter.jpg`},{name:`Smash Kitchen`,item:`Organic Dijon Mustard`,why:`Sharp tang that cuts through the creaminess — you can't taste it but you'd miss it.`},{name:`Lea & Perrins`,item:`Worcestershire Sauce`,why:`Umami depth. The ingredient nobody notices but everybody needs.`}],mealPrep:{storage:`Store noodles and sauce SEPARATELY. Sauce thickens overnight — add splash of broth when reheating.`,reheat:`Low heat, stir frequently. Add broth 1 tbsp at a time. Never boil.`,lasts:`3-4 days in fridge.`}},{id:31,status:`live`,carbLevel:`low`,meta:{macros:{protein:38,calories:480,fat:30,carbs:10,netCarbs:7,estimated:!0},allergens:[`mustard`],warnings:[`spicy adult version`],dietTags:[`dairy-free`,`gluten-free`,`egg-free`,`low-carb`,`soy-free`,`nut-free`],proteinTags:[`chicken`],splitAxes:[`spice`],effortTags:[`low-effort`,`hands-off`,`weeknight`,`one-pan`,`one-hand`],costTier:`budget`,costPerServing:`$4.50`,substitutionNotes:[`Swap thighs for bone-in drumsticks — same time, same temp`,`Skip the kid wrap to make it fully low-carb`,`Asparagus → broccoli or green beans — same prep, same cook`,`Adult sauce: olive tapenade works too — but Umami Lemon Heat (creamy + bright + slow chili burn) is the one that actually elevates this dinner`]},slug:`danos-bone-in-thighs`,proteinAnchor:`chicken`,mealType:`other`,flavorDirection:`smoky-southwest`,splitFriendly:`full`,title:`Dan-O's Bone-In Chicken Thighs`,category:`Core Signatures`,pillar:`Protein Meals`,tags:[`chicken`,`thighs`,`bone-in`,`oven-baked`,`split-cook`,`low-effort`,`weeknight`,`no-marinade`,`worth-every-penny`],time:`45 min (5 min hands-on)`,servings:4,protein:38,calories:480,image:`/images/danos-thighs/hero-split-tray.webp`,role:`The Easiest Dinner in Our Rotation`,makeThisWhen:`You want a real dinner with zero mental load. No marinade. No thermometer. No flipping. Bone-in thighs are nearly impossible to ruin — and the back of the Dan-O's bottle is the whole recipe.`,hook:`Two trays. Two seasonings. One oven. Adults get Dan-O's Spicy, kids get Dan-O's Original. Same cook, different plates — that's the whole brand in one dinner.`,description:`Bone-in skin-on chicken thighs. Pat dry hard, season aggressively, bake uncovered at 425°F for 35-40 minutes. Adults get Dan-O's Spicy + charred asparagus drizzled with Umami Lemon Heat Sauce. Kids get Dan-O's Original + plain asparagus + a small tortilla wrap on the side. The recipe is on the back of the bottle. The system is what makes it repeatable.`,whyMostFail:[`Cover the pan with foil — steam-softens the skin instead of crisping it`,`Skip patting dry — wet skin will never crisp, no matter how hot the oven gets`,`Under-season because they're nervous — Dan-O's tolerates a heavy hand, coat aggressively`,`Use boneless skinless — no skin to crisp, no fat to baste, dries out in 20 minutes`],whyThisWorks:[`Bone-in + skin-on = forgiving. The skin protects the meat, the fat bastes from the inside.`,`Uncovered, no foil, no flipping = skin actually crisps instead of steaming`,`Aggressive Dan-O's coating survives the fat rendering — most home cooks under-season by half`,`Two trays at once = full split-cook, no mental load. Spicy on the left, Original on the right.`,`425°F for 35-40 min = the sweet spot. Hot enough to crisp skin, slow enough to render fat.`],executionRules:[`PAT DRY hard. Paper towels, both sides, every thigh. Wet skin = rubber skin.`,`Two trays. Don't try to do half-and-half in one pan — the seasonings will cross.`,`Coat aggressively. You should not see chicken skin under the seasoning.`,`Skin-side UP, no flipping. Period.`,`425°F, uncovered, 35-40 min. Don't open the oven before 30.`,`Rest 5 min before plating. Skin sets, juices redistribute.`],troubleshooting:[{problem:`Skin is rubbery / soft`,fix:`You didn't pat dry enough, OR oven temp was too low. 425°F minimum. Wet skin can't crisp.`},{problem:`Tastes bland`,fix:`Under-seasoned. Dan-O's needs a heavy hand — you should barely see chicken under the coating. Add a pinch of salt on top of the seasoning if needed.`},{problem:`Meat is dry`,fix:`Used boneless skinless. Use BONE-IN SKIN-ON. The bone retains heat, the skin protects the meat. Non-negotiable.`},{problem:`Seasoning burnt`,fix:`Oven too hot or thighs too small. 425°F is the cap. If thighs are tiny, pull at 30 min.`},{problem:`Kids won't eat the wrap side`,fix:`Skip it. The thigh is the meal. Wrap is just a comfort carb if they're hungry.`}],splitCook:{splitRatio:`50% Adult Spicy / 50% Kid Original`,splitPoint:`AT THE PAN. Two trays, two seasonings. Adult tray = Dan-O's Spicy. Kid tray = Dan-O's Original. Bake on the same rack, same time, same temp. Zero workflow split.`,sharedIngredients:[`--- PROTEIN ---`,`8 bone-in skin-on chicken thighs (~4-5 oz each)`,`1-2 tbsp avocado or olive oil (just enough to coat)`,`Pinch of salt (Dan-O's is salted, but a small assist helps)`,`--- VEG (shared base) ---`,`1 large bunch asparagus (1-1.5 lbs), trimmed`,`Olive oil + salt + pepper`],sharedSteps:[{text:`PREHEAT: Oven to 425°F. Convection if you have it.`,images:[]},{text:`PAT DRY: Paper towels, every thigh, both sides. Press hard. This is the most important step.`,images:[`/images/danos-thighs/step1-pat-dry.webp`]},{text:`OIL: Drizzle oil, rub it in. Tiny pinch of salt on each thigh.`},{text:`ASPARAGUS PREP: Snap off woody ends. Toss with olive oil, salt, pepper. Single layer on a sheet pan.`,images:[]}],adult:{label:`Adult — Dan-O's Spicy + Umami Lemon Heat Drizzle`,protein:48,calories:590,extraIngredients:[`--- ADULT TRAY ---`,`Dan-O's Spicy Seasoning (heavy coat — both sides)`,`--- ADULT FINISH ---`,{text:`1-2 tbsp Umami Lemon Heat Sauce (drizzle over asparagus)`,link:`/cookbook/umami-lemon-heat`},`Cracked black pepper`],steps:[{text:`SEASON: Coat both sides of the adult thighs HEAVY with Dan-O's Spicy. You should barely see the chicken.`,images:[`/images/danos-thighs/step2-season.webp`]},{text:`BAKE: Skin-side up on the adult tray. 425°F, 35-40 min. Don't flip, don't open the oven before 30.`,images:[`/images/danos-thighs/step3-cooked.webp`]},{text:`ASPARAGUS: Roast the same time, same oven. 12-15 min until tender + slightly charred. Pull when thighs are at 30 min mark.`,images:[]},{text:`MAKE THE SAUCE: 3 minutes — mayo + lemon + soy + Dijon + chili oil. Whisk smooth, rest 5 min. (See Umami Lemon Heat Sauce in Cookbook.)`,images:[]},{text:`PLATE: 2 thighs over charred asparagus, drizzle Umami Lemon Heat over the asparagus. Crack of pepper. Done.`,images:[`/images/danos-thighs/plated-split.webp`]}]},kid:{label:`Kid — Dan-O's Original + Plain Asparagus + Wrap`,protein:28,calories:370,extraIngredients:[`--- KID TRAY ---`,`Dan-O's Original Seasoning (heavy coat — both sides)`,`--- KID FINISH ---`,`1 small flour tortilla per kid (cut in half), warmed`],variants:[{name:`Standard`,description:`1 thigh + plain asparagus + small folded wrap on the side`,steps:[{text:`SEASON: Coat both sides of kid thighs with Dan-O's Original. Same heavy hand — Original isn't spicy, just savory.`},{text:`BAKE: Same rack as adult tray, 425°F, 35-40 min.`},{text:`WRAP: Warm tortilla in microwave 15 sec or on a dry pan. Cut in half, fold.`},{text:`PLATE: 1 thigh + plain asparagus (no tapenade) + folded wrap. Mild, familiar, no resistance.`}]},{name:`Picky / no-veg`,description:`Skip asparagus. Just thigh + wrap.`,steps:[{text:`SAME COOK. Just plate the thigh + the warm folded wrap. No fight over asparagus.`}]}]}},ingredients:[`--- PROTEIN ---`,`8 bone-in skin-on chicken thighs (~4-5 oz each, day=Mon)`,`--- SEASONING ---`,`Dan-O's Spicy Seasoning (adult tray — heavy coat) [adult-only]`,`Dan-O's Original Seasoning (kid tray — heavy coat) [kid-only]`,`1-2 tbsp avocado or olive oil`,`Salt to assist`,`--- VEG ---`,`1 large bunch asparagus (1-1.5 lbs)`,`Olive oil, salt, pepper`,`--- ADULT FINISH ---`,{text:`1-2 tbsp Umami Lemon Heat Sauce (adult drizzle)`,link:`/cookbook/umami-lemon-heat`},`--- KID FINISH ---`,`Small flour tortillas (1 per kid) [kid-only]`],steps:[{text:`PREHEAT 425°F. Pat thighs dry hard with paper towels — both sides. Wet skin will not crisp.`,images:[`/images/danos-thighs/step1-pat-dry.webp`]},{text:`OIL + SALT: Drizzle oil, pinch of salt each thigh.`},{text:`SEASON TWO TRAYS: Adult tray gets Dan-O's Spicy. Kid tray gets Dan-O's Original. Heavy coat both sides.`,images:[`/images/danos-thighs/step2-season.webp`]},{text:`BAKE: Both trays on the same rack, skin-side up. 35-40 min, no flipping, no foil, no opening the oven before 30 min.`,images:[`/images/danos-thighs/step3-cooked.webp`]},{text:`ASPARAGUS: Toss with olive oil, salt, pepper. Roast 12-15 min on a separate sheet pan.`},{text:`REST: 5 min after pulling thighs. Skin sets, juices redistribute.`},{text:`ADULT SAUCE: Whisk together mayo, lemon, soy, Dijon, chili oil. Rest 5 min. Full method in Umami Lemon Heat Sauce (Cookbook).`},{text:`PLATE: Adults — 2 thighs + charred asparagus drizzled with Umami Lemon Heat. Kids — 1 thigh + plain asparagus + folded wrap.`,images:[`/images/danos-thighs/plated-split.webp`]}],brands:[{name:`Dan-O's`,item:`Spicy Seasoning`,why:`Adult tray. Cayenne + garlic + onion + lemon/orange peel + sea salt — adds heat without making it taste like 'hot sauce in powder form'.`,image:`/images/brands/danos-spicy.png`,url:`https://danosseasoning.com/product/spicy-seasoning-medium/`},{name:`Dan-O's`,item:`Original Seasoning`,why:`Kid tray. Same flavor architecture as Spicy, no cayenne. Mild, savory, kids eat it without resistance.`,image:`/images/brands/danos-original.png`,url:`https://danosseasoning.com/product/original-seasoning-medium/`}],mealPrep:{storage:`Cooked thighs in an airtight container, fridge. Pour the rendered pan juices over the chicken before sealing — that's the secret weapon for next-day tacos.`,reheat:`Air fryer 350°F for 4-5 min — re-crisps the skin. Don't microwave (turns skin rubbery).`,lasts:`3-4 days in fridge. Skin loses some crispness but flavor holds.`,chainTo:{slug:`next-day-chicken-tacos`,title:`Next-Day Chicken Tacos`,note:`Same chicken, totally different meal. Chop it fine — skin and rendered fat included — assemble tacos in 10 min.`}}},{id:32,status:`live`,carbLevel:`low`,meta:{macros:{protein:32,calories:360,fat:18,carbs:22,netCarbs:19,estimated:!0},allergens:[],warnings:[`spicy adult version`],dietTags:[`dairy-free`,`egg-free`,`soy-free`,`nut-free`,`gluten-free`],proteinTags:[`chicken`],splitAxes:[`spice`],effortTags:[`fast`,`leftover-friendly`,`no-cook-protein`,`weeknight`,`one-hand`],costTier:`budget`,costPerServing:`$3.50`,substitutionNotes:[`Protein paths: leftover Dan-O's thighs (best — rendered fat + spice mix is the secret weapon) OR store rotisserie chicken + 1 tsp taco seasoning + 1 tsp olive oil (engineered to mimic the rendered fat)`,`Tortillas: corn (called for, more authentic + GF). Flour works but loses the taqueria character.`,`Sauces: Herdez Avocado Hot (adult) + Avocado Cilantro Salsa Verde (kid) is the system. Any creamy avocado salsa works.`,`Add a squeeze of lime to the kid's sauce if they like tang — most don't, hence the split.`]},slug:`next-day-chicken-tacos`,proteinAnchor:`chicken`,mealType:`tacos`,flavorDirection:`smoky-southwest`,splitFriendly:`full`,title:`Split Plate Next-Day Chicken Tacos`,category:`Core Signatures`,pillar:`Protein Meals`,tags:[`tacos`,`chicken`,`leftover`,`rotisserie`,`meal-chain`,`no-cook`,`weeknight`,`kid-friendly`,`split-cook`],time:`10 min`,servings:4,protein:32,calories:360,image:`/images/next-day-tacos/hero-mise-en-place.webp`,role:`The Meal Chain Reinvention`,makeThisWhen:`You have leftover Dan-O's thighs in the fridge — OR you grabbed a rotisserie at Costco. The recipe is the assembly system, not the protein source. 10 minutes, two completely different plates, zero whining.`,hook:`One tray of chicken thighs becomes two completely different family dinners. Bad leftovers feel repetitive. Good chained meals feel intentional — the chicken changes identity, the kid plate stays simple, and the sauce is the star.`,description:`Next-day tacos built on leftover Dan-O's thighs (or store rotisserie). Chop the chicken fine — skin and rendered fat included. Adults get Herdez Avocado Hot Sauce + cilantro-onion salad with lime. Kids get a deconstructed plate with Avocado Cilantro mild sauce as a dip — sauce stays separate so they can commit at their own pace.`,whyMostFail:[`Treat leftovers as 'reheat the same meal' — repetition kills it. The chicken needs to change identity (chop fine, change format, change sauce).`,`Discard the crispy skin — that's the texture that makes it feel intentional, not lazy.`,`Use chicken breast leftovers (dry on day 2). Thigh meat survives reheating because the fat keeps it juicy.`,`Force kids to eat assembled tacos. They want components — sauce as dip, chicken in a pile, tortilla on the side.`,`Skip the cilantro-onion salad. It's free flavor with one cutting board.`],whyThisWorks:[`Chop fine + skin in = the chicken stops being a 'thigh' and becomes 'taco filling'. Identity shift.`,`Rendered fat + spice mix from the original pan = built-in seasoning. No taco packet needed if you saved the juices.`,`Two sauce variants (Herdez Hot for adults, Avocado Cilantro for kids) = same condiment family, different heat. Visual continuity, separate experiences.`,`Sauce-as-dip on the kid plate = they control the commitment. Way more wins than trying to assemble a taco for them.`,`Lime in the adult onion salad only = adults get the tang, kids stay in the comfort zone.`,`Rotisserie shortcut works because the recipe is the assembly system, not the protein source.`],executionRules:[`If using leftover thighs: SAVE THE PAN JUICES when storing. Pour the rendered fat + spice mix over the chopped chicken when reheating — that IS the seasoning.`,`If using rotisserie: warm the chopped chicken with 1 tsp taco seasoning + 1 tsp olive oil. The oil mimics rendered fat. Don't skip the oil.`,`Chop fine — small enough that kids can scoop with a fork. Skin and crispy bits go IN, not in the trash.`,`Make TWO onion-cilantro salads if both adults and kids will eat it: lime in adult bowl, no lime in kid bowl.`,`Kid plate: components separate. Tortilla, chicken, sauce. Let them dip and assemble themselves.`,`Warm corn tortillas dry-pan or on a flame for 15 sec each side. Cold tortillas crack — and corn cracks fast.`],troubleshooting:[{problem:`Leftovers taste dry / boring`,fix:`You discarded the pan juices when storing. Next time, pour the rendered fat over the chicken before sealing the container. For THIS taco: a splash of chicken broth + a fork-mash on the warm chicken revives it.`},{problem:`Tastes nothing like the original Dan-O's thighs`,fix:`You used breast meat or no skin. Use thigh meat with skin chopped in. The flavor is in the fat + skin.`},{problem:`Rotisserie path tastes flat`,fix:`Skipped the olive oil. Plain rotisserie + taco seasoning is dry. Add 1 tsp oil to mimic the rendered fat from the original recipe.`},{problem:`Kids won't eat the assembled taco`,fix:`Stop assembling. Give them components on a divided tray — tortilla flat, chicken in a compartment, sauce in another compartment as a dip. Sauce-as-dip is the kid hack.`},{problem:`Tortillas crack when folding`,fix:`Cold corn tortillas crack. Warm them dry-pan or over a flame for 15 sec each side. Stack and cover with a towel to keep warm.`},{problem:`Onion-cilantro tastes harsh`,fix:`Adults: needs lime + salt + 5 min rest. Kids: skip the lime entirely — kids find raw onion + lime too sharp.`}],splitCook:{splitRatio:`60% Adult / 40% Kid`,splitPoint:`AT THE PLATE. Same chicken, same warm tortillas. Adults assemble tacos with cilantro-onion + lime + Herdez Hot. Kids get a divided tray — tortilla flat, chicken in a compartment, Avocado Cilantro mild as a dip.`,sharedIngredients:[`--- PROTEIN (pick one path) ---`,{text:`Leftover Dan-O's chicken thighs (~3 thighs adult portion + ~2 thighs kid portion = ~5 thighs / ~16-18 oz cooked) WITH the rendered pan juices saved`,link:`/recipes/danos-bone-in-thighs`},`OR store rotisserie chicken (~16-18 oz pulled) + 1 tsp taco seasoning + 1 tsp olive oil (mimics rendered fat)`,`--- TORTILLAS ---`,`8 small corn tortillas (2 per serving — adults stack, kids may only use 1)`],sharedSteps:[{text:`CHOP THE CHICKEN: Fine dice — small enough kids can scoop with a fork. Crispy skin goes IN, not in the trash. The skin bits are what make it feel intentional, not lazy.`,images:[`/images/next-day-tacos/step2-chop.webp`]},{text:`WARM THE CHICKEN: Small pan, medium heat. Add chopped chicken + ALL saved pan juices (rendered fat + spice mix). Stir 2-3 min until heated through. Rotisserie path: add 1 tsp taco seasoning + 1 tsp olive oil instead.`,images:[`/images/next-day-tacos/step3-pan-warm.webp`]},{text:`WARM TORTILLAS: Dry pan or open flame, 15 sec per side. Stack under a clean towel to keep pliable.`,images:[]}],adult:{label:`Adult — Herdez Avocado Hot + Cilantro-Onion-Lime`,protein:38,calories:420,extraIngredients:[`--- ADULT GARNISH ---`,`1/2 cup white onion, finely diced`,`1/4 cup fresh cilantro, chopped`,`1 tbsp lime juice (adult only — kids don't want this)`,`Pinch of salt`,{text:`Herdez Avocado Hot Sauce (drizzle generously)`,link:`https://www.salsas.com/herdez/products/hot-sauce/herdez-avocado-hot-sauce/`}],steps:[{text:`ADULT ONION SALAD: Mix diced onion + cilantro + lime + salt. Rest 5 min — the lime mellows the onion bite.`,images:[]},{text:`ASSEMBLE: Warm tortilla → chopped chicken → spoon of cilantro-onion → generous drizzle of Herdez Avocado Hot. Eat hand-held.`,images:[`/images/next-day-tacos/adult-plate.webp`]}]},kid:{label:`Kid — Deconstructed + Avocado Cilantro Dip`,protein:24,calories:290,extraIngredients:[`--- KID GARNISH (no lime) ---`,`2 tbsp white onion, finely diced (optional — most kids skip)`,`1 tbsp fresh cilantro, chopped (optional)`,{text:`Herdez Taqueria Avocado Cilantro (mild — used as a DIP, not a topping)`,link:`https://www.salsas.com/herdez/products/taqueria-street-sauces/herdez-taqueria-street-sauce-avocado-cilantro/`}],variants:[{name:`Standard — Components Separate (Sauce as Dip)`,description:`Divided tray: warm tortilla flat in one section, chopped chicken in another compartment, Avocado Cilantro mild as a dip in the third. Kids assemble or dip — their call.`,steps:[{text:`PLATE: Tortilla flat in a tray section (DO NOT fold or assemble). Chopped chicken in another compartment. Mild Avocado Cilantro sauce in a third compartment as a DIP. Optional: tiny pinch of cilantro-onion (no lime) on the chicken.`,images:[`/images/next-day-tacos/kid-tray.webp`]},{text:`WHY THIS WORKS: Kids commit at their own pace. They might dip the chicken in sauce. They might fold the tortilla themselves. They might just eat the chicken plain. All are wins. Don't pre-assemble.`}]},{name:`Picky — Plain Chicken + Tortilla`,description:`Skip the sauce. Chicken pile + warm tortilla wedge. Quesadilla path if they only eat melted cheese.`,steps:[{text:`PLATE: Just the chopped chicken + a warm tortilla folded once. Skip sauce, skip onion. Add a sprinkle of mild shredded cheese if they need it.`}]}]}},ingredients:[`--- PROTEIN ---`,{text:`Leftover Dan-O's thighs (~16-18 oz cooked) + saved pan juices [BEST PATH]`,link:`/recipes/danos-bone-in-thighs`},`OR store rotisserie chicken (~16-18 oz pulled) + 1 tsp taco seasoning + 1 tsp olive oil [SHORTCUT PATH]`,`--- TORTILLAS ---`,`8 small corn tortillas`,`--- ADULT GARNISH ---`,`1/2 cup white onion, finely diced [adult]`,`1/4 cup fresh cilantro, chopped [adult]`,`1 tbsp lime juice [adult-only]`,`Pinch of salt [adult]`,`--- KID GARNISH (optional, no lime) ---`,`2 tbsp white onion, finely diced [kid-optional]`,`1 tbsp fresh cilantro, chopped [kid-optional]`,`--- SAUCES ---`,{text:`Herdez Avocado Hot Sauce [adult]`,link:`https://www.salsas.com/herdez/products/hot-sauce/herdez-avocado-hot-sauce/`},{text:`Herdez Taqueria Avocado Cilantro [kid — used as dip]`,link:`https://www.salsas.com/herdez/products/taqueria-street-sauces/herdez-taqueria-street-sauce-avocado-cilantro/`}],steps:[{text:`CHOP CHICKEN: Fine dice. Skin and crispy bits go IN. This is what makes it stop tasting like leftovers.`,images:[`/images/next-day-tacos/step2-chop.webp`]},{text:`WARM CHICKEN: Pan + leftover pan juices (rendered fat + spice mix). Or rotisserie + 1 tsp taco seasoning + 1 tsp olive oil. 2-3 min medium heat.`,images:[`/images/next-day-tacos/step3-pan-warm.webp`]},{text:`WARM TORTILLAS: Dry pan or flame, 15 sec each side. Stack under a towel.`},{text:`ADULT ONION SALAD: 1/2 cup diced white onion + 1/4 cup cilantro + 1 tbsp lime + salt. Rest 5 min.`},{text:`KID ONION SALAD (optional, no lime): 2 tbsp diced onion + 1 tbsp cilantro. Most kids skip — that's fine.`},{text:`ADULT PLATE: Warm tortilla → chopped chicken → cilantro-onion → Herdez Avocado Hot drizzle. Hand-held.`,images:[`/images/next-day-tacos/adult-plate.webp`]},{text:`KID TRAY: Components SEPARATE. Tortilla flat, chicken in a compartment, Avocado Cilantro mild as a DIP. Don't assemble for them.`,images:[`/images/next-day-tacos/kid-tray.webp`]}],brands:[{name:`Herdez`,item:`Avocado Hot Sauce`,why:`Adult sauce. Real avocados + heat — creamy, spicy, not vinegar-forward like most hot sauces. Cuts through the rich chicken without overpowering.`,image:`/images/brands/herdez-avocado-hot-sauce.png`,url:`https://www.salsas.com/herdez/products/hot-sauce/herdez-avocado-hot-sauce/`},{name:`Herdez`,item:`Taqueria Avocado Cilantro Street Sauce`,why:`Kid sauce — used as a dip, not a topping. Avocado + tomatillo + jalapeño = mild creamy salsa verde. Squeeze bottle makes it easy to portion.`,image:`/images/brands/herdez-avocado-cilantro.png`,url:`https://www.salsas.com/herdez/products/taqueria-street-sauces/herdez-taqueria-street-sauce-avocado-cilantro/`}],mealPrep:{storage:`Chopped chicken + pan juices in an airtight container. Sauces in fridge. Onion-cilantro best fresh — make day-of.`,reheat:`Pan, 2-3 min medium heat with the saved juices. Don't microwave (chicken gets rubbery).`,lasts:`Chopped chicken: 2-3 days. Onion-cilantro salad: same day only (cilantro wilts overnight).`}},{id:33,status:`live`,carbLevel:`low`,meta:{macros:{protein:44,calories:540,fat:30,carbs:24,netCarbs:22,estimated:!0},allergens:[`dairy`,`gluten`],warnings:[`contains-dairy`,`contains-gluten`,`spicy-adult-version`],dietTags:[`egg-free`,`soy-free`,`nut-free`,`halal`],proteinTags:[`chicken`],splitAxes:[`spice`],effortTags:[`fast`,`air-fryer`,`freezer-to-plate`,`weeknight`,`comfort`,`one-hand`],costTier:`moderate`,costPerServing:`$5.50`,substitutionNotes:[`Wings: Kinder's Buttery Buffalo (called for — comes pre-sauced) OR any frozen wings + Frank's RedHot tossed at the end`,`Skip the bread for low-carb adult version`,`Carrots → celery sticks if blue cheese on celery is your hill`,`Sauce: Protein Blue Cheese Crema (mandatory cross-link — this is what carries the meal nutritionally)`]},slug:`buffalo-wing-night`,proteinAnchor:`chicken`,mealType:`other`,flavorDirection:`smoky-southwest`,splitFriendly:`full`,title:`Split Plate Buffalo Wing Night`,category:`Core Signatures`,pillar:`Protein Meals`,tags:[`wings`,`buffalo`,`chicken`,`air-fryer`,`freezer-to-plate`,`comfort`,`split-cook`,`high-protein`,`kid-friendly`,`weeknight`],time:`25 min`,servings:4,protein:44,calories:540,image:`/images/buffalo-wing-night/hero-split-plate.webp`,role:`The High-Protein Comfort Night`,makeThisWhen:`Friday night, kids want comfort food, you want something that feels indulgent without being a wreck. Frozen wings + a real protein crema = junk dinner becomes high-protein comfort. 25 min, one air fryer, zero pretending.`,hook:`Frozen wings + protein blue cheese crema = junk dinner becomes high-protein comfort food. The crema does the leverage work — adds protein, satiation, mouthfeel, and turns 'okay frozen wings' into 'restaurant Friday night'.`,description:`Kinder's Buttery Buffalo wings from frozen — air fryer extra crispy, tossed aggressively in their included hot sauce, served with Protein Blue Cheese Crema, baby carrots, and Rudi's Three Cheese Texas Toast for the kid. Adults get sauced wings + chives garnish. Kids get naked (unsauced) wings + crema-as-dip + bread. Same air-fryer batch, two completely different experiences.`,whyMostFail:[`Treat frozen wings as a 'sad easy night' — they're not, they're a leverage opportunity. The crema does the work, not the wings.`,`Toss the wings in sauce while they're still in the air fryer / before resting — sauce absorbs into hot wings and dulls. Rest 1 min, THEN toss aggressively.`,`Forget the green garnish. Buffalo plates are ALL orange — chives or scallions on top change the photo and the bite.`,`Pour the sauce/dip over the kid plate. Sauce-as-dip is the kid principle on this site. Components stay separate.`,`Use water-based 'protein dressing' as the dip. It tastes fake and ruins the meal. Use real blue cheese crema (built on real cottage cheese + real blue cheese crumbles).`],whyThisWorks:[`Frozen wings + air fryer extra crispy + 1 min rest + aggressive toss in HOT sauce = restaurant-level wings without a fryer or 90 minutes`,`Protein Blue Cheese Crema (~66 cal / 4.8g protein per serving) flips the meal math — frozen wings alone are decent protein but low satiety; the crema adds protein, volume, and richness perception`,`Kid plate: naked unsauced wings + crema as a dip + Rudi's Three Cheese Texas Toast = familiar comfort, no spice resistance`,`Adult plate: sauced wings + crema for dipping + carrots for crunch + chives on top for visual contrast`,`Same air-fryer batch (cook all wings together), then split into sauced / unsauced at plating — zero workflow split until the end`],executionRules:[`Air fry from frozen at 400°F for 18-22 min, shake basket halfway. Don't crowd — single layer, space between wings, or they steam instead of crisp.`,`REST 1 minute after pulling. This is non-negotiable. Tossing in sauce immediately = sauce absorbs into hot wings and dulls. Rest then toss.`,`TOSS AGGRESSIVELY: Adult wings into a large bowl, pour ALL the included buffalo sauce, toss with tongs hard until every wing is glossy. If you're being gentle, you're doing it wrong.`,`PULL KID WINGS BEFORE SAUCING: After the rest, pull the kid portion (4-5 wings) into their tray BEFORE tossing the rest in sauce. No sauce on those.`,`GARNISH WITH CHIVES OR SCALLIONS on adult plate — buffalo plates are too orange without green. Cheap fix, big visual upgrade.`,`Sauce stays separate on kid plate. Dip-not-pour is the kid principle.`],troubleshooting:[{problem:`Wings are soggy / not crispy`,fix:`Overcrowded the air fryer basket. Single layer, space between. Shake halfway. If using a Cosori-style multi-rack, swap racks at the halfway mark too.`},{problem:`Sauce coverage is uneven (some glossy, some dry)`,fix:`You didn't rest the wings before tossing, OR you tossed gently. Rest 1 min full stop, then toss with tongs hard in a bowl until every wing is glossy. This is the move.`},{problem:`Wings taste flat after saucing`,fix:`Sauce was added to wings that were too hot — it absorbed. Always rest first.`},{problem:`Kid won't eat the wings even unsauced`,fix:`Kinder's are pre-seasoned (mild spice in the seasoning even before saucing). If kid is super spice-sensitive, use plain frozen wings + butter brush for kids — same crispy texture, zero seasoning.`},{problem:`Plate looks flat in photos / on the table`,fix:`All orange. Add chives or scallions on adult plate, and the white crema dip on the side. Green + white + orange = balanced visual.`},{problem:`Kid won't dip`,fix:`Don't push. The dip is OPTIONAL on the kid plate. They might just eat the wing and bread. That's a win. Sauce-as-dip means optional, not required.`}],splitCook:{splitRatio:`60% Adult / 40% Kid`,splitPoint:`AT THE TONGS. Same wings, same air-fryer batch. After the 1-min rest: pull kid portion (4-5 wings) into their tray FIRST, then toss the rest aggressively in the included Kinder's buffalo sauce.`,sharedIngredients:[`--- WINGS ---`,`1 bag Kinder's Buttery Buffalo Party Wings (19 oz frozen, includes buffalo sauce packet)`,`--- VEG ---`,`1 lb baby carrots (or carrot sticks)`,`--- KID CARB ---`,`1 box Rudi's Three Cheese Texas Toast (4 thick slices — kid gets 1)`,`--- SAUCE (mandatory) ---`,{text:`1 batch Protein Blue Cheese Crema (~8 servings, made ahead — gets better on day 2)`,link:`/cookbook/protein-blue-cheese-crema`}],sharedSteps:[{text:`MAKE THE CREMA AHEAD: 5 min prep + 10 min rest. Cottage cheese + 365 blue cheese + Fairlife + lemon + SPG → blend smooth → fold in chives + chunks. Fridge until serving. (See Protein Blue Cheese Crema in Cookbook.)`,images:[]},{text:`AIR FRY WINGS: From frozen, 400°F for 18-22 min. Single layer, shake basket halfway. Crispy = goal. Soggy = overcrowded.`,images:[]},{text:`TOAST THE BREAD: Last 6-7 min of the wing cook, slide Rudi's Three Cheese Texas Toast into a toaster oven or air fryer at 400°F. Pull when cheese is melted and edges are golden.`,images:[]},{text:`REST: Wings to a clean bowl. 1 minute. DO NOT skip — this is the move that prevents soggy sauced wings.`,images:[]}],adult:{label:`Adult — Sauced Wings + Crema Dip + Chives`,protein:50,calories:620,extraIngredients:[`--- ADULT FINISH ---`,`Included Kinder's buffalo sauce packet (full)`,`2 tbsp fresh chives or scallions, chopped (the visual fix)`,`1 ramekin Protein Blue Cheese Crema (dip)`,`Baby carrots`],steps:[{text:`PULL KID WINGS FIRST: Move 4-5 wings to kid tray BEFORE saucing. No going back once they're sauced.`,images:[]},{text:`TOSS AGGRESSIVELY: Adult wings in a bowl. Pour the included Kinder's buffalo sauce over. Tongs, toss HARD until every wing is glossy. This is not a delicate move.`,images:[]},{text:`PLATE: Sauced wings on a round plate. Square ramekin of Protein Blue Cheese Crema beside. Pile of baby carrots. Chives scattered over the wings — the green is the fix.`,images:[`/images/buffalo-wing-night/hero-split-plate.webp`]}]},kid:{label:`Kid — Naked Wings + Crema Dip + Texas Toast`,protein:38,calories:460,extraIngredients:[`--- KID FINISH ---`,`1 slice Rudi's Three Cheese Texas Toast (toasted)`,`Baby carrots`,`1 small ramekin Protein Blue Cheese Crema (OPTIONAL — as a dip, not a topping)`],variants:[{name:`Standard — Unsauced + Dip-Optional`,description:`Divided tray: 4-5 naked wings in one section, baby carrots + small ramekin of crema as optional dip, slice of Rudi's Three Cheese Texas Toast.`,steps:[{text:`PLATE: Divided tray. Unsauced wings in main section, carrots + crema dip ramekin in the side compartment, toasted Rudi's Three Cheese in the bottom compartment. Don't pre-dip. Don't pre-sauce. Don't pre-fold. They commit at their own pace.`,images:[]}]},{name:`Spice-Sensitive — Plain Frozen Wings`,description:`If Kinder's are too seasoned even unsauced (some kids), swap kid portion for plain frozen wings + butter brush. Same air-fryer time.`,steps:[{text:`Cook 4-5 plain frozen wings in the same air fryer (separate basket or stagger). Brush with butter + tiny pinch of salt. Serve same way as Standard.`}]}]}},ingredients:[`--- WINGS ---`,`1 bag Kinder's Buttery Buffalo Party Wings (19 oz frozen, sauce included)`,`--- VEG ---`,`1 lb baby carrots`,`--- KID CARB ---`,`Rudi's Three Cheese Texas Toast (1 slice per kid)`,`--- SAUCE (mandatory) ---`,{text:`Protein Blue Cheese Crema (1 batch makes 8 servings)`,link:`/cookbook/protein-blue-cheese-crema`},`--- GARNISH ---`,`2 tbsp fresh chives or scallions [adult]`],steps:[{text:`MAKE THE CREMA: 5 min prep + 10 min rest. Best made ahead — day 2 is better than day 1. (See Protein Blue Cheese Crema in Cookbook.)`},{text:`AIR FRY WINGS: From frozen, 400°F, 18-22 min, single layer, shake halfway. Soggy = overcrowded. Crispy = winning.`},{text:`TOAST THE BREAD: Last 6-7 min, slide Rudi's Three Cheese Texas Toast into the toaster oven at 400°F. Pull when cheese is melted.`},{text:`REST: Wings to a clean bowl. 1 minute. NON-NEGOTIABLE — this prevents soggy sauced wings.`},{text:`PULL KID PORTION FIRST: 4-5 wings to the kid tray BEFORE saucing. No sauce.`},{text:`TOSS ADULT WINGS: Pour the included Kinder's buffalo sauce over the remaining wings. Tongs, toss HARD until glossy. Aggressive = correct.`},{text:`PLATE: Adult round plate — sauced wings + carrots + ramekin of crema + chives scattered over. Kid divided tray — naked wings + carrots + crema dip ramekin + toasted Rudi's Three Cheese.`,images:[`/images/buffalo-wing-night/hero-split-plate.webp`]}],brands:[{name:`Kinder's`,item:`Buttery Buffalo Party Wings (19 oz frozen)`,why:`Pre-cooked, pre-seasoned wings with the buffalo sauce packet included. Anaheim chilis + red jalapeño + garlic in the sauce = real buffalo flavor, not gas-station mild. The leverage move: frozen wings that don't taste frozen.`,image:`/images/brands/kinders-buttery-buffalo-wings.png`,url:`https://www.kinders.com/products/buttery-buffalo-party-wings`},{name:`Rudi's Bakery`,item:`Three Cheese with Garlic Texas Toast`,why:`Real cheese, real bread (Rocky Mountain Sourdough), real butter — not soy or palm oil. The kid carb that earns its slot. 4 thick slices per box.`,image:`/images/brands/rudis-three-cheese-texas-toast.png`,url:`https://rudisbakery.com/products/3-cheese-with-garlic-texas-toast/`},{name:`Protein Blue Cheese Crema`,item:`Mandatory cross-link`,why:`The sauce IS the meal's leverage. Without it, frozen wings are 'okay'. With it, the meal is high-protein comfort food. Made ahead (8 servings, 5 days fridge life).`,url:`/cookbook/protein-blue-cheese-crema`}],mealPrep:{storage:`Wings: best fresh out of the air fryer. Leftover sauced wings keep 2 days in fridge. Crema: 5-7 days.`,reheat:`Wings: air fryer 375°F for 3-4 min to re-crisp (microwave = soggy). Crema: serve cold.`,lasts:`Wings 2 days. Crema 5-7 days (gets better).`}},{id:34,status:`live`,carbLevel:`high`,meta:{macros:{protein:32,calories:460,fat:16,carbs:48,netCarbs:44,estimated:!0},allergens:[`gluten`,`dairy`],warnings:[`contains-gluten`,`contains-dairy`,`spicy-adult-version`],dietTags:[`egg-free`,`soy-free`,`nut-free`,`halal`],proteinTags:[`chicken`,`beef`],splitAxes:[`protein`,`spice`],effortTags:[`fast`,`emergency-dinner`,`freezer-to-plate`,`air-fryer`,`no-cook-assembly`,`weeknight`,`one-hand`],costTier:`moderate`,costPerServing:`$5.00`,substitutionNotes:[`TIER 2 protein: Colonel Kababz Chicken Seekh (adult — slight kick) + Colonel Kababz Beef Seekh (kid — less spicy). Same brand, same macros, different heat. Or any frozen seekh kebab brand.`,`TIER 3 carb: Vadilal Rumali Roti (called for — thin, flexible, restaurant style) OR Haldiram's Minute Khana Phulka Roti (thicker, whole wheat) OR any frozen flatbread.`,`TIER 4 freshness: red onion + green chutney + cucumber sticks. Don't skip — this is the difference between freezer-beige and intentional.`,`Green chutney: any store-bought cilantro-mint variety. Homemade works but the point is emergency dinner.`,`Skip the green chutney entirely for spice-sensitive kids — plain rumali + beef kebab + cucumber is enough.`]},slug:`emergency-kebab-night`,proteinAnchor:`chicken`,mealType:`other`,flavorDirection:`indian`,splitFriendly:`full`,title:`Split Plate Emergency Kebab Night`,category:`Core Signatures`,pillar:`Protein Meals`,tags:[`kebab`,`seekh`,`indian`,`frozen`,`emergency-dinner`,`20-min`,`air-fryer`,`no-cook`,`split-cook`,`rumali`,`halal`],time:`20 min`,servings:4,protein:32,calories:460,image:`/images/emergency-kebab-night/hero.webp`,role:`The 6 PM Emergency Dinner`,makeThisWhen:`It's 6 PM, nobody planned, everyone's tired, and the DoorDash math is heading toward $80 for mediocre food. You don't need to cook — you need to ASSEMBLE. Frozen kebab + frozen rumali + a 5-minute onion-cucumber salad = a real Indian family dinner in 20 minutes.`,hook:`Same brand. Two SKUs. Adults get Colonel Kababz Chicken Seekh (slight kick). Kids get Colonel Kababz Beef Seekh (mild, less spicy). Same macros, different heat — the rare frozen split where the brand does the work for you.`,description:`Three frozen products + one fresh element. Air fryer the kebabs for char (5 min finish AFTER the heat-through step), microwave the rumali roti, slice the red onion + cucumber, splash green chutney. Adult plate: chicken kebab wrapped in rumali + onion-chutney salad. Kid divided tray: beef kebab + plain rumali + cucumber sticks. This is the formula — Tier 2 protein + Tier 3 carb + Tier 4 freshness — applied in 20 minutes.`,whyMostFail:[`Treat frozen kebab as 'sad easy dinner' instead of leverage. Assembled comfort food IS the lane — not a compromise.`,`Skip the char step. Microwave-only kebabs are flabby and pale. 5 min in the air fryer at 400°F after heating fixes everything — visible char, real flavor, restaurant feel.`,`Skip the Tier 4 freshness adder. A plate of kebabs + roti is freezer-beige. The onion-cucumber-chutney salad is what makes it feel intentional.`,`Plate the components separated like a cafeteria. Adult plate needs INTERACTION — wrap one kebab inside the rumali. Visible interaction beats components.`,`Use chicken seekh for kids. The chicken is slightly spicy, the beef is mild. Reverse it.`,`Compare to DoorDash and lose: $80 of cold mediocre food vs. $20 of frozen + 20 min of assembly. The emergency dinner IS the win.`],whyThisWorks:[`TIER 2 protein x2: Colonel Kababz Chicken Seekh (adult, slight kick) + Beef Seekh (kid, mild). Same brand, same macros, different heat — split-cook done by SKU selection, not separate cooking.`,`TIER 3 carb: Vadilal Rumali Roti — thin, flexible, restaurant-style. 30 seconds in the microwave. Fold around a kebab on the adult plate for visible interaction.`,`TIER 4 freshness: red onion sliced thin + green chutney + cucumber sticks. The acid + crunch is what kills the freezer-beige problem. 5 minutes of knife work tops.`,`Air fryer char step (5 min @ 400°F after the heat-through) = visible grill marks + real flavor. Skipping this is the #1 way the meal looks sad.`,`Total active time: 20 min. Total cognitive load: near-zero. This is exactly the 'assembled comfort food' lane the brand owns.`,`Cost reality: ~$5/serving. DoorDash equivalent: $20-25/serving with tip + fees. The math is the value prop.`],executionRules:[`AIR FRYER CHAR IS NOT OPTIONAL. Per-box heat instructions get the kebabs warm; the air fryer 5 min @ 400°F finish is what gives them char + texture + flavor. Skipping this is why frozen kebabs taste like frozen kebabs.`,`Two boxes, one basket: Beef Seekh + Chicken Seekh in the same air fryer at the same time. They cook identically. Pull together.`,`Slice red onion THIN — paper-thin half-moons. Salt them, let them sit 5 min while the kebabs cook. The salt mellows the harsh raw bite.`,`Warm rumali ONLY when ready to plate. Microwave 30 sec wrapped in a damp paper towel. Cold rumali cracks; over-warmed rumali dries out.`,`ADULT PLATE INTERACTION: Wrap one kebab inside a folded rumali. Don't just lay components side by side. Visible interaction is the difference between 'plate' and 'meal'.`,`Kid plate stays simple: 1 beef kebab + plain rumali (folded, no wrap) + cucumber sticks. Skip the onion salad and green chutney for kids — most won't touch them.`],troubleshooting:[{problem:`Kebabs look pale / flabby`,fix:`Skipped the air fryer char step. 5 min @ 400°F AFTER the heat-through is non-negotiable. Real char = real flavor + real photo.`},{problem:`Adult kebabs too spicy`,fix:`Use the beef variant for everyone. Same macros, less heat. Or add yogurt to the plate to cut the heat.`},{problem:`Kid won't eat the kebab`,fix:`Use the BEEF variant. Chicken seekh has more spice. Or strip the kebab off the skewer onto plain rumali and let them eat it like a soft taco.`},{problem:`Rumali roti cracks when folding`,fix:`Cold rumali cracks. Microwave 30 sec wrapped in a damp paper towel. Don't over-microwave or it dries out.`},{problem:`Salad too harsh / raw onion bite`,fix:`Slice the onion THIN and salt it 5 min before serving. Salt + time mellows the bite. Skip if your kids hate raw onion entirely — cucumber sticks alone are fine.`},{problem:`Plate looks sad in photos`,fix:`Three fixes: (1) char marks visible on kebabs (air fryer finish). (2) Wrap one kebab in the rumali on the adult plate. (3) Add green chutney drizzle — color contrast is the cheapest visual upgrade.`}],splitCook:{splitRatio:`50% Adult Chicken / 50% Kid Beef`,splitPoint:`AT THE BOX. Adults get Colonel Kababz Chicken Seekh (slight kick). Kids get Colonel Kababz Beef Seekh (mild). Both boxes go in the air fryer together — same time, same temp. Zero workflow split until plating.`,sharedIngredients:[`--- TIER 2 PROTEIN (split by SKU) ---`,`1 box Colonel Kababz Chicken Seekh Kabab (8 large, 11 oz frozen) [adult]`,`1 box Colonel Kababz Beef Seekh Kabab (8 large, 11 oz frozen) [kid]`,`--- TIER 3 CARB ---`,`1 pack Vadilal Quick Treat Rumali Roti (6 pieces, 240g frozen) — OR substitute Haldiram's Minute Khana Phulka Roti`,`--- TIER 4 FRESHNESS ---`,`1 medium red onion, sliced paper-thin`,`1 medium cucumber`,`Store-bought green chutney (cilantro-mint based) — any brand`,`Pinch of salt`],sharedSteps:[{text:`AIR FRY KEBABS: Both boxes (chicken + beef) into the air fryer together, 400°F for 12 min total. Shake basket at 6 min. THE LAST 5 MIN gets you the char that matters — don't pull early.`,images:[`/images/emergency-kebab-night/mise-en-place.webp`]},{text:`SLICE ONION + SALT: Paper-thin half-moons of red onion. Sprinkle a pinch of salt. Let sit 5 min — salt mellows the raw bite. (This is the Tier 4 move that punches above its weight.)`,images:[]},{text:`CUCUMBER STICKS (kid) + CUCUMBER SLICES (adult): Slice cucumber into sticks for the kid tray. Thin half-moons for the adult salad.`,images:[]},{text:`WARM RUMALI: Wrap in damp paper towel. Microwave 30 sec total. Don't over-warm or it dries out.`,images:[]}],adult:{label:`Adult — Chicken Seekh + Wrap + Onion-Chutney Salad`,protein:38,calories:540,extraIngredients:[`--- ADULT FINISH ---`,`2-3 tbsp green chutney (drizzle on salad + dip)`,`Cucumber slices (thin half-moons)`,`Fresh lime wedge (optional)`],steps:[{text:`ADULT SALAD: Combine salted red onion + cucumber slices + 1 tbsp green chutney + tiny pinch more salt. Toss. This is the freshness anchor — without it, the plate is one-dimensional.`,images:[]},{text:`WRAP ONE KEBAB: Take one chicken seekh, place it on a warm rumali, fold the rumali around it. THIS is the plate-interaction move that elevates the visual.`,images:[]},{text:`PLATE: Wrapped kebab + 1-2 unwrapped chicken seekh on the side + folded rumali underneath + small ramekin of onion-cucumber-chutney salad. Optional: lime wedge.`,images:[`/images/emergency-kebab-night/adult-plate.webp`]}]},kid:{label:`Kid — Beef Seekh + Plain Rumali + Cucumber`,protein:26,calories:380,extraIngredients:[`--- KID FINISH (simple) ---`,`Cucumber sticks (4-5 per kid)`,`(Optional) tiny ramekin of green chutney as a dip if they ask`],variants:[{name:`Standard — Components Separate`,description:`Divided bento tray: 1-2 beef seekh kebabs + plain rumali (folded once, no wrap) + cucumber sticks in their own compartment. Sauce-as-dip pattern: skip the onion salad and chutney entirely unless they ask.`,steps:[{text:`PLATE: Bento tray. 1 beef seekh + 1 folded rumali (or one rolled around a half-kebab if they like burritos) + 4-5 cucumber sticks in another compartment. Done.`,images:[`/images/emergency-kebab-night/kid-tray.webp`]}]},{name:`Adventurous — Mild Chutney Dip`,description:`Same plate, plus a tiny ramekin of green chutney as a dip. Most cilantro-mint chutneys are not actually spicy — let them try.`,steps:[{text:`Add a 1-tbsp ramekin of green chutney to the divided tray. Don't push — they'll dip if they want.`}]}]}},ingredients:[`--- TIER 2 PROTEIN ---`,`1 box Colonel Kababz Chicken Seekh Kabab (11 oz) [adult]`,`1 box Colonel Kababz Beef Seekh Kabab (11 oz) [kid]`,`--- TIER 3 CARB ---`,`1 pack Vadilal Rumali Roti (6 pieces) — or Haldiram's Phulka Roti`,`--- TIER 4 FRESHNESS ---`,`1 medium red onion, sliced paper-thin [adult]`,`1 medium cucumber`,`2-3 tbsp store-bought green chutney [adult]`,`Salt`,`Lime wedge (optional, adult)`],steps:[{text:`AIR FRY KEBABS: Both boxes together, 400°F, 12 min. Shake at 6 min. The last 5 min gets the char — don't pull early. Char is non-negotiable.`,images:[`/images/emergency-kebab-night/mise-en-place.webp`]},{text:`SLICE + SALT THE ONION: Paper-thin red onion. Salt it. 5 min rest while kebabs cook — kills the harsh raw bite.`},{text:`CUCUMBER: Sticks for kids, thin slices for the adult salad.`},{text:`ADULT SALAD: Combine onion + cucumber slices + 1 tbsp green chutney + pinch of salt. Toss.`},{text:`WARM RUMALI: 30 sec in microwave, wrapped in damp paper towel. Don't dry out.`},{text:`WRAP ONE ADULT KEBAB IN RUMALI: This is the plate-interaction move. Don't skip.`},{text:`PLATE: Adult — wrapped chicken seekh + 1-2 more unwrapped + onion-chutney salad ramekin + optional lime. Kid — bento tray with beef seekh + plain folded rumali + cucumber sticks.`,images:[`/images/emergency-kebab-night/adult-plate.webp`]}],brands:[{name:`Colonel Kababz`,item:`Chicken Seekh Kabab (8 large, 11 oz)`,why:`Tier 2 protein for ADULTS. Halal, fully cooked, minced chicken with herbs + spices. Slightly spiced — adults get the kick. Same brand as the beef variant so cooking is identical.`,image:`/images/brands/colonel-kababz-chicken-seekh.jpg`,url:`https://www.midamarhalal.com/products/colonel-kababz-chicken-seekh-kabab-1`},{name:`Colonel Kababz`,item:`Beef Seekh Kabab (8 large, 11 oz)`,why:`Tier 2 protein for KIDS. Same brand, same macros, milder than the chicken version. The split-cook is done by SKU selection, not by cooking differently.`,image:`/images/brands/colonel-kababz-beef-seekh.jpg`,url:`https://www.midamarhalal.com/products/colonel-kababz-beef-seekh-kabab-1`},{name:`Vadilal Quick Treat`,item:`Rumali Roti (6 pieces, 240g)`,why:`Tier 3 carb. Thin, flexible, restaurant-style — the ONLY frozen roti that folds around a kebab cleanly. 30 sec microwave. Don't substitute for paratha (too thick).`,image:`/images/brands/vadilal-rumali-roti.png`,url:`https://www.sayweee.com/en/product/Vadilal-Quick-Treat-Rumali-Roti-6-pcs/91916`},{name:`Haldiram's`,item:`Minute Khana Phulka Roti (12 pieces)`,why:`Tier 3 carb alternative. Whole wheat, thicker, more traditional. Use when rumali isn't available or for kids who prefer something more substantial.`,image:`/images/brands/haldirams-phulka-roti.png`,url:`https://international.haldiram.com/frozen-food/haldiram-minute-khana/breads-range`}],mealPrep:{storage:`Kebabs: keep frozen until cook day. Cooked leftover kebabs keep 2 days in fridge. Rumali roti: stays frozen 6 months. Onion-cucumber salad: best fresh, same day only.`,reheat:`Kebabs: air fryer 350°F for 3 min to re-crisp. Rumali: 20 sec microwave in damp paper towel.`,lasts:`Cooked kebabs 2 days. Frozen components: months. Salad: same day.`}},{id:35,status:`live`,carbLevel:`high`,meta:{macros:{protein:23,calories:400,fat:14,carbs:45,netCarbs:42,estimated:!0},allergens:[`soy`,`gluten`],warnings:[`contains-soy`,`contains-gluten`,`spicy-adult-version`],dietTags:[`egg-free-kid-version`,`dairy-free`,`nut-free`,`halal`],proteinTags:[`chicken`],splitAxes:[`spice`,`carb`],effortTags:[`fast`,`air-fryer`,`freezer-to-plate`,`weeknight`,`modular`],costTier:`moderate`,costPerServing:`$5.50`,substitutionNotes:[`Cookbook bases used (stack them ahead): /cookbook/bone-broth-rice (8 servings, make Sunday), /cookbook/spicy-umami-fried-rice (adult side, uses cold bone broth rice), /cookbook/tks-sauce (adult glaze).`,`Chicken: Crazy Cuizine Mandarin Orange Chicken (66 oz Costco box, ~4 dinners per box at this scale). DISCARD the included orange-sauce packet — TKS Sauce replaces it. Frozen breaded chicken alternatives work (Kirkland, etc.) but flavor architecture is built around the Crazy Cuizine breading.`,`Kid version is intentionally simpler: half-serving plain bone broth rice (just reheat, no fried rice complexity), plain crispy chicken (pulled before saucing), raw mini sweet peppers for crunch. Same air fryer batch, simpler plate.`,`Adult side options: fried rice OR plain bone broth rice (skip the fried rice step if you're tired). Same chicken + sauce work over either.`]},slug:`tks-sweet-heat-bowl`,proteinAnchor:`chicken`,mealType:`other`,flavorDirection:`smoky-southwest`,splitFriendly:`full`,title:`Split Plate TKS Sweet Heat Chicken Bowl`,category:`Core Signatures`,pillar:`Protein Meals`,tags:[`chicken`,`crazy-cuizine`,`fried-rice`,`tks-sauce`,`air-fryer`,`split-cook`,`modular`,`weeknight`,`freezer-to-plate`],time:`20 min (if bone broth rice is pre-made)`,servings:4,protein:23,calories:400,image:`/images/tks-sweet-heat-chicken/hero.webp`,role:`The Modular Takeout Dinner`,makeThisWhen:`You have cold bone broth rice in the fridge (made Sunday, 8 servings batch), and you want a real high-protein takeout-style dinner in 20 minutes. Same air fryer batch covers adults + kids — adults get the glaze + fried rice, kids get plain chicken + plain rice + sweet peppers. Drop the included orange-sauce packet, swap in TKS Sauce.`,hook:`One air fryer batch of Crazy Cuizine, two completely different plates. Adults get crispy chicken tossed in TKS Sauce over Spicy Umami Fried Rice. Kids get plain crispy chicken with half-serving bone broth rice and raw sweet peppers — no spice, no glaze, no fried-rice complexity. The Costco frozen chicken is the protein anchor; the cookbook bases (bone broth rice + fried rice + TKS sauce) do all the upgrading.`,description:`Modular dinner that stacks three cookbook bases: Bone Broth Rice (made ahead Sunday, used cold for adult fried rice + warm for kid plain rice), Spicy Umami Fried Rice (adult side), and TKS Sauce (adult chicken glaze). 1 lb Crazy Cuizine chicken in the air fryer → split at the toss step: adult portion (5 oz each) goes into a hot dry pan with TKS Sauce for the cling; kid portion (3 oz each) gets pulled before saucing, plated plain. 20 minutes active time when rice is pre-made.`,whyMostFail:[`Use the included Crazy Cuizine orange-sauce packet. It's a sugar bomb. The whole point of this recipe is replacing it with TKS Sauce.`,`Toss the chicken with cold sauce. Pan needs to be screaming hot when sauce hits — the residual breading starch + the sauce reduce together for natural glaze cling. Cold pan = sauce slides off.`,`Use fresh hot rice instead of cold for the adult fried rice. Fresh rice steams and turns mushy. Bone broth rice has to be cold (overnight fridge or 30 min freezer minimum).`,`Sauce the kid portion. Kids in this house don't want the glaze — pull their chicken BEFORE the sauce hits the pan. Same air fryer batch, different plating.`,`Skip the raw sweet peppers on the kid plate. The plate becomes 100% beige otherwise — chicken brown, rice brown. Peppers are the cheap Tier 4 fix.`],whyThisWorks:[`Three cookbook bases do the work: Bone Broth Rice (8-serving batch made Sunday) + Spicy Umami Fried Rice (3-serving recipe, uses 2 servings for the adults) + TKS Sauce (2-serving recipe, half batch glazes 10 oz chicken).`,`One air fryer batch of Crazy Cuizine = 1 lb cooked = 2 adult portions (5 oz each) + 2 kid portions (3 oz each). Costco party box = 4 dinners worth.`,`Adult split: chicken pulled into hot dry pan + TKS Sauce poured around the edge + 60-90 sec toss = restaurant glaze cling without cornstarch slurry.`,`Kid split: chicken pulled BEFORE the sauce step. Half-serving plain bone broth rice (microwave 60 sec with a splash of water). Raw mini sweet peppers on the side. Components separate (sauce-as-dip pattern applies — pour TKS Sauce in a tiny ramekin if they want to dip).`,`Macros stay honest: 5 oz chicken = 200 cal / 13g protein. + 1/4 batch TKS Sauce = ~28 cal / 3g. + 1 serving fried rice = 333 cal / 16g. Adult total ~560 cal / 32g protein. Kid total ~235 cal / 14g protein. Averaged 400 cal / 23g.`],executionRules:[`BONE BROTH RICE MUST BE PRE-MADE AND COLD. The adult fried rice requires cold rice for texture. If you don't have it cold, make it the morning of and spread on a sheet pan to chill faster.`,`AIR FRY ONE BATCH for everyone: 1 lb Crazy Cuizine, 400°F, 9-12 min, single layer, shake basket halfway. Pull when crispy + golden.`,`PULL KID PORTION FIRST. 6 oz (about 2 small kids' worth) onto the kid tray BEFORE the adult chicken goes near sauce. No going back once it's glazed.`,`ADULT GLAZE STEP: dry skillet medium-high, screaming hot, chicken in, TKS Sauce poured AROUND THE EDGE (not on chicken). Toss aggressively 60-90 sec. The hiss is the cue. Off heat when every piece is glossy.`,`WHILE CHICKEN COOKS: make fried rice from cold bone broth rice (full method on the cookbook page). Microwave kid's half-serving plain bone broth rice with a splash of water (60 sec).`,`PLATE KID FIRST so peppers don't get warm. Adult plate last so the chicken stays hot under the glaze.`],troubleshooting:[{problem:`Sauce slid off chicken instead of glazing`,fix:`Pan wasn't hot enough. Medium-high, screaming hot, sauce around the edge of the pan (hissing immediately). Toss continuously — the cling builds over 60-90 sec, it's not instant.`},{problem:`Fried rice is mushy`,fix:`Used warm rice. Bone broth rice MUST be cold. Make ahead, fridge overnight. The 8-serving Sunday batch is the architecture move.`},{problem:`Kid won't eat the chicken even plain`,fix:`Crazy Cuizine breading has a slight tang. If your kid is sensitive, brush with butter + tiny pinch of salt after air-frying — totally neutralizes the breading flavor.`},{problem:`Kid plate looks beige`,fix:`Add the raw mini sweet peppers. Costco multicolor mini sweet peppers (red, orange, yellow) are the Tier 4 fix — kids snack on them raw between bites of chicken. Don't cook them, kids prefer them crunchy.`},{problem:`Adults want more chicken / heavier portion`,fix:`Use 6-7 oz per adult instead of 5. Top out at 8 oz max — at that point you've eaten a full Costco serving worth, the macros stop being honest.`},{problem:`Want to scale up to 4 adults instead of 2A+2K`,fix:`Use full 1 lb chicken just for adults (4 × 4 oz portions) and a full batch of TKS Sauce. Make 2 batches of fried rice (uses 6 servings of bone broth rice — slightly less than the 8-serving Sunday batch).`}],splitCook:{splitRatio:`55% Adult Sauced / 45% Kid Plain`,splitPoint:`AFTER AIR FRYER. Pull kid portion (6 oz total) onto the kid tray BEFORE saucing the adult portion. Same air fryer batch, sauce only touches the adult chicken.`,sharedIngredients:[`--- PROTEIN (one air fryer batch covers everyone) ---`,`1 lb Crazy Cuizine Mandarin Orange Chicken (frozen, air-fryer ready)`,`*** Throw away the included orange-sauce packet — that's the whole reason this recipe exists ***`,`--- TIER 3 BASE (made ahead Sunday) ---`,{text:`Bone Broth Rice (need 2.5 servings of the 8-serving batch — adult fried rice uses 2, kid plain uses 0.5)`,link:`/cookbook/bone-broth-rice`}],sharedSteps:[{text:`AIR FRY CHICKEN: 1 lb Crazy Cuizine, 400°F, 9-12 min from frozen, single layer, shake basket at 6 min. Pull when crispy + golden + edges crackle.`,images:[`/images/tks-sweet-heat-chicken/wok-cooked.webp`]},{text:`MAKE THE TKS SAUCE: While chicken air-fries (you have ~10 min). Whisk ginger-garlic paste + sesame chili oil + rice vinegar + soy + Bare Bones packet + hot honey sriracha. Full method in TKS Sauce (Cookbook).`,images:[`/images/tks-sweet-heat-chicken/sauce-ready.webp`]},{text:`MAKE THE FRIED RICE: While chicken cooks, fry the cold bone broth rice with egg + sauce per the Spicy Umami Fried Rice method. Use 2 servings of cold bone broth rice for 2 adults. Full method in Spicy Umami Fried Rice (Cookbook).`,images:[]},{text:`PULL KID CHICKEN: 6 oz (about half the cooked batch) onto the kid tray. No sauce yet. This is the split point.`,images:[`/images/tks-sweet-heat-chicken/wok-cooked.webp`]}],adult:{label:`Adult — TKS Sauced + Fried Rice`,protein:32,calories:560,extraIngredients:[`--- ADULT GLAZE ---`,{text:`1/2 batch TKS Sauce (made while chicken cooks)`,link:`/cookbook/tks-sauce`},`--- ADULT SIDE ---`,{text:`1 serving Spicy Umami Fried Rice (per adult) — made from cold bone broth rice`,link:`/cookbook/spicy-umami-fried-rice`},`--- ADULT GARNISH (optional, recommended) ---`,`1-2 scallions, sliced thin`,`1 tsp toasted sesame seeds`],steps:[{text:`HOT DRY SKILLET: Medium-high heat, dry pan (no oil), screaming hot. Add the adult chicken (10 oz total, 5 oz per person).`,images:[]},{text:`GLAZE: Pour half a batch of TKS Sauce AROUND THE EDGE of the pan — the hiss is the cue. Toss aggressively 60-90 sec until every piece is glossy. Off heat when standing liquid is gone.`,images:[]},{text:`PLATE: Adult bowl — pile of Spicy Umami Fried Rice on one side, glossy TKS-glazed chicken on the other. Scatter scallions + sesame seeds across both. Real takeout dinner.`,images:[`/images/tks-sweet-heat-chicken/hero.webp`]}]},kid:{label:`Kid — Plain Crispy + Half Rice + Sweet Peppers`,protein:14,calories:235,extraIngredients:[`--- KID SIDE (kept simple) ---`,`Half serving Bone Broth Rice (microwave 60 sec with a splash of water)`,`4-6 raw mini sweet peppers (Costco multicolor bag — red, orange, yellow)`,`--- KID OPTIONAL DIP ---`,{text:`Tiny ramekin of TKS Sauce on the side (most kids skip — sauce-as-dip pattern: it's there if they want to try it)`,link:`/cookbook/tks-sauce`}],variants:[{name:`Standard — Plain Chicken + Half Rice + Peppers`,description:`3 oz unsauced crispy chicken, half serving plain bone broth rice (just reheated, no fried rice complexity), 4-6 raw mini sweet peppers on the side. Optional tiny ramekin of TKS Sauce as a dip if they want to try it.`,steps:[{text:`REHEAT KID RICE: Half serving plain bone broth rice in a small bowl, splash of water, microwave 60 sec covered with a damp paper towel.`,images:[]},{text:`SLICE PEPPERS: 4-6 mini sweet peppers cut into rings or sticks. Raw — kids prefer the crunch.`,images:[]},{text:`PLATE KID TRAY: 3 oz crispy chicken (no sauce) + half-serving plain bone broth rice (use a small ramekin and flip onto the plate as a rice mound — kids respond to playful shapes) + raw sweet peppers on the side. Optional tiny TKS Sauce ramekin as dip. Done.`,images:[`/images/tks-sweet-heat-chicken/kid-trays.webp`]}]},{name:`Picky — Plain Chicken Only`,description:`Skip the rice, skip the peppers, just plain crispy chicken. Pair with a soft tortilla or bread if they need a carb anchor.`,steps:[{text:`PLATE: Just the 3 oz plain crispy chicken. Optionally with a folded tortilla or piece of bread on the side.`}]}]}},ingredients:[`--- PROTEIN ---`,`1 lb Crazy Cuizine Mandarin Orange Chicken (frozen) — discard the orange-sauce packet`,`--- COOKBOOK BASES (pre-made or stacked into this meal) ---`,{text:`Bone Broth Rice — 2.5 servings of the 8-serving batch`,link:`/cookbook/bone-broth-rice`},{text:`Spicy Umami Fried Rice — adult side, 2 servings from a 3-serving batch`,link:`/cookbook/spicy-umami-fried-rice`},{text:`TKS Sauce — adult glaze, 1/2 batch (the whole batch makes 2 servings — fits perfectly)`,link:`/cookbook/tks-sauce`},`--- KID SIDES ---`,`4-6 raw mini sweet peppers per kid (Costco multicolor bag) [kid]`,`--- ADULT GARNISH (optional) ---`,`Scallions, sliced thin`,`Toasted sesame seeds`],steps:[{text:`AIR FRY ALL THE CHICKEN: 1 lb Crazy Cuizine, 400°F, 9-12 min from frozen. One batch for everyone. Discard the included orange-sauce packet.`,images:[`/images/tks-sweet-heat-chicken/wok-cooked.webp`]},{text:`MAKE TKS SAUCE: Whisk together while chicken cooks. 2 min. Full method on the TKS Sauce cookbook page.`,images:[`/images/tks-sweet-heat-chicken/sauce-ready.webp`]},{text:`MAKE ADULT FRIED RICE: From cold bone broth rice + egg + sauce. Full method on Spicy Umami Fried Rice cookbook page. 12 min total, finishes around the same time as the chicken.`},{text:`MICROWAVE KID RICE: Half serving plain bone broth rice + splash of water, 60 sec covered.`},{text:`PULL KID CHICKEN: 6 oz onto the kid tray BEFORE saucing. The split point.`,images:[`/images/tks-sweet-heat-chicken/wok-cooked.webp`]},{text:`GLAZE ADULT CHICKEN: Hot dry skillet, adult chicken in, TKS Sauce around the edge, toss 60-90 sec until every piece is glossy.`},{text:`PLATE: Adults get fried rice + glazed chicken + scallion-sesame garnish. Kids get plain chicken + half-serving plain rice + raw sweet peppers + optional TKS Sauce ramekin as dip.`,images:[`/images/tks-sweet-heat-chicken/kid-trays.webp`,`/images/tks-sweet-heat-chicken/hero.webp`]}],brands:[{name:`Crazy Cuizine`,item:`Mandarin Orange Chicken (66 oz Costco party box, discard the packet)`,why:`Pre-cooked, pre-breaded, air-fryer ready in 9-12 min. The chicken itself is good — antibiotics-free, 13g protein per 3 oz. The orange-sauce packet is what's wrong with it. One Costco box = 4 dinners at this scale.`,image:`/images/brands/crazy-cuizine-mandarin-orange-chicken.jpg`,url:`https://www.costco.com/p/-/crazy-cuizine-mandarin-orange-chicken-66-oz/100437350`},{name:`Bone Broth Rice`,item:`Cookbook base — pre-made Sunday`,why:`Tier 3 carb. 8-serving batch on Sunday powers this dinner (adult fried rice + kid plain rice), plus 5.5 servings of leftover rice for the rest of the week. This is the architecture move — never make rice on dinner night.`,url:`/cookbook/bone-broth-rice`},{name:`Spicy Umami Fried Rice`,item:`Cookbook base — adult side`,why:`Tier 3+2+1+4 stacked into one side. Uses 2 servings of cold bone broth rice for 2 adults. Made fresh while chicken air-fries.`,url:`/cookbook/spicy-umami-fried-rice`},{name:`TKS Sauce`,item:`Cookbook base — adult glaze`,why:`Tier 1 signature sauce. Replaces the discarded Crazy Cuizine orange packet. Hot-pan toss technique gives restaurant cling without cornstarch slurry.`,url:`/cookbook/tks-sauce`}],mealPrep:{storage:`Best fresh. Cooked sauced chicken keeps 2 days but the glaze cling softens. Plain unsauced chicken (kid portion) holds longer.`,reheat:`Air fryer 350°F for 3-4 min to re-crisp the breading. Microwave kills the texture.`,lasts:`Fried rice 2-3 days. Sauced chicken 2 days. Plain chicken 3 days. Bone broth rice 5-6 days.`,chainTo:{slug:`next-day-chicken-tacos`,title:`Next-Day Chicken Tacos`,note:`Leftover plain crispy chicken (kid portion) chops fine and stacks into next-day tacos — same modular system, different format.`}}},{id:36,status:`live`,carbLevel:`high`,meta:{macros:{protein:39,calories:510,fat:25,carbs:31,netCarbs:11,estimated:!0},allergens:[`dairy`,`gluten`],warnings:[`contains-dairy`,`contains-gluten`,`spicy-adult-version`],dietTags:[`egg-free`,`soy-free`,`nut-free`],proteinTags:[`pork`],splitAxes:[`pasta`,`spice`],effortTags:[`meal-prep`,`one-pot-base`,`weeknight`,`split-pasta`],costTier:`moderate`,costPerServing:`$5.00`,substitutionNotes:[`Protein pasta is the design lever — Pete's Rotini gets paired with full-fat Italian sausage because the pasta's 17g protein + 7g net carbs absorbs the indulgence. DON'T sub lean turkey when using protein pasta. That's belt-and-suspenders fitness cosplay.`,`Kid pasta is regular Barilla Mini Penne — small enough to be kid-familiar, no protein-pasta texture resistance.`,`Adult finish: chili flakes + Italian seasoning go on the adult plate only. Kid plate stays mild.`,`Spinach goes in the adult pan only — kids consistently reject it. Save the spinach for adults, free up the kid plate.`,`Sausage brand: Falls Brand Mild Italian (1.5 lb tray, fresh ground pork, gluten-free) is what's called for; any mild Italian sausage works. Falls Brand specifically because the fat ratio works for the drain step.`]},slug:`creamy-sausage-spinach-pasta`,proteinAnchor:`pork`,mealType:`pasta`,flavorDirection:`creamy-comfort`,splitFriendly:`full`,title:`Creamy Sausage Spinach Pasta`,category:`Core Signatures`,pillar:`Protein Meals`,tags:[`pasta`,`sausage`,`spinach`,`alfredo`,`split-cook`,`protein-pasta`,`meal-prep`,`weeknight`,`comfort`],time:`35 min`,servings:8,protein:39,calories:510,image:`/images/creamy-sausage-spinach-pasta/hero.webp`,role:`The Cook-Once Pasta That Meal-Preps All Week`,makeThisWhen:`You want one cook to feed the family tonight AND fill 8 lunch containers for the week. Adults get Pete's high-protein rotini with sausage + spinach + chili flakes. Kids get Barilla mini penne with sausage only — no spinach, no spice. Same pan-fond, two finishing paths.`,hook:`Protein pasta is the lever, not the lean turkey. Pete's rotini absorbs the indulgence — splurge on full-fat Italian sausage + real Alfredo because the pasta's 17g protein + 7g net carbs makes the macros honest. Kids eat regular mini penne with the same sausage. Both versions are real food, neither is fake-healthy.`,description:`Cook 3 lb of Falls Brand mild Italian sausage in one pan, drain the fat (this is the critical move — without it, the Alfredo turns oily), then split: half goes into Pete's protein rotini with wilted baby spinach for adults, half goes into Barilla mini penne for kids. Adults finish with chili flakes + Italian seasoning. 8 meal-prep servings at 510 cal / 39g protein each. Reheats well — Pete's pasta + Alfredo + bone broth splash holds up across the week where leaner meal preps go chalk by day 3.`,whyMostFail:[`Skip the fat-drain step. Rao's + sausage fat = greasy sludge. Drain the rendered grease and the Alfredo stays creamy. This is the move that separates 'meal prep' from 'glistening leftover container of regret'.`,`Force protein pasta on kids. Most kids reject the texture instantly — chew is wrong, color is wrong, it's not the penne they know. Use Barilla Mini Penne for kids, Pete's Rotini for adults. Both pastas cook in the same time window.`,`Pair protein pasta with lean ground turkey. Belt-and-suspenders fitness cosplay — the pasta IS the lean play. Splurge on full-fat Italian sausage and the macros stay honest.`,`Wilt spinach into the sauce pan with the sausage. Spinach dumps water into the sauce and dilutes it. Cook spinach separately, drain it, then fold into adult pan.`,`Make one giant pasta and try to split flavors after. Cook two pastas. Split happens at the pasta pot, not after.`],whyThisWorks:[`Pete's Pasta Rotini (17g protein / 7g net carbs per serving) does what most 'high-protein meal preps' use lean turkey for — but does it through the carb-balance lever instead of the meat-fat lever. That lets the sausage stay full-fat and the sauce stay full-cream.`,`Falls Brand fresh ground pork sausage renders enough fat in 8 minutes to need draining. Without drain = oily sludge. With drain = clean sausage with deep browning + a clean Alfredo.`,`Wilt the spinach SEPARATELY (not in the sausage pan). Water from the spinach would break the sauce. Drain after wilting before folding into the adult pan.`,`Two pastas, one sausage-Alfredo base: 3 lb sausage + 1 jar Rao's makes enough sauce for both pans. Split the cooked sausage between the two pasta pots at the end.`,`Adult plate gets the protein/fiber win (Pete's rotini + sausage + Alfredo + spinach + chili flakes + Italian seasoning). Kid plate gets the familiar comfort win (Barilla mini penne + sausage + Alfredo). Both win different battles.`,`Bone broth (1/2 cup, added slowly) loosens the sauce if it tightens. This is the meal-prep reheat secret — Pete's pasta absorbs sauce overnight; the bone broth gives the dish somewhere to loosen back up by mid-week.`],executionRules:[`BROWN HARD, BREAK SMALL. Use a meat masher to break sausage finely (kid-bite size). Big chunks distribute unevenly across containers; small crumble distributes everywhere.`,`DRAIN THE FAT. After the sausage is browned, pour everything into a strainer set over a bowl. Discard the rendered fat (or save 1 tbsp for the spinach pan if you want). Return the drained meat to the pan. This is the single move that determines whether the meal prep stays creamy or turns oily by day 2.`,`COOK SPINACH SEPARATELY. Wilt 12 oz baby spinach in a separate pan over medium heat (with or without 1 tsp of the reserved sausage fat). 90 seconds — pull when bright green, not gray. Drain and squeeze excess water.`,`TWO PASTA POTS. Pete's rotini for adults (~6 servings of pasta dry = ~3 cups), Barilla mini penne for kids (~3 servings dry = ~1.5 cups). Both finish in 9-10 minutes. Cook simultaneously in two pots.`,`BUILD THE SAUCE LOW. After drain, add the full jar of Rao's Alfredo + 1 extra serving to the sausage pan over LOW heat. Stir. If it's tight, add bone broth 2 tbsp at a time (up to 1/2 cup total). The cream should coat the spoon, not slide off.`,`SPLIT AT THE FINAL STEP. Adult pan: rotini + 60% of sausage-Alfredo + spinach + a pinch of chili flakes + Italian seasoning. Kid pan: mini penne + 40% of sausage-Alfredo. No spinach, no chili flakes.`,`PORTION INTO 8 CONTAINERS. ~6 adult portions + ~2 kid portions, OR adjust to your household. Macros per portion: 510 cal / 39g protein / 25g fat / 11g net carbs.`],troubleshooting:[{problem:`Sauce is oily / greasy`,fix:`You skipped the fat-drain step. There is no save here mid-recipe — next time, drain. For tonight, scoop visible fat off the top of the pan with a spoon and stir in 1 tbsp of fresh cream cheese to re-emulsify. Imperfect fix.`},{problem:`Pasta is dry by day 3 of leftovers`,fix:`Add 2 tbsp of chicken bone broth or water when reheating. Microwave covered 90 sec, stir, microwave 30 sec more. Pete's pasta absorbs sauce overnight — the bone broth gives it somewhere to loosen back up.`},{problem:`Sausage broke into big chunks instead of fine crumble`,fix:`Use a meat masher tool (or potato masher). Most home cooks use a spatula and stop mashing too early. Keep mashing for the first 4 minutes — fine crumble distributes flavor evenly across the dish.`},{problem:`Spinach turned gray and watery`,fix:`Cooked too long OR added directly to the sauce. Wilt SEPARATELY for 90 sec, drain, squeeze. Then fold into the adult pan.`},{problem:`Kid won't eat the mini penne even plain`,fix:`Strip 1 oz of the sausage-Alfredo from the kid pan and mix in 1 tbsp regular butter + a pinch of salt. Plain pasta + butter is the universal kid override.`},{problem:`Adults want more heat`,fix:`Bump the chili flakes from a pinch to 1/4 tsp per adult bowl. Or stir in 1 tsp of Calabrian chili paste at the very end — that's the restaurant move.`}],splitCook:{splitRatio:`60% Adult Pete's Rotini / 40% Kid Mini Penne`,splitPoint:`AT THE PASTA POTS. Two pots cook simultaneously (Pete's for adults, Barilla for kids). After draining the sausage and building the Alfredo, split the sausage-sauce 60/40 between the two pasta pots. Adult pot gets the wilted spinach + chili flakes + Italian seasoning; kid pot stays plain.`,sharedIngredients:[`--- PROTEIN ---`,`3 lb Falls Brand Mild Italian Sausage (the 24 oz / 1.5 lb tray, buy 2)`,`--- SAUCE ---`,`1 full jar Rao's Homemade Alfredo Sauce (~15 oz)`,`1 additional serving Rao's Alfredo (about 4 oz from a second jar, OR substitute 1/4 cup heavy cream + 2 tbsp Parmesan)`,`Up to 1/2 cup chicken bone broth (added slowly to loosen sauce as needed)`],sharedSteps:[{text:`BROWN THE SAUSAGE: All 3 lb in a large skillet over medium-high heat. Break apart finely with a meat masher (kid-bite size). 8-10 min until deeply browned and fond starts forming.`,images:[`/images/creamy-sausage-spinach-pasta/brown-sausage.webp`]},{text:`DRAIN THE FAT (NON-NEGOTIABLE): Pour the sausage into a strainer over a bowl. Discard the rendered grease. Return drained sausage to the pan. This step determines whether the meal prep stays creamy or turns oily by day 2.`,images:[`/images/creamy-sausage-spinach-pasta/drain-fat.webp`]},{text:`WILT SPINACH SEPARATELY: 12 oz baby spinach in a separate pan over medium heat. 90 seconds, just until bright green. Drain, squeeze excess water. Set aside.`,images:[`/images/creamy-sausage-spinach-pasta/spinach-sausage.webp`]},{text:`COOK TWO PASTAS SIMULTANEOUSLY: Pot 1: 6 servings dry Pete's Rotini, salted boiling water, 9-10 min al dente (adult). Pot 2: 3 servings dry Barilla Mini Penne, same timing (kid).`,images:[]},{text:`BUILD THE SAUCE: Lower heat on the sausage pan. Add the full jar of Rao's + 1 extra serving. Stir until coated. If tight, splash bone broth (2 tbsp at a time, up to 1/2 cup total). Sauce should coat the back of a spoon.`,images:[]}],adult:{label:`Adult — Pete's Rotini + Spinach + Heat`,protein:45,calories:560,extraIngredients:[`--- ADULT PASTA ---`,`6 servings dry Pete's Pasta Rotini (about 12 oz dry — adult pot)`,`--- ADULT FINISH ---`,`12 oz wilted baby spinach (from the shared step, all of it)`,`Pinch of red chili flakes`,`1/2 tsp Italian seasoning`],steps:[{text:`ADULT POT: Toss drained Pete's Rotini with 60% of the sausage-Alfredo from the shared pan. Fold in wilted spinach. Sprinkle a pinch of chili flakes + 1/2 tsp Italian seasoning. Toss until rotini grooves are coated.`,images:[`/images/creamy-sausage-spinach-pasta/two-pans.webp`]},{text:`PLATE ADULT: Generous scoop into a wide bowl. Rotini grooves catch the sauce + sausage + spinach. Optional: cracked black pepper + grated Parmesan.`,images:[`/images/creamy-sausage-spinach-pasta/hero.webp`]}]},kid:{label:`Kid — Mini Penne + Sausage Only`,protein:28,calories:420,extraIngredients:[`--- KID PASTA ---`,`3 servings dry Barilla Mini Penne (about 6 oz dry — kid pot)`,`--- KID FINISH ---`,`(nothing — keep it plain)`],variants:[{name:`Standard — Plain Mini Penne`,description:`Mini penne tossed with sausage + Alfredo. No spinach, no spice. The familiar comfort version.`,steps:[{text:`KID POT: Toss drained Barilla Mini Penne with 40% of the sausage-Alfredo from the shared pan. NO spinach, NO chili flakes. Stir to coat.`},{text:`PLATE KID: Smaller bowl. Just pasta + sauce + visible sausage crumble. Looks like the cafeteria penne they already eat — no surprises.`}]},{name:`Buttery — For The Spice-Sensitive Kid`,description:`If the kid rejects even the Alfredo (some do — it's the herb flecks in Rao's), strip the kid portion plain and stir in 1 tbsp butter + tiny salt.`,steps:[{text:`Skip the Alfredo on this kid's pasta entirely. Toss the drained mini penne with 1 tbsp butter + a pinch of salt + some sausage crumble. Done.`}]}]}},ingredients:[`--- PROTEIN ---`,`3 lb Falls Brand Mild Italian Sausage (two 24 oz / 1.5 lb trays)`,`--- SAUCE ---`,`1 jar Rao's Homemade Alfredo Sauce (15 oz)`,`1 extra serving Rao's Alfredo (~4 oz from another jar) OR 1/4 cup heavy cream + 2 tbsp Parmesan`,`Up to 1/2 cup chicken bone broth (to loosen)`,`--- ADULT PASTA + FINISH ---`,`6 servings dry Pete's Pasta Rotini [adult]`,`12 oz Marketside baby spinach [adult]`,`Red chili flakes [adult]`,`Italian seasoning [adult]`,`--- KID PASTA ---`,`3 servings dry Barilla Mini Penne [kid]`],steps:[{text:`MISE EN PLACE: Falls Brand sausage out, Pete's rotini, Barilla mini penne, Rao's Alfredo, baby spinach, bone broth ready. Two pasta pots filled and salted, sausage pan ready.`,images:[`/images/creamy-sausage-spinach-pasta/mise-en-place.webp`]},{text:`BROWN SAUSAGE: 3 lb in large skillet, medium-high. Mash finely with meat masher. 8-10 min, deeply browned with fond.`,images:[`/images/creamy-sausage-spinach-pasta/brown-sausage.webp`]},{text:`DRAIN THE FAT: Sausage into strainer over a bowl. Discard grease. Return drained sausage to pan. NON-NEGOTIABLE step.`,images:[`/images/creamy-sausage-spinach-pasta/drain-fat.webp`]},{text:`WILT SPINACH: 12 oz in separate pan, medium, 90 sec until bright green. Drain, squeeze.`,images:[`/images/creamy-sausage-spinach-pasta/spinach-sausage.webp`]},{text:`COOK PASTAS: Pete's Rotini in pot 1, Barilla Mini Penne in pot 2. Both 9-10 min al dente.`},{text:`BUILD SAUCE: Low heat on sausage pan. Stir in full Rao's jar + 1 extra serving. Loosen with bone broth if tight (2 tbsp at a time, up to 1/2 cup).`},{text:`SPLIT INTO TWO PANS: 60% sausage-Alfredo into adult pan with rotini + spinach + chili flakes + Italian seasoning. 40% into kid pan with mini penne (no spinach, no spice).`,images:[`/images/creamy-sausage-spinach-pasta/two-pans.webp`]},{text:`PLATE OR MEAL-PREP: Generous bowls tonight, OR portion into 8 meal-prep containers (~6 adult + ~2 kid) for the week. Reheat with a splash of bone broth to keep the sauce loose.`,images:[`/images/creamy-sausage-spinach-pasta/hero.webp`]}],brands:[{name:`Falls Brand`,item:`Old Fashioned Recipe Mild Italian Sausage (24 oz / 1.5 lb tray)`,why:`Fresh ground pork (not pre-cooked rope sausage). Renders enough fat in 8 min to need draining — that's exactly the macro-balance lever this recipe uses. Gluten-free. Buy two trays for the 3-lb batch.`,url:`https://www.walmart.com/ip/Falls-Brand-Fresh-Pork-Sausage-Mild-Italian-24-oz/33856372`},{name:`Pete's Pasta`,item:`Rotini (8 oz, high protein / low carb, made in Italy)`,why:`17g protein / 7g net carbs per serving. This is the design lever — the protein/fiber in the pasta absorbs the indulgence of full-fat sausage + cream Alfredo, so the macros stay honest. DO NOT pair this pasta with lean turkey. That defeats the architecture.`,image:`/images/brands/petes-pasta-rotini.png`,url:`https://petespasta.com/products/rotini`},{name:`Rao's`,item:`Homemade Alfredo Sauce (15 oz jar)`,why:`Real cream + Parmesan + butter, no flour thickener, no preservatives. The full-fat sauce is the point — the protein pasta makes the macros work.`,image:`/images/brands/raos-alfredo.png`,url:`https://raos.com/product/alfredo-sauce/`},{name:`Barilla`,item:`Classic Mini Penne (1 lb box)`,why:`Kid pasta. Mini penne is the cafeteria-familiar shape — kids accept it instantly. Non-GMO, durum wheat. 9-10 min al dente, same window as Pete's.`,image:`/images/brands/barilla-mini-penne.png`,url:`https://www.barilla.com/en-us/products/pasta/classic-blue-box/mini-penne`},{name:`Marketside (Walmart)`,item:`Fresh Baby Spinach (11 oz clamshell)`,why:`Pre-washed, pre-trimmed. Wilts in 90 sec. Adult-pan-only ingredient — kids consistently reject it, save your spinach and your peace.`,url:`https://www.walmart.com/ip/Marketside-Fresh-Baby-Spinach-11-oz/23848086`}],macroHonesty:`Per-serving (510 cal / 39g protein / 25g fat / 31g total carbs / 11g net carbs) computed for the 8-serving batch with the fat-drain step (~30% of sausage fat discarded). WITHOUT the drain, calories would be ~620/serving and fat ~36g. The drain is what makes the macros honest. Flagged estimated because Pete's pasta serving size and sausage fat retention vary by cook.`,mealPrep:{storage:`8 containers, fridge. Pete's pasta absorbs sauce overnight — that's why the bone broth fix exists for reheating.`,reheat:`Microwave covered 90 sec + a splash of chicken bone broth (or water) to loosen the sauce, stir, microwave 30 sec more. Skip the reheat-splash and the dish goes chalky by day 3.`,lasts:`4-5 days in the fridge. Freezes OK for 2 months but Pete's protein pasta texture softens slightly after freezer storage. Best fresh through day 4.`}},{id:37,status:`live`,carbLevel:`high`,meta:{macros:{protein:47,calories:540,fat:27,carbs:33,netCarbs:28,estimated:!0},allergens:[`dairy`],warnings:[`contains-dairy`,`spicy-adult-version`],dietTags:[`gluten-free`,`halal`,`egg-free`,`soy-free`,`nut-free`],proteinTags:[`chicken`],splitAxes:[`spice`,`presentation`],effortTags:[`grill`,`weeknight`,`one-hand`,`split-plate`],costTier:`moderate`,costPerServing:`$5.50`,substitutionNotes:[`Boneless skinless thighs (Tier 2 reliable protein) — sub bone-in if outdoor grilling, just add 8-10 min cook time. Breasts work but dry out; thighs are forgiving.`,`Dan-O's Outlaw Sweet & Tangy (Tier 1 Dan-O's family — pairs across recipes 21, 31) — tamarind-based, not just sugar. Sub Original + 1 tsp brown sugar + a pinch of tamarind paste if you only have Original.`,`Little Potato Co. Savory Herb tray (Tier 3 emergency carb) — pre-washed, microwave-ready, seasoning packet included. Sub any small waxy potatoes + your own herb mix; the convenience play is the tray.`,`Lee Kum Kee Chiu Chow Style Chili Crisp Oil (Tier 1 signature) — does double duty here: 2 tbsp in the marinade for color + acidity, then again in the Chili Crisp Sour Cream (see /cookbook/chili-crisp-sour-cream). Sub Fly By Jing or Lao Gan Ma; the Chiu Chow has shallot + garlic bits that carry flavor.`,`Daisy Light Sour Cream (Tier 1 sauce base) — pairs with the chili crisp for the adult dip. Sub regular sour cream (full fat) for richer mouthfeel, but macros climb.`,`Flavor rotation reality check: this dinner is sweet + smoky + spicy. If your weekly rotation already has Tandoori (id 26), Buffalo Wings (id 33), or Dan-O's Bone-In (id 31) — those all live in the same flavor bucket. Pair Outlaw Grilled Thighs with herb/citrus dinners (id 25 chimichurri) or yogurt-marinade dinners to keep the palate honest across the week.`]},slug:`outlaw-grilled-thighs-smashed-potatoes`,proteinAnchor:`chicken`,mealType:`grill`,flavorDirection:`sweet-tangy-spicy`,splitFriendly:`full`,title:`Outlaw BBQ Grilled Thighs + Smashed Potatoes`,category:`Core Signatures`,pillar:`Protein Meals`,tags:[`grill`,`outdoor`,`chicken`,`potatoes`,`tamarind`,`chili crisp`,`sauce-anchored`,`split-cook`,`weeknight`],time:`30 min`,servings:4,protein:47,calories:540,image:`/images/outlaw-grilled-thighs/hero.webp`,role:`The Grill-Night Family Win`,makeThisWhen:`It's grill weather and you want a real cookout dinner that adults and kids will both eat. Adult plate: sliced thigh + crispy smashed potatoes + chili crisp sour cream. Kid tray: diced chicken (no char), same potatoes, plain sour cream dip. Two presentations, one workflow.`,hook:`Sweet-tangy tamarind glaze, deep grill char, crispy smashed potatoes, and a chili crisp sour cream dip that's already a cookbook-grade sauce. Adults get the full split-plate flex; kids get the 3-compartment tray with all the spice pulled out. Same cook, same potatoes, same chicken — different format.`,description:`~47g protein for ~540 calories. Boneless skinless thighs marinated in Dan-O's Outlaw Sweet & Tangy + chili crisp + light oil, grilled over medium-high until the edges char (not burn), then sliced for adults and diced for kids. Smashed potatoes from a Little Potato Co. tray — microwave 5 min, smash with jagged edges (NOT puréed), bake until deeply browned. Chili crisp sour cream sauce on the side for adults; plain Daisy Light for kids. Outdoor grill is ideal; cast iron grill pan or oven broiler with grill marks works.`,whyMostFail:[`Pull the chicken too early. Boneless thighs need real char on the surface — the sweet & tangy marinade needs heat to caramelize. Pale grilled chicken is the failure mode. Pull when the edges are darkly charred AND the internal temp hits 165°F, not before.`,`Mash the potatoes into purée. The whole point of smashed potatoes is the jagged broken edges that crisp in the oven. If you flatten with a glass and it goes smooth, you've made bad mashed potatoes, not crispy smashed potatoes. Press once with the base of a glass — leave the surface uneven.`,`Skip the marinade time. 10 minutes is not marinating. Dan-O's Outlaw needs 30 min minimum to penetrate. Overnight is better. The color depth in the cooked thigh tells the story.`,`Stir the chili crisp into the sour cream too thoroughly. Visible orange chili oil streaks are the visual sell. Fold gently 3-4 times — keep the swirl. A homogenous beige sauce looks like ranch.`,`Use full-fat sour cream and wonder why macros climb. Daisy Light is 50% less fat for ~zero flavor loss in a dip context. The chili crisp does the flavor work; the sour cream is the carrier.`],whyThisWorks:[`Dan-O's Outlaw Sweet & Tangy is tamarind-based, not pure sugar. The tamarind brings acid + complexity that survives grill heat — most sweet seasonings just burn. The result is char + sweet + savory + tang in one bite.`,`Lee Kum Kee Chiu Chow Chili Crisp does double duty: in the marinade it adds color + heat + shallot/garlic depth; in the sauce it's the heat anchor of a sauce that crosses into 3+ other recipes (Buffalo wings, smashed potatoes, leftover grilled chicken wraps).`,`Little Potato Co. tray + microwave + smash + bake is a 25-minute crispy potato move that runs parallel to the chicken grilling. While potatoes bake, chicken grills. Total active time stays under 15 min.`,`The split mechanic uses TWO axes: presentation (sliced vs diced) AND sauce (spicy vs plain). Kids reject visible char and unfamiliar sauces — diced removes the char visual; plain sour cream removes the sauce friction. Same cook, two formats they'll each eat.`,`Chili crisp sour cream is its own cookbook-grade sauce (see /cookbook/chili-crisp-sour-cream) — once you make it, it cross-links into Buffalo wings, leftover chicken wraps, smashed potatoes as a standalone side, and even baked salmon. Build once, use across the week.`],executionRules:[`MARINATE LONGER. 30 min minimum, overnight ideal. The Dan-O's Outlaw color should be deeply coating the thighs (you'll see this in the bowl) — if it looks faint, give it more time.`,`GRILL MEDIUM-HIGH, FLIP ONCE. ~5 min per side for boneless thighs. Internal temp 165°F. Strong char marks on both sides. Don't fuss — flipping multiple times kills the grill marks.`,`PARALLEL COOKING. Microwave the potato tray (5 min) while the grill heats. Smash potatoes on parchment-lined sheet pan while chicken marinates. Pop potatoes into 425°F oven when chicken hits the grill. Both finish in ~25 min.`,`SMASH WITH JAGGED EDGES. Press each potato ONCE with the base of a glass or a flat measuring cup. Leave cracks. Cracks are where the crisp lives.`,`FOLD THE SAUCE GENTLY. Spoon 2-3 tbsp Lee Kum Kee Chiu Chow Chili Crisp into ~1 cup Daisy Light Sour Cream. Fold 3-4 times. Stop when you can still see orange streaks. That's the photo — and the flavor — moment.`,`SPLIT AT PLATING. Adult bowl: slice 2 thighs across the grain, lay over smashed potatoes, drizzle chili crisp sour cream on the side. Kid tray: dice 1.5 thighs into bite-sized pieces (no visible char), same potatoes, plain Daisy Light in the dip compartment.`,`DON'T DUMP SAUCE OVER ADULT PLATE. Drizzle or serve on the side. Visible chili crisp swirl on top of the sour cream is the brand cue — don't homogenize it on the plate.`],troubleshooting:[{problem:`Chicken came out pale, no char`,fix:`Grill wasn't hot enough OR you flipped too early. Medium-HIGH heat (~450-500°F surface). Don't touch for the first 4 minutes per side. The marinade needs to caramelize on contact.`},{problem:`Chicken charred outside, raw inside`,fix:`Grill too hot OR thighs too thick. Thinner thighs (uneven natural shape) cook unevenly — butterfly the thicker end before marinating. Or move to indirect heat after the first char to finish through.`},{problem:`Potatoes turned mushy / didn't crisp`,fix:`You smashed them too flat (purée mode) OR didn't bake at high enough heat. Press once, leave cracks. Bake at 425°F (not 375°F). Oil spray helps the crisp.`},{problem:`Sauce looks like beige ranch`,fix:`You stirred too much. Sauce should have visible orange chili oil streaks. Fold 3-4 times max. If already homogenized, drizzle a fresh tsp of chili crisp ON TOP just before serving — the visual carries half the appeal.`},{problem:`Kid won't try the diced chicken`,fix:`Dice smaller (1/2-inch cubes), and serve in their own divided tray compartment (not on a plate next to adult food). The 3-compartment tray is the brand cue — kids accept food when it's in 'their' format.`},{problem:`Sweet-tangy is too sweet for adult taste`,fix:`Bump the chili crisp in the marinade from 2 tbsp to 3 tbsp. The chili oil cuts the sweetness AND adds umami depth. Or finish with a squeeze of lime on the cooked thighs.`},{problem:`Smashed potatoes seasoning packet is too salty`,fix:`Use HALF the seasoning packet in the smash, then sprinkle the rest on the cooked potatoes if you want more. The packet is calibrated for the full tray; smashing increases surface area and salt concentration.`}],splitCook:{splitRatio:`2 thighs per adult (sliced) / 1.5 thighs per kid (diced)`,splitPoint:`AT PLATING. Same marinade, same grill, same cook. Only the cut + the sauce differ. Adult gets sliced thigh + chili crisp sour cream. Kid gets diced thigh + plain sour cream.`,sharedIngredients:[`--- PROTEIN ---`,`8 boneless skinless chicken thighs (~2 lbs / 32 oz)`,`--- MARINADE ---`,`2-3 tbsp Dan-O's Outlaw Sweet & Tangy BBQ seasoning`,`2 tbsp Lee Kum Kee Chiu Chow Style Chili Crisp Oil`,`1 tbsp light oil (avocado or vegetable)`,`--- POTATOES (shared, kid + adult eat the same) ---`,`1 tray (1 lb) Little Potato Co. A Little Savory Herb (with seasoning packet)`,`Oil spray`],sharedSteps:[{text:`MARINATE THE THIGHS: Combine Dan-O's Outlaw + Lee Kum Kee Chili Crisp + light oil in a large bowl. Add chicken, toss to coat thoroughly. The color should be deeply orange-red. Refrigerate 30 min minimum, overnight ideal.`,images:[`/images/outlaw-grilled-thighs/step1-marinade.webp`]},{text:`MICROWAVE THE POTATOES: Pierce the tray's vent (it's pre-vented). Microwave on high 5 min. The tray steams them through — no boiling required.`,images:[]},{text:`SMASH + SEASON: Transfer potatoes to a parchment-lined sheet pan. Press each one ONCE with the base of a glass — leave jagged edges, do NOT purée. Spray with oil, sprinkle the seasoning packet (start with half, add more after baking if needed). Set aside.`,images:[]},{text:`PREHEAT: Grill to medium-high (~450°F). Oven to 425°F.`,images:[]},{text:`GRILL THE CHICKEN: Lay thighs out on the grates with space between. Close lid. 4-5 min per side, flip ONCE, char marks should be clear and dark. Internal temp 165°F when done.`,images:[`/images/outlaw-grilled-thighs/step2-grill.webp`]},{text:`BAKE THE POTATOES: Pop the sheet pan in at 425°F for 20-25 min, until deeply browned and crispy at the edges. The fluffy interior + crispy exterior contrast is the goal.`,images:[`/images/outlaw-grilled-thighs/step4-potatoes.webp`]},{text:`REST THE CHICKEN: Off the grill onto a cutting board. Rest 3-5 min so the juices redistribute. Slicing immediately = pale interior with juices on the board, not in the meat.`,images:[`/images/outlaw-grilled-thighs/step3-rested.webp`]}],adult:{label:`Adult — Sliced + Chili Crisp Sour Cream`,protein:47,calories:540,extraIngredients:[`--- ADULT SAUCE ---`,`1/2 cup Daisy Light Sour Cream`,`2-3 tbsp Lee Kum Kee Chiu Chow Style Chili Crisp Oil`,{text:`(Full Chili Crisp Sour Cream recipe →`,link:`/cookbook/chili-crisp-sour-cream`}],steps:[{text:`BUILD THE SAUCE: Spoon Daisy Light Sour Cream into a small bowl. Add 2-3 tbsp Lee Kum Kee Chiu Chow Chili Crisp on top. Fold gently 3-4 times — STOP when you can still see orange streaks. Don't homogenize.`,images:[`/images/outlaw-grilled-thighs/step5-sauce.webp`]},{text:`SLICE THE THIGHS: 2 thighs per adult, cut across the grain into 1/2-inch slices. Lay over the smashed potatoes in a wide bowl. The grill marks should be visible.`,images:[]},{text:`PLATE: Wide bowl. Sliced thigh + crispy smashed potatoes. Chili crisp sour cream on the side OR drizzled with the orange streaks visible. DON'T dump and mix.`,images:[`/images/outlaw-grilled-thighs/hero.webp`]}]},kid:{label:`Kid — Diced + Plain Sour Cream Dip`,protein:22,calories:260,extraIngredients:[`--- KID SAUCE ---`,`2 tbsp plain Daisy Light Sour Cream (no chili crisp)`],variants:[{name:`Standard — 3-Compartment Tray`,description:`Diced chicken (no char) + smashed potatoes + plain sour cream dip in a 3-compartment tray. The format IS the brand — kids accept divided trays at higher rates than mixed plates.`,steps:[{text:`DICE 1.5 THIGHS: Trim off the heaviest char (kids reject visible burn). Cut into 1/2-inch cubes. Pieces should look like chicken-nugget-adjacent, not adult dinner.`,images:[]},{text:`PLATE INTO 3-COMPARTMENT TRAY: Diced chicken in the largest compartment, smashed potatoes in the second, plain Daisy Light sour cream in the third (for dipping).`,images:[]}]},{name:`Honey Mustard Override — For The No-Sour-Cream Kid`,description:`Some kids reject sour cream entirely. Sub Money Mustard (see /cookbook/money-mustard) or plain ketchup. The chicken is plenty seasoned — the dip is a tactile/comfort thing.`,steps:[{text:`Skip the sour cream compartment. Use Money Mustard or ketchup instead. Same tray format, same compartments.`}]}]}},ingredients:[`--- PROTEIN ---`,`8 boneless skinless chicken thighs (~2 lbs / 32 oz)`,`--- MARINADE ---`,{text:`Dan-O's Outlaw Sweet & Tangy BBQ seasoning (2-3 tbsp)`,link:`/cookbook/chili-crisp-sour-cream`},`Lee Kum Kee Chiu Chow Style Chili Crisp Oil (2 tbsp in marinade)`,`Light oil (1 tbsp, avocado or vegetable)`,`--- POTATOES ---`,`1 tray (1 lb) Little Potato Co. A Little Savory Herb (with seasoning packet)`,`Oil spray`,`--- SAUCE (adult) ---`,{text:`Chili Crisp Sour Cream (1/2 cup Daisy Light + 2-3 tbsp chili crisp)`,link:`/cookbook/chili-crisp-sour-cream`},`--- SAUCE (kid) ---`,`2 tbsp plain Daisy Light Sour Cream`],steps:[{text:`MARINATE: Toss thighs with Dan-O's Outlaw + Lee Kum Kee Chili Crisp + light oil. Cover and refrigerate 30 min minimum, overnight ideal.`,images:[`/images/outlaw-grilled-thighs/step1-marinade.webp`]},{text:`POTATOES — MICROWAVE + SMASH: Microwave Little Potato Co. tray 5 min. Smash on parchment-lined sheet pan with the base of a glass — leave jagged edges (NOT puréed). Oil spray + half the seasoning packet.`,images:[]},{text:`PREHEAT BOTH: Grill medium-high (~450°F). Oven 425°F.`,images:[]},{text:`GRILL: Thighs on the grates, 4-5 min per side, flip ONCE. Internal 165°F. Strong char marks both sides.`,images:[`/images/outlaw-grilled-thighs/step2-grill.webp`]},{text:`BAKE POTATOES: 425°F for 20-25 min. Deeply browned + crispy edges + fluffy interior.`,images:[`/images/outlaw-grilled-thighs/step4-potatoes.webp`]},{text:`REST CHICKEN: 3-5 min on the cutting board. Don't slice too early.`,images:[`/images/outlaw-grilled-thighs/step3-rested.webp`]},{text:`BUILD SAUCE: Daisy Light + Lee Kum Kee Chili Crisp, fold 3-4 times. Leave orange streaks visible.`,images:[`/images/outlaw-grilled-thighs/step5-sauce.webp`]},{text:`SPLIT THE PLATE: Adult bowl — 2 sliced thighs over smashed potatoes + chili crisp sour cream on side. Kid 3-compartment tray — 1.5 thighs diced (no char), potatoes, plain sour cream.`,images:[`/images/outlaw-grilled-thighs/hero.webp`]}],brands:[{name:`Dan-O's`,item:`Outlaw Sweet & Tangy BBQ (made with Tamarind, 8.5 oz)`,why:`Tamarind base = real acid + complexity, not just sugar. Survives grill heat where pure sweet seasonings just burn. Anchors the Dan-O's family alongside Original (id 21, id 31) and Spicy.`,image:`/images/brands/danos-outlaw.png`,url:`https://danosseasoning.com/product/sweet-tangy-bbq-seasoning-made-with-tamarind-medium-bottle/`},{name:`Little Potato Co.`,item:`A Little Savory Herb (1 lb tray, microwave-ready, seasoning packet included)`,why:`Pre-washed, pre-portioned, 5-min microwave. The whole point is the convenience — parallel-cook with the grill. Seasoning packet has salt + dehydrated garlic + onion + citric acid for tartness.`,image:`/images/brands/little-potato-savory-herb.webp`,url:`https://www.littlepotatoes.com/product/little-savory-herb/`},{name:`Lee Kum Kee`,item:`Chiu Chow Style Chili Crisp Oil (7.2 oz, 205g)`,why:`Does double duty: marinade (color + heat + acid) AND the sauce. Chiu Chow specifically has shallot + garlic bits that carry the flavor — generic chili oil is too one-note. One jar runs across 3+ recipes.`,image:`/images/brands/lee-kum-kee-chili-oil.jpg`,url:`https://usa.lkk.com/en/products/chiu-chow-style-chili-crisp-oil-7-2-oz`},{name:`Daisy`,item:`Light Sour Cream (1 lb / 16 oz tub, 50% less fat)`,why:`The sauce carrier. Light is intentional — the chili crisp does the flavor work, the sour cream is the cool/creamy contrast. Full-fat is fine but pushes calories without adding much.`,image:`/images/brands/daisy-sour-cream.jpg`,url:`https://www.daisybrand.com/our-products/sour-cream/`}],macroHonesty:`Per-serving (~540 cal / 47g protein / 27g fat / 33g total carbs / ~28g net carbs) breaks down: 350 cal from 2 grilled thighs (marinade oil included), 150 cal from 4 oz smashed potatoes + seasoning + oil spray, 40 cal from 2 tbsp chili crisp sour cream. Estimated (not per-ingredient verified) because thigh size + grill char retention + sauce ratio vary. Kid plate at 1.5 diced thighs + smaller potato portion + plain sour cream = ~260 cal / 22g protein.`,mealPrep:{storage:`Leftover thighs + potatoes hold 3 days in the fridge. Sauce keeps separately in a jar 5 days.`,reheat:`Thighs: 350°F oven for 6-8 min, or cast iron 2 min per side to re-crisp. Don't microwave — turns the char rubbery. Potatoes: same oven, same temp; air fryer 5 min at 400°F is even better.`,lasts:`Best fresh. Day-2 thighs are still good if reheated dry-heat (not microwave). Sauce is dump-and-stir, build fresh each time you eat for the visual.`}},{id:38,status:`live`,carbLevel:`low`,meta:{macros:{protein:53,calories:491,fat:28,carbs:11,netCarbs:11,estimated:!0},allergens:[`fish`,`soy`],warnings:[`contains-fish-sauce`,`contains-soy`,`spicy-adult-version`],dietTags:[`gluten-free-option`,`halal`,`dairy-free`,`egg-free`,`nut-free`,`low-carb`],proteinTags:[`pork`],splitAxes:[`spice`,`sauce`,`vehicle`],effortTags:[`fast`,`weeknight`,`one-pan`,`one-hand`,`split-plate`],costTier:`moderate`,costPerServing:`$5.00`,substitutionNotes:[`NY Style Sausage Co. 95% Lean Ground Pork (Tier 2 — first solo-pork dinner; id 36 was Italian sausage) — sub any 93-95% lean pork; lower-lean (80%) renders too much grease for a wrap.`,`Verka Organic Ginger Garlic Paste (Tier 1 — also in TKS Sauce id 35) — sub fresh-minced 1 tsp ginger + 1 tsp garlic; the paste is the convenience play.`,`Red Boat Fish Sauce 40°N (Tier 1 NEW signature) — anchors SE Asian dinners going forward. Sub Three Crabs or Squid Brand; do NOT sub Maggi (too soy-heavy, kills the fermented depth).`,`Kikkoman All-Purpose Soy Sauce (Tier 1 — also in TKS Sauce, brand image cached) — the standard. Reduced-sodium also works; MacroFactor estimates with that since it's approximated for calorie tracking only.`,`Dynasty Sesame Chili Oil (Tier 1 — also in TKS Sauce) — aromatic top note. 2 tsp here adds takeout-restaurant aroma without dumping heavy oil.`,`Dan-O's SPG Tri-O (Tier 1 Dan-O's family — also in Protein Blue Cheese Crema) — 4 pinches into the cooked pork. Kid-safe, savory, no heat.`,`Deep Coriander Powder — 1/2 tsp in the Lift Drizzle adds bright citrusy aromatic. Skip if you don't have it but the drizzle loses ~10% of its lift.`,`Tanimura & Antle Artisan Sweet Gem Lettuce (Tier 4 freshness + vehicle) — sub butter lettuce or romaine hearts; iceberg too crunchy + flavorless. Sweet Gem specifically holds the meat without snapping.`,`Herdez Taqueria Avocado Cilantro (Tier 1 — kid sauce component, cross-link to id 32) — the mild creamy that lets kids skip the adult fish sauce + chili.`,`Chosen Avocado Oil Spray (Tier 3 utility) — spray-not-pour move. 4 seconds = ~40 cal; spraying lets you skip 2 tbsp of pour-oil without losing the searing surface.`,`Slider rolls (kid vehicle alternative) — dinner slider rolls work when kids reject lettuce. Hawaiian, Sola keto, King's Hawaiian — any small soft roll.`,`MENTOR PUSHBACK (optional): Lighter sauce variant — drop olive oil to 1 tbsp + bump lime to 3 tbsp + 1 tsp rice vinegar + 1 tsp allulose. Brighter, ~half the calories per serving. Shipped recipe stays oil-richer because the fat carries the soy + lemon onto the lettuce; the lighter version reads as 'salad dressing'. Try both.`,`MENTOR PUSHBACK (optional): Adult texture flourish — finish with 1 tbsp toasted sesame seeds OR 2 tbsp crispy fried shallots OR 2 tbsp crushed roasted peanuts. The dish is soft + crunchy already (mince + lettuce); a third texture lifts it from 'good' to 'restaurant'.`,`MENTOR PUSHBACK (optional): Adult herb finish — sprinkle fresh cilantro, Thai basil, or mint just before serving. Kids already get cilantro via the Herdez Avocado Cilantro crema; adults don't. Herbs are what separates this from 'healthy pork in lettuce'.`]},slug:`pork-mince-lettuce-wraps`,proteinAnchor:`pork`,mealType:`wrap`,flavorDirection:`se-asian-bright`,splitFriendly:`full`,title:`Pork Mince Lettuce Wraps`,category:`Core Signatures`,pillar:`Protein Meals`,tags:[`lettuce-wraps`,`pork`,`se-asian`,`fish-sauce`,`low-carb`,`split-cook`,`weeknight`,`one-pan`],time:`25 min`,servings:4,protein:53,calories:491,image:`/images/pork-lettuce-wraps/hero.webp`,role:`The Low-Carb Family Wrap`,makeThisWhen:`You want a high-protein dinner that adults assemble (lettuce cup + spicy fish-sauce drizzle) and kids eat with a spoon (mild creamy sauce mixed into the mince, lettuce OR slider rolls — their call). 25 min, one pan, one mince, two completely different formats.`,hook:`Restraint is the brand. No hoisin, no peanut butter, no sugary glaze — fish sauce + lemon + sesame chili oil do the lift. Adults get the heat (2 fresh chilies in the pork, 2 more in the drizzle); kids never see a chili — their portion is pulled aside before chilies hit the pan, and the sauce is mixed INTO the mince so they don't have to pour anything themselves.`,description:`32 oz of 95% lean ground pork browned with ginger garlic paste + green onion, then split: adult side gets fresh red chilies + fish sauce + lemon + sesame chili oil; kid side stays mild and gets a creamy sauce (olive oil + Herdez Avocado Cilantro + bone broth) stirred directly into the mince. Adults wrap in Tanimura & Antle Sweet Gem lettuce with Lift Drizzle on the side. Kids spoon into lettuce OR onto a slider roll — kid-format choice protects against the lettuce-rejection day.`,whyMostFail:[`Dump raw pork into a cold pan. You'll steam it gray. Heat the pan first, spray oil, START WITH AROMATICS (ginger garlic paste + green onion) for 60 sec, THEN add the pork. The fond on the pan and the early aromatics are what build flavor — there's no sugar in this dish to mask under-browning.`,`Add chilies to the whole pan. The kid portion is now too spicy to eat. PULL the kid portion before chilies — the split moment is non-negotiable in a family-flex recipe. ~1/4 of the pan goes into a deli container; the rest gets chilies + the adult finish.`,`Pour fish sauce onto cold lettuce. Lettuce wilts in 60 seconds. Lift Drizzle is served ON THE SIDE — adults spoon into the wrap right before eating. Pour-on = soggy lettuce + diluted flavor.`,`Make a sugary glaze with hoisin / peanut butter / brown sugar. That's the takeout move and it destroys this dish's macros. Fish sauce + lemon + soy carry plenty of flavor. The mentor specifically flagged this — don't reach for the sugar bottle.`,`Skip the kid sauce-mix step. If you give a 3-year-old a bowl of plain seasoned mince + an open ramekin of sauce, they will either pour the whole thing in or refuse the dry mince. Mix the kid sauce INTO the mince yourself. Sauce should be visible but distributed.`],whyThisWorks:[`95% lean pork renders just enough fat to brown + flavor the aromatics, but not so much that the wraps go greasy. Lower lean % (80%) drops a sloppy puddle into the lettuce.`,`The split is THREE axes at once: spice (chilies vs none), sauce (Lift Drizzle vs mixed-in cilantro crema), vehicle (lettuce vs slider rolls). That gives kids 3 different reasons to NOT push back. Most family recipes only split on one axis.`,`Lift Drizzle (the adult sauce — its own cookbook entry) is olive oil + fish sauce + soy + lemon + coriander + chopped chilies. Acid does the lift; oil carries the salt onto the lettuce. Restraint by design — 5 ingredients, no sugar.`,`Kid sauce is olive oil + Herdez Avocado Cilantro + bone broth. The cilantro crema adds creaminess + mild herb depth (the kid version of 'fresh herb finish'). Bone broth thins it without dilution. Three ingredients, mixed straight into the mince.`,`Tanimura & Antle Sweet Gem holds the mince without snapping (butter lettuce too soft, romaine hearts too rigid, iceberg too brittle). The Sweet Gem inner leaves are about 4 inches — exactly wrap-sized.`,`Avocado oil spray (Chosen Foods) is the spray-not-pour move. 4 seconds = 40 cal instead of the 240 cal you'd dump from 2 tbsp pour-oil. Surface coating without the puddle.`],executionRules:[`HEAT FIRST, AROMATICS FIRST. Pan on medium-high, spray with avocado oil, add ginger garlic paste + chopped green onion. 60-90 sec until fragrant. NEVER dump pork into a cold pan or a pan without aromatics.`,`BROWN, DON'T STEAM. Spread pork in a single layer. Don't stir for 90 sec. Crust forms on contact. Then break with a spatula and brown the rest. The photos in the recipe show separated mince texture — not gray clumps.`,`SEASON SHARED, SPLIT LATE. Fish sauce + sesame chili oil + lemon + Dan-O's SPG (4 pinches) go in BEFORE the split. All of this is kid-safe (no chilies yet). Stir to coat.`,`PULL KID PORTION FIRST. Spoon ~1/4 of the pan (~250g cooked) into a deli container. THIS IS THE SPLIT MOMENT. After this, the adult half can get chilies.`,`ADULT FINISH: Add 2 chopped fresh red Thai chilies to the adult half. Stir. Cook 30 sec.`,`KID SAUCE MIX: While adult cooks, mix kid sauce in a small bowl — 1 tbsp olive oil + 1 tbsp Herdez Avocado Cilantro + 1 tbsp chicken bone broth. Stir into the kid's mince directly. Sauce should coat, not drown.`,`LIFT DRIZZLE: Whisk 2 tbsp olive oil + 2 tbsp soy + 1 tbsp fish sauce + 3 tbsp lemon juice + 1/2 tsp coriander + 2 chopped chilies in a small bowl. Adult side only. Serve in a small bowl for spooning, NOT pouring over the platter.`,`SERVE SEPARATE. Adults: build their own lettuce cup at the table — leaf + spoon of mince + spoon of Lift Drizzle. Kids: deli container of pre-mixed mince + a stack of lettuce leaves OR a plate of slider rolls. Their call.`],troubleshooting:[{problem:`Pork came out gray + steamed, not browned`,fix:`Pan wasn't hot enough, OR you stirred too early. Medium-HIGH. Spread the mince. Don't touch for 90 sec — let the crust form on contact.`},{problem:`Lettuce wilted in the wrap by the second bite`,fix:`Lift Drizzle was poured over the mince in the pan or onto the lettuce. SERVE THE DRIZZLE SEPARATELY. Spoon into each wrap immediately before eating.`},{problem:`Too spicy / kid bite of something they shouldn't have`,fix:`Chilies went in before the split. PULL THE KID PORTION FIRST, THEN add chilies. No fix mid-recipe — start over for the kid portion (~5 min).`},{problem:`Adult sauce tastes flat / one-dimensional`,fix:`Coriander powder skipped, OR lemon under-measured. The lift comes from lemon + coriander. Bump lemon by 1 tbsp + add the 1/2 tsp coriander. Don't reach for sugar.`},{problem:`Kid refused even with the cilantro crema mix`,fix:`Try the slider roll version — sometimes the rejection is the lettuce, not the mince. Or thin the kid sauce further with another tablespoon of bone broth. Last resort: add 1 tsp shredded mozzarella into the kid's mince for the comfort signal.`},{problem:`Too greasy in the lettuce`,fix:`Lean % too low (you bought 80% instead of 95%) OR aromatic oil dumped instead of sprayed. Drain off rendered fat before the seasoning step if it pools.`},{problem:`MacroFactor doesn't match the listed macros`,fix:`MacroFactor approximates by calorie/serving — the protein/fat/carb split is slightly off depending on which soy/fish sauce variant it indexed. Use the listed numbers as your source of truth for this site.`}],splitCook:{splitRatio:`3:1 Adult-to-Kid by volume (~750g cooked adult / ~250g cooked kid)`,splitPoint:`AFTER SHARED SEASONING. Pull ~1/4 of the pan into a deli container before chilies go in. Adult half gets chilies + Lift Drizzle on the side; kid portion gets the cilantro crema mixed in directly.`,sharedIngredients:[`--- PROTEIN ---`,`32 oz NY Style Sausage Co. 95% Lean Ground Pork (2 packs)`,`--- AROMATICS ---`,`Chosen Foods Avocado Oil Spray (4 seconds = ~1 tbsp)`,`2 tbsp Verka Organic Ginger Garlic Paste`,`1 cup chopped green onion (~1 bunch)`,`--- SHARED SEASONING ---`,`2 tbsp Red Boat Fish Sauce 40°N`,`2 tsp Dynasty Sesame Chili Oil (Goma Rayu)`,`3 tbsp ReaLemon lemon juice (~6 portions)`,`4 pinches Dan-O's SPG Tri-O seasoning`],sharedSteps:[{text:`HEAT PAN + SPRAY: Stainless steel pan over medium-high heat. Spray with Chosen Avocado Oil for 4 seconds.`,images:[`/images/pork-lettuce-wraps/step1-mise.webp`]},{text:`AROMATICS FIRST: Add 2 tbsp Verka ginger garlic paste + 1 cup chopped green onion. Sauté 60-90 sec until fragrant. Don't brown — soften.`,images:[]},{text:`ADD PORK + BROWN: Add 32 oz ground pork. Spread in single layer. Don't stir for 90 sec — let crust form. Then break with spatula, brown the rest. 6-8 min total.`,images:[`/images/pork-lettuce-wraps/step2-raw-pork.webp`]},{text:`SHARED SEASONING: Add 2 tbsp Red Boat fish sauce + 2 tsp Dynasty sesame chili oil + 3 tbsp ReaLemon + 4 pinches Dan-O's SPG. Stir to coat. Cook 60 sec.`,images:[]},{text:`SPLIT MOMENT: Spoon ~1/4 of the pan (~250g cooked) into a deli container. THIS IS THE KID PORTION — set aside. After this, the rest of the pan gets chilies.`,images:[`/images/pork-lettuce-wraps/step3-split.webp`]}],adult:{label:`Adult — Lettuce Cup + Lift Drizzle on the Side`,protein:53,calories:491,extraIngredients:[`--- ADULT FINISH (in pan) ---`,`2 fresh red Thai chilies, finely chopped`,`--- ADULT SAUCE (Lift Drizzle, 2 servings) ---`,{text:`Lift Drizzle: 2 tbsp olive oil + 2 tbsp Kikkoman soy + 1 tbsp Red Boat fish sauce + 3 tbsp ReaLemon + 1/2 tsp Deep Coriander Powder + 2 chopped fresh red chilies (full recipe → )`,link:`/cookbook/lift-drizzle`},`--- VEHICLE ---`,`Tanimura & Antle Artisan Sweet Gem Lettuce — separated into wrap-sized leaves`],steps:[{text:`ADULT FINISH: After the split, add 2 chopped fresh red Thai chilies to the remaining pork. Stir + cook 30 sec.`,images:[]},{text:`BUILD LIFT DRIZZLE: In a small bowl, whisk 2 tbsp olive oil + 2 tbsp Kikkoman soy + 1 tbsp Red Boat fish sauce + 3 tbsp ReaLemon + 1/2 tsp Deep Coriander Powder + 2 chopped chilies. Stir until coriander dissolves.`,images:[`/images/pork-lettuce-wraps/step4-sauce-mise.webp`]},{text:`SERVE: Plate adult mince in a bowl. Lift Drizzle in a separate small bowl with a spoon. Tanimura & Antle Sweet Gem leaves on a paper-towel-lined platter. Build at the table — leaf, spoon of mince, spoon of drizzle.`,images:[`/images/pork-lettuce-wraps/step5-lettuce-pork.webp`]}]},kid:{label:`Kid — Pre-Mixed Mince + Lettuce OR Slider Rolls`,protein:28,calories:280,extraIngredients:[`--- KID SAUCE (mixed INTO mince) ---`,`1 tbsp olive oil`,{text:`1 tbsp Herdez Taqueria Avocado Cilantro Sauce (mild creamy — also used in Next-Day Chicken Tacos id 32)`,link:`/cookbook/`},`1 tbsp chicken bone broth (any brand — Kirkland or Bare Bones)`,`--- VEHICLE (kid's choice) ---`,`Tanimura & Antle Sweet Gem lettuce leaves OR dinner slider rolls`],variants:[{name:`Standard — Lettuce Cups`,description:`Pre-mixed mince in their bowl, lettuce leaves on the side. They can spoon into the leaf or just eat with a spoon.`,steps:[{text:`MIX KID SAUCE INTO MINCE: In the deli container (or transfer to a bowl), stir 1 tbsp olive oil + 1 tbsp Herdez Avocado Cilantro + 1 tbsp chicken bone broth INTO the kid's pork. Sauce should coat the mince visibly without pooling at the bottom.`},{text:`PLATE: Kid bowl of pre-sauced mince + a few Sweet Gem leaves on the side. No drizzle ramekin — sauce is already in.`}]},{name:`Slider Roll Override — For The Lettuce-Refuser`,description:`Sometimes kids reject lettuce on sight. Sub dinner slider rolls — same mince, different vehicle.`,steps:[{text:`Same mince mix (kid sauce stirred in). Serve in a halved dinner slider roll like a tiny sloppy joe. Kids who hate lettuce will eat this.`}]}]}},ingredients:[`--- PROTEIN ---`,`32 oz NY Style Sausage Co. 95% Lean Ground Pork (2 packs × 16 oz)`,`--- AROMATICS ---`,`Chosen Foods Avocado Oil Spray (4 sec)`,`2 tbsp Verka Organic Ginger Garlic Paste`,`1 cup chopped green onion (~1 bunch)`,`--- SHARED SEASONING ---`,`2 tbsp Red Boat Fish Sauce 40°N`,`2 tsp Dynasty Sesame Chili Oil (Goma Rayu)`,`3 tbsp ReaLemon lemon juice`,`4 pinches Dan-O's SPG Tri-O`,`--- ADULT ONLY ---`,`2 fresh red Thai chilies, chopped [adult, into pork]`,{text:`Lift Drizzle — adult sauce (recipe →)`,link:`/cookbook/lift-drizzle`},`--- KID ONLY (sauce mixed into mince) ---`,`1 tbsp olive oil [kid]`,`1 tbsp Herdez Taqueria Avocado Cilantro Sauce [kid]`,`1 tbsp chicken bone broth [kid]`,`--- VEHICLE ---`,`1 pack Tanimura & Antle Artisan Sweet Gem Lettuce (for adult wraps + kid lettuce option)`,`Dinner slider rolls (kid backup if lettuce gets rejected)`],steps:[{text:`MISE EN PLACE: Everything out — pork packs, Verka paste, green onions chopped, Red Boat, Dynasty, ReaLemon, Dan-O's SPG, Chosen spray, fresh chilies, Sweet Gem lettuce washed, kid sauce ingredients ready.`,images:[`/images/pork-lettuce-wraps/step1-mise.webp`]},{text:`HEAT PAN + AROMATICS: Stainless steel pan, medium-high. Spray avocado oil 4 sec. Add Verka paste + green onion. Sauté 60-90 sec until fragrant.`,images:[]},{text:`BROWN PORK: 32 oz pork into the pan. Spread single layer. Don't stir 90 sec — let crust form. Then break with spatula, brown the rest. 6-8 min total.`,images:[`/images/pork-lettuce-wraps/step2-raw-pork.webp`]},{text:`SHARED SEASON: Fish sauce + sesame chili oil + lemon + 4 pinches SPG. Stir to coat. Cook 60 sec.`,images:[]},{text:`PULL KID PORTION: ~1/4 of pan into deli container. SPLIT MOMENT.`,images:[`/images/pork-lettuce-wraps/step3-split.webp`]},{text:`ADULT: Add 2 chopped chilies to remaining pork. Stir 30 sec.`,images:[]},{text:`LIFT DRIZZLE: Whisk olive oil + soy + fish sauce + lemon + coriander + 2 chopped chilies in small bowl.`,images:[`/images/pork-lettuce-wraps/step4-sauce-mise.webp`]},{text:`KID SAUCE INTO MINCE: 1 tbsp olive oil + 1 tbsp Herdez Avocado Cilantro + 1 tbsp bone broth stirred into kid's deli container. Should coat, not pool.`,images:[]},{text:`SERVE: Adult bowl of mince + Lift Drizzle ramekin + Sweet Gem leaves on platter. Kid bowl of pre-sauced mince + lettuce leaves OR slider rolls. Build at the table.`,images:[`/images/pork-lettuce-wraps/hero.webp`,`/images/pork-lettuce-wraps/step5-lettuce-pork.webp`]}],brands:[{name:`NY Style Sausage Co.`,item:`95% Lean Ground Pork (16 oz, fresh, made in California)`,why:`95% lean is the right ratio — enough fat to brown + flavor the aromatics without rendering a puddle into the wraps. Fresh ground (not frozen), no preservatives, no MSG. Buy 2 packs for the 32 oz batch.`},{name:`Verka`,item:`Organic Ginger Garlic Paste`,why:`Pre-minced + jarred. Saves 10 min of knife work. The paste form distributes evenly through the hot pan; fresh-minced ginger clumps. Cross-recipe with TKS Sauce (id 35).`,image:`/images/brands/verka-ginger-garlic-paste.jpg`,url:`https://www.verkausa.com/product/masala-ginger-garlic-750`},{name:`Red Boat`,item:`Fish Sauce 40°N (8.45 fl oz, just anchovies + salt)`,why:`First-press, barrel-aged Vietnamese fish sauce. The salt + umami + fermented depth that lifts the dish without needing sugar. The 40°N grade is the cleanest — Three Crabs or Squid Brand work but skip the discount labels (they extend with caramel + MSG).`,image:`/images/brands/red-boat-fish-sauce.png`,url:`https://redboatfishsauce.com/products/fish-sauce-40n`},{name:`Dynasty`,item:`Sesame Chili Oil 'Goma Rayu' (3.5 fl oz)`,why:`Toasted sesame + slow chili = takeout aroma. Only 2 tsp here — aromatic top note, not the main heat (chilies do the heat). Cross-recipe with TKS Sauce (id 35).`,image:`/images/brands/dynasty-sesame-chili-oil.jpg`,url:`https://www.foodservicedirect.com/dynasty-sesame-chili-oil--3-5-fluid-ounce----12-per-case-238271.html`},{name:`Kikkoman`,item:`All-Purpose Soy Sauce`,why:`Clean salt + umami. The default soy on this site — also in TKS Sauce. MacroFactor approximated with Reduced Sodium for calorie tracking; the real recipe uses All-Purpose.`,image:`/images/brands/kikkoman-soy-sauce.jpg`,url:`https://kikkomanusa.com/homecooks/products/soy-sauce-non-gmo/`},{name:`Dan-O's`,item:`SPG Tri-O Seasoning (Salt-Pepper-Garlic)`,why:`4 pinches into the shared pork. Kid-safe, no heat, savory backbone. Granulated garlic doesn't clump like fresh raw garlic. Cross-recipe with Protein Blue Cheese Crema.`,image:`/images/brands/danos-spg-tri-o.png`,url:`https://danosseasoning.com/product/spg-tri-o-medium-bottle/`},{name:`Chosen Foods`,item:`Avocado Oil Spray (100% pure, pressed-not-blended)`,why:`Spray-not-pour. 4 seconds = ~40 cal; pouring 2 tbsp = 240 cal. Same searing surface, 200 cal saved per cook. High smoke point (500°F) so it doesn't break down at medium-high.`,image:`/images/brands/chosen-foods-spray.png`,url:`https://www.chosenfoods.com/products/avocado-oil-cooking-spray`},{name:`Tanimura & Antle`,item:`Artisan Sweet Gem Lettuce (4 heads per pack)`,why:`The leaf size — about 4 inches — is exactly wrap-sized. Crisp without snapping, sweet without bitterness, holds mince without leaking. Butter lettuce too soft, romaine too rigid, iceberg too brittle. Sweet Gem is the goldilocks.`,image:`/images/brands/tanimura-antle-sweet-gem.png`,url:`https://www.taproduce.com/artisan-sweet-gem/`},{name:`Herdez`,item:`Taqueria Avocado Cilantro Sauce (mild)`,why:`Kid sauce component. Mild creamy avocado + cilantro = the kid version of 'fresh herb finish'. Cross-recipe with Next-Day Chicken Tacos (id 32). 1 tbsp into the kid's mince + olive oil + bone broth = a 3-ingredient mild sauce.`,image:`/images/brands/herdez-avocado-cilantro.png`,url:`https://www.salsas.com/herdez/products/taqueria-street-sauces/herdez-taqueria-street-sauce-avocado-cilantro/`},{name:`ReaLemon`,item:`100% Lemon Juice (small squeeze bottle)`,why:`The acid that does the lift. Mentor flagged: 'Without acid this becomes hot oily pork in lettuce.' Use 3 tbsp into the shared seasoning + 3 tbsp into the Lift Drizzle. Fresh-squeezed lemon works but ReaLemon stays in the fridge year-round.`},{name:`Deep`,item:`Coriander Powder (Indian grocery brand)`,why:`1/2 tsp into the Lift Drizzle. Bright citrus-floral aromatic — adds the third layer of lift after lemon + chilies. Zero calories, big flavor return.`}],macroHonesty:`Per-serving (491 cal / 53g protein / 28g fat / 11g carbs / ~11g net) computed from MacroFactor: 351 cal from the seasoned pork portion (32 oz pork ÷ 4 + aromatics + shared seasoning) + 140 cal from 2 tbsp Lift Drizzle. Verified, not estimated — Tushar logged every ingredient with weights. Kid portion (~280 cal / 28g protein) accounts for smaller pork serving + 1 tbsp olive oil + Herdez Avocado Cilantro + bone broth in the mix. Slider roll adds ~140 cal if kid picks the roll instead of lettuce.`,mealPrep:{storage:`Seasoned mince (both adult and kid portions) holds 3 days in airtight containers. Lift Drizzle keeps 5 days in a small jar. Sweet Gem lettuce washed + stored with paper towels in the bag — 3 days.`,reheat:`Microwave the mince covered 60-90 sec. The lettuce is always fresh — wash + dry day-of, or store with paper towels. Lift Drizzle is dump-and-stir, build fresh per meal if possible.`,lasts:`3 days for the mince. Lift Drizzle 5 days. Sweet Gem lettuce 3 days washed (longer if you keep the heads intact).`}}],t=e.filter(e=>e.status===`live`),n=e.filter(e=>e.status===`coming-soon`),r=e.filter(e=>e.status!==`placeholder`);[...new Set(r.map(e=>e.category))],[...new Set(r.map(e=>e.pillar))];function i(t){return e.find(e=>e.slug===t)}export{e as i,i as n,t as r,n as t};